  ('jee-physics-current-electricity-q04', 'jee-physics-current-electricity', 'The power dissipated in a 5 ohm resistor carrying 2 A is:', '10 W', '2.5 W', '40 W', '20 W', 'D', 'P = I²R = 4 x 5 = 20 W.', 3),
