  ('jee-physics-current-electricity-q07', 'jee-physics-current-electricity', 'Three 2 ohm resistors in series give a total resistance of:', '2 ohm', '0.67 ohm', '6 ohm', '8 ohm', 'C', 'Series resistances add: 2 + 2 + 2 = 6 ohm.', 6),
