  ('jee-physics-magnetism-emi-q07', 'jee-physics-magnetism-emi', 'The inductive reactance of an inductor at angular frequency omega is:', '1/(omega L)', 'L/omega', 'omega/L', 'omega L', 'D', 'Inductive reactance X_L = omega x L and rises with frequency.', 6),
  ('jee-physics-magnetism-emi-q08', 'jee-physics-magnetism-emi', 'An LC circuit resonates at an angular frequency of:', 'sqrt(LC)', 'LC', '1/sqrt(LC)', '1/(LC)', 'C', 'Resonance occurs at omega = 1/sqrt(LC).', 7),
  ('jee-physics-optics-q01', 'jee-physics-optics', 'The focal length of a concave mirror of radius of curvature 20 cm is:', '20 cm', '40 cm', '10 cm', '5 cm', 'C', 'Focal length f = R/2 = 20/2 = 10 cm.', 0),
