  ('jee-physics-modern-physics-q04', 'jee-physics-modern-physics', 'A radioactive sample has a half-life of 5 years. After 15 years the fraction remaining is:', '1/8', '1/4', '1/2', '1/16', 'A', '15 years is three half-lives, leaving (1/2)³ = 1/8 of the sample.', 3),
  ('jee-physics-modern-physics-q05', 'jee-physics-modern-physics', 'Einstein''s photoelectric equation is KE_max =:', 'hf + phi', 'hf - phi', 'phi - hf', 'hf x phi', 'B', 'KE_max = hf - phi, where phi is the work function.', 4),
  ('jee-physics-modern-physics-q06', 'jee-physics-modern-physics', 'Emission of an alpha particle reduces the mass number of a nucleus by:', '1', '4', '2', '0', 'B', 'An alpha particle is a helium nucleus, so mass number drops by 4.', 5),
  ('jee-physics-modern-physics-q07', 'jee-physics-modern-physics', 'The relation between energy and mass defect is given by:', 'E = mc²', 'E = mc', 'E = m/c²', 'E = m²c', 'A', 'Einstein''s mass-energy relation E = mc² gives the released binding energy.', 6),
  ('jee-physics-modern-physics-q08', 'jee-physics-modern-physics', 'The radius of the n-th Bohr orbit varies with n as:', 'n', '1/n²', '1/n', 'n²', 'D', 'The Bohr radius r_n is proportional to n².', 7),
  ('jee-physics-thermodynamics-q01', 'jee-physics-thermodynamics', 'The first law of thermodynamics is a statement of conservation of:', 'Mass', 'Energy', 'Momentum', 'Charge', 'B', 'The first law, delta U = Q - W, expresses conservation of energy.', 0),
  ('jee-physics-thermodynamics-q02', 'jee-physics-thermodynamics', 'In an isothermal process for an ideal gas, the change in internal energy is:', 'Zero', 'Negative', 'Positive', 'Equal to the work done', 'A', 'Internal energy depends on temperature only; at constant T, delta U = 0.', 1),
