  ('jee-physics-thermodynamics-q04', 'jee-physics-thermodynamics', 'The efficiency of a Carnot engine between 600 K and 300 K is:', '25 percent', '75 percent', '50 percent', '100 percent', 'C', 'eta = 1 - T_cold/T_hot = 1 - 300/600 = 0.5, or 50 percent.', 3),
  ('jee-physics-thermodynamics-q05', 'jee-physics-thermodynamics', 'The work done in an isochoric (constant volume) process is:', 'Zero', 'Maximum', 'P delta V', 'nRT', 'A', 'With no volume change, W = P delta V = 0.', 4),
