  ('jee-chemistry-periodicity-q02', 'jee-chemistry-periodicity', 'The modern periodic law arranges elements by increasing:', 'Atomic number', 'Atomic mass', 'Density', 'Valency', 'A', 'Moseley''s modern law orders elements by atomic number.', 1),
  ('jee-chemistry-periodicity-q03', 'jee-chemistry-periodicity', 'Down a group, ionisation energy generally:', 'Increases', 'Decreases', 'Stays constant', 'Becomes zero', 'B', 'Added shells increase size, so electrons are easier to remove going down a group.', 2),
  ('jee-chemistry-periodicity-q04', 'jee-chemistry-periodicity', 'The most electronegative element in the periodic table is:', 'Fluorine', 'Chlorine', 'Oxygen', 'Nitrogen', 'A', 'Fluorine has the highest electronegativity on the Pauling scale.', 3),
  ('jee-chemistry-periodicity-q05', 'jee-chemistry-periodicity', 'Elements of groups 1 and 2 belong to the:', 'p-block', 's-block', 'd-block', 'f-block', 'B', 'Groups 1 and 2 have their last electron in an s orbital, defining the s-block.', 4),
  ('jee-chemistry-periodicity-q06', 'jee-chemistry-periodicity', 'The second ionisation energy of an element compared with the first is always:', 'Smaller', 'Larger', 'Equal', 'Zero', 'B', 'Removing an electron from a cation needs more energy, so IE2 is greater than IE1.', 5),
  ('jee-chemistry-periodicity-q07', 'jee-chemistry-periodicity', 'The lanthanide contraction causes the atomic sizes of which pair to be nearly equal?', 'Zr and Hf', 'Na and K', 'Li and Be', 'F and Cl', 'A', 'The lanthanide contraction makes Zr and Hf almost the same size.', 6),
  ('jee-chemistry-periodicity-q08', 'jee-chemistry-periodicity', 'Down a group, metallic character generally:', 'Increases', 'Decreases', 'Stays constant', 'Disappears', 'A', 'Easier electron loss down a group increases metallic character.', 7),
  ('jee-chemistry-mole-concept-q01', 'jee-chemistry-mole-concept', 'The number of molecules in 2 moles of a gas is:', '6.022 x 10^23', '12 x 10^24', '3.0 x 10^23', '1.2 x 10^24', 'D', '2 moles contain 2 x 6.022 x 10^23 = 1.2 x 10^24 molecules.', 0),
  ('jee-chemistry-mole-concept-q02', 'jee-chemistry-mole-concept', 'The molar volume of an ideal gas at STP is:', '11.2 L', '22.4 L', '24.4 L', '1 L', 'B', 'One mole of ideal gas occupies 22.4 L at STP.', 1),
  ('jee-chemistry-mole-concept-q03', 'jee-chemistry-mole-concept', 'The number of moles in 36 g of water (molar mass 18) is:', '1', '2', '0.5', '18', 'B', 'moles = mass/molar mass = 36/18 = 2.', 2),
  ('jee-chemistry-mole-concept-q04', 'jee-chemistry-mole-concept', 'Molarity is defined as moles of solute per:', 'Kilogram of solvent', 'Litre of solvent', 'Litre of solution', 'Mole of solution', 'C', 'Molarity = moles of solute per litre of solution.', 3),
  ('jee-chemistry-mole-concept-q05', 'jee-chemistry-mole-concept', 'In a reaction, the reagent that is completely consumed is called the:', 'Excess reagent', 'Limiting reagent', 'Catalyst', 'Product', 'B', 'The limiting reagent runs out first and caps the amount of product.', 4),
  ('jee-chemistry-mole-concept-q06', 'jee-chemistry-mole-concept', 'The mass of 0.5 mole of CO2 (molar mass 44) is:', '22 g', '11 g', '44 g', '88 g', 'A', 'mass = moles x molar mass = 0.5 x 44 = 22 g.', 5),
  ('jee-chemistry-mole-concept-q07', 'jee-chemistry-mole-concept', 'On dilution of a solution, the number of moles of solute:', 'Increases', 'Stays the same', 'Decreases', 'Becomes zero', 'B', 'Dilution adds only solvent, so moles of solute stay constant (M1V1 = M2V2).', 6),
  ('jee-chemistry-mole-concept-q08', 'jee-chemistry-mole-concept', 'The empirical formula of a compound with 40 percent C, 6.7 percent H and 53.3 percent O (by mass) is:', 'CHO', 'CH2O', 'C2H4O2', 'CH4O', 'B', 'Mole ratio C:H:O is about 1:2:1, giving the empirical formula CH2O.', 7),
  ('jee-chemistry-equilibrium-q01', 'jee-chemistry-equilibrium', 'At chemical equilibrium, the rates of the forward and reverse reactions are:', 'Zero', 'Maximum', 'Equal', 'Unrelated', 'C', 'Equilibrium is dynamic: forward and reverse rates are equal.', 0),
  ('jee-chemistry-equilibrium-q02', 'jee-chemistry-equilibrium', 'The pH of a 0.01 M strong acid solution is:', '1', '2', '12', '0.01', 'B', 'pH = -log(0.01) = 2.', 1),
  ('jee-chemistry-equilibrium-q03', 'jee-chemistry-equilibrium', 'Adding more reactant to a system at equilibrium shifts it, by Le Chatelier, toward the:', 'Reactants', 'Solid phase', 'No change', 'Products', 'D', 'Increasing a reactant drives the equilibrium toward the products.', 2),
  ('jee-chemistry-equilibrium-q04', 'jee-chemistry-equilibrium', 'The ionic product of water Kw at 25 C is:', '10^-7', '10^-14', '10^-1', '1', 'B', 'Kw = [H+][OH-] = 1.0 x 10^-14 at 25 C.', 3),
  ('jee-chemistry-equilibrium-q05', 'jee-chemistry-equilibrium', 'Increasing pressure on a gaseous equilibrium shifts it toward the side with:', 'Fewer gas moles', 'More gas moles', 'Higher temperature', 'More solid', 'A', 'Higher pressure favours the side with fewer moles of gas.', 4),
  ('jee-chemistry-equilibrium-q06', 'jee-chemistry-equilibrium', 'A buffer solution is best described as one that resists changes in:', 'Temperature', 'Volume', 'pH', 'Colour', 'C', 'A buffer resists pH change on adding small amounts of acid or base.', 5),
  ('jee-chemistry-equilibrium-q07', 'jee-chemistry-equilibrium', 'The relation between Kp and Kc is Kp =:', 'Kc + RT', 'Kc / RT', 'Kc x RT', 'Kc (RT)^delta-n', 'D', 'Kp = Kc (RT) raised to the change in moles of gas, delta-n.', 6),
  ('jee-chemistry-equilibrium-q08', 'jee-chemistry-equilibrium', 'Adding a common ion to a weak electrolyte solution:', 'Increases its ionisation', 'Changes its identity', 'Has no effect', 'Suppresses its ionisation', 'D', 'The common-ion effect shifts equilibrium back, suppressing ionisation.', 7),
  ('jee-chemistry-thermodynamics-q01', 'jee-chemistry-thermodynamics', 'A reaction is spontaneous when the Gibbs energy change is:', 'Positive', 'Infinite', 'Zero', 'Negative', 'D', 'Spontaneity requires delta G to be negative.', 0),
  ('jee-chemistry-thermodynamics-q02', 'jee-chemistry-thermodynamics', 'Hess''s law is based on the fact that enthalpy is a:', 'Path function', 'Random variable', 'State function', 'Constant for all reactions', 'C', 'Enthalpy is a state function, so delta H is path-independent.', 1),
  ('jee-chemistry-thermodynamics-q03', 'jee-chemistry-thermodynamics', 'The Gibbs energy relation is delta G =:', 'delta H + T delta S', 'delta H - T delta S', 'T delta S - delta H', 'delta H x T delta S', 'B', 'delta G = delta H - T delta S.', 2),
  ('jee-chemistry-thermodynamics-q04', 'jee-chemistry-thermodynamics', 'For an exothermic reaction, the enthalpy change delta H is:', 'Positive', 'Zero', 'Negative', 'Always one', 'C', 'Exothermic reactions release heat, so delta H is negative.', 3),
  ('jee-chemistry-thermodynamics-q05', 'jee-chemistry-thermodynamics', 'The entropy of a perfect crystal at absolute zero is, by the third law:', 'Maximum', 'Zero', 'Negative', 'Undefined', 'B', 'The third law sets the entropy of a perfect crystal at 0 K to zero.', 4),
  ('jee-chemistry-thermodynamics-q06', 'jee-chemistry-thermodynamics', 'At equilibrium, the Gibbs energy change of a reaction is:', 'Maximum', 'Minimum negative', 'Zero', 'Large positive', 'C', 'At equilibrium delta G = 0.', 5),
  ('jee-chemistry-thermodynamics-q07', 'jee-chemistry-thermodynamics', 'The relation between standard Gibbs energy and equilibrium constant is delta G-standard =:', 'RT ln K', '-RT ln K', '-R/T ln K', 'RT/K', 'B', 'delta G-standard = -RT ln K links thermodynamics to equilibrium.', 6),
  ('jee-chemistry-thermodynamics-q08', 'jee-chemistry-thermodynamics', 'Which reaction generally shows a positive entropy change?', 'Solid to gas', 'Liquid to solid', 'Gas to liquid', 'Two gases combining into one', 'A', 'Sublimation increases disorder, giving a positive entropy change.', 7),
  ('jee-chemistry-goc-q01', 'jee-chemistry-goc', 'The stability order of carbocations is:', 'methyl > 1 degree > 2 degree > 3 degree', 'All equally stable', '1 degree > 2 degree > 3 degree', '3 degree > 2 degree > 1 degree > methyl', 'D', 'Tertiary carbocations are most stable due to hyperconjugation and inductive donation.', 0),
  ('jee-chemistry-goc-q02', 'jee-chemistry-goc', 'An electron-deficient species that seeks electrons is a:', 'Nucleophile', 'Free radical', 'Electrophile', 'Carbanion', 'C', 'Electrophiles are electron-poor and accept electron pairs.', 1),
  ('jee-chemistry-goc-q03', 'jee-chemistry-goc', 'The -NO2 group exerts which kind of inductive effect?', 'Electron-donating (+I)', 'Electron-withdrawing (-I)', 'No effect', 'Only resonance', 'B', 'Nitro is strongly electron-withdrawing, showing a -I effect.', 2),
  ('jee-chemistry-goc-q04', 'jee-chemistry-goc', 'A carbon atom bonded to four different groups is called:', 'Quaternary', 'Primary', 'Chiral', 'Aromatic', 'C', 'A chiral (asymmetric) carbon has four different substituents and is optically active.', 3),
  ('jee-chemistry-goc-q05', 'jee-chemistry-goc', 'Which is the strongest acid among the following?', 'Ethanol', 'Phenol', 'Acetic acid', 'Water', 'C', 'Carboxylic acids are stronger than phenols and alcohols due to resonance-stabilised anions.', 4),
  ('jee-chemistry-goc-q06', 'jee-chemistry-goc', 'Hyperconjugation involves the delocalisation of electrons from:', 'Lone pairs', 'pi to pi bonds', 'Adjacent C-H sigma bonds', 'd orbitals', 'C', 'Hyperconjugation delocalises electrons of neighbouring C-H sigma bonds into an empty or pi orbital.', 5),
  ('jee-chemistry-goc-q07', 'jee-chemistry-goc', 'Compounds with the same molecular formula but different structures are called:', 'Isotopes', 'Homologues', 'Allotropes', 'Isomers', 'D', 'Isomers share a molecular formula but differ in structure or arrangement.', 6),
  ('jee-chemistry-goc-q08', 'jee-chemistry-goc', 'The resonance (+M) effect of -OH on benzene makes the ring:', 'Deactivated', 'Inert', 'Activated toward electrophiles', 'Meta-directing', 'C', '-OH donates electrons by resonance, activating the ring and directing ortho/para.', 7),
  ('jee-chemistry-hydrocarbons-q01', 'jee-chemistry-hydrocarbons', 'The general formula of an alkane is:', 'CnH2n+2', 'CnH2n', 'CnH2n-2', 'CnHn', 'A', 'Saturated open-chain alkanes follow CnH2n+2.', 0),
  ('jee-chemistry-hydrocarbons-q02', 'jee-chemistry-hydrocarbons', 'Alkanes typically undergo which kind of reaction with halogens in sunlight?', 'Free-radical substitution', 'Electrophilic addition', 'Nucleophilic substitution', 'Elimination', 'A', 'Alkanes undergo free-radical substitution with halogens under UV light.', 1),
  ('jee-chemistry-hydrocarbons-q03', 'jee-chemistry-hydrocarbons', 'Markovnikov''s rule predicts the addition of HBr to propene gives mainly:', '2-bromopropane', '1-bromopropane', 'Propane', 'Propyne', 'A', 'H adds to the carbon with more hydrogens, putting Br on C2 (2-bromopropane).', 2),
  ('jee-chemistry-hydrocarbons-q04', 'jee-chemistry-hydrocarbons', 'Benzene preferentially undergoes:', 'Electrophilic substitution', 'Addition reactions', 'Nucleophilic addition', 'Free-radical addition', 'A', 'Aromatic stability makes benzene favour electrophilic substitution over addition.', 3),
  ('jee-chemistry-hydrocarbons-q05', 'jee-chemistry-hydrocarbons', 'The number of pi bonds in an alkyne triple bond is:', '0', '1', '3', '2', 'D', 'A triple bond has one sigma and two pi bonds.', 4),
  ('jee-chemistry-hydrocarbons-q06', 'jee-chemistry-hydrocarbons', 'Aromaticity by Huckel''s rule requires the number of pi electrons to equal:', '4n', '2n', '4n + 2', 'n + 1', 'C', 'Huckel''s rule: a planar cyclic system is aromatic with (4n + 2) pi electrons.', 5),
  ('jee-chemistry-hydrocarbons-q07', 'jee-chemistry-hydrocarbons', 'Addition of HBr to an alkene in the presence of peroxide gives anti-Markovnikov product via:', 'Carbocation mechanism', 'Ionic mechanism', 'Free-radical mechanism', 'No reaction', 'C', 'The peroxide effect proceeds by a free-radical chain, reversing the regiochemistry.', 6),
  ('jee-chemistry-hydrocarbons-q08', 'jee-chemistry-hydrocarbons', 'A -NO2 substituent on benzene directs an incoming electrophile to the:', 'Meta position', 'Para position', 'Ortho position', 'Ipso position', 'A', 'Nitro is a deactivating, meta-directing group.', 7),
  ('jee-chemistry-coordination-compounds-q01', 'jee-chemistry-coordination-compounds', 'The coordination number of the central metal in [Co(NH3)6]3+ is:', '3', '4', '6', '2', 'C', 'Six ammonia ligands give a coordination number of 6.', 0),
  ('jee-chemistry-coordination-compounds-q02', 'jee-chemistry-coordination-compounds', 'A ligand that binds through two donor atoms is called:', 'Monodentate', 'Ambidentate', 'Bidentate', 'Neutral', 'C', 'A bidentate ligand, such as ethylenediamine, donates through two atoms.', 1),
  ('jee-chemistry-coordination-compounds-q03', 'jee-chemistry-coordination-compounds', 'In crystal field theory, ligands split the d orbitals into:', 't2g and eg sets', 's and p sets', 'Two equal halves', 'Three triplets', 'A', 'In an octahedral field, the d orbitals split into lower t2g and higher eg sets.', 2),
  ('jee-chemistry-coordination-compounds-q04', 'jee-chemistry-coordination-compounds', 'Which ligand is a strong-field ligand that favours low-spin complexes?', 'I-', 'Br-', 'CN-', 'Cl-', 'C', 'Cyanide is a strong-field ligand causing large splitting and low-spin pairing.', 3),
  ('jee-chemistry-coordination-compounds-q05', 'jee-chemistry-coordination-compounds', 'The spin-only magnetic moment for a complex with 2 unpaired electrons is about:', '1.73 BM', '2.83 BM', '3.87 BM', '0 BM', 'B', 'mu = sqrt(n(n+2)) = sqrt(8) = 2.83 BM for n = 2.', 4),
  ('jee-chemistry-coordination-compounds-q06', 'jee-chemistry-coordination-compounds', 'cis-trans isomerism in coordination compounds is a type of:', 'Ionisation isomerism', 'Optical isomerism', 'Linkage isomerism', 'Geometrical isomerism', 'D', 'cis and trans arrangements of ligands are geometrical isomers.', 5),
  ('jee-chemistry-coordination-compounds-q07', 'jee-chemistry-coordination-compounds', 'A polydentate ligand forming a ring with the metal is said to produce a:', 'Lattice', 'Salt bridge', 'Chelate', 'Polymer', 'C', 'Ring formation by a polydentate ligand is called chelation, giving a chelate.', 6),
  ('jee-chemistry-coordination-compounds-q08', 'jee-chemistry-coordination-compounds', 'In the spectrochemical series, which ligand causes the largest crystal-field splitting?', 'H2O', 'NH3', 'CO', 'Cl-', 'C', 'CO lies highest in the spectrochemical series, producing the largest splitting.', 7),
  ('jee-chemistry-electrochemistry-q01', 'jee-chemistry-electrochemistry', 'In a galvanic cell, oxidation occurs at the:', 'Cathode', 'Salt bridge', 'Anode', 'Electrolyte', 'C', 'Oxidation always occurs at the anode of any electrochemical cell.', 0),
  ('jee-chemistry-electrochemistry-q02', 'jee-chemistry-electrochemistry', 'The value of the Faraday constant is approximately:', '9650 C/mol', '96500 C/mol', '6.022 x 10^23 C/mol', '1.6 x 10^-19 C/mol', 'B', 'One Faraday is about 96500 C, the charge of one mole of electrons.', 1),
  ('jee-chemistry-electrochemistry-q03', 'jee-chemistry-electrochemistry', 'The standard cell potential is given by E-cathode minus:', 'Zero', 'E-electrolyte', 'E-anode', 'Twice E-anode', 'C', 'E-cell-standard = E-cathode-standard minus E-anode-standard.', 2),
  ('jee-chemistry-electrochemistry-q04', 'jee-chemistry-electrochemistry', 'The Nernst equation introduces a correction term proportional to:', '1/Q', 'Q squared', 'log Q', 'exp(Q)', 'C', 'The Nernst equation subtracts (0.059/n) log Q from the standard potential.', 3),
  ('jee-chemistry-electrochemistry-q05', 'jee-chemistry-electrochemistry', 'A positive standard reduction potential indicates a species that is a:', 'Strong reducing agent', 'Poor conductor', 'Neutral species', 'Strong oxidising agent', 'D', 'More positive reduction potential means a stronger tendency to be reduced, a good oxidiser.', 4),
  ('jee-chemistry-electrochemistry-q06', 'jee-chemistry-electrochemistry', 'The relation between Gibbs energy and cell potential is delta G-standard =:', 'nFE-standard', 'nF / E-standard', 'E-standard / nF', '-nFE-standard', 'D', 'delta G-standard = -nFE-cell-standard.', 5),
  ('jee-chemistry-electrochemistry-q07', 'jee-chemistry-electrochemistry', 'Kohlrausch''s law concerns the molar conductivity at:', 'High concentration', 'Freezing point', 'Standard pressure', 'Infinite dilution', 'D', 'Kohlrausch''s law gives molar conductivity at infinite dilution as a sum of ionic contributions.', 6),
  ('jee-chemistry-electrochemistry-q08', 'jee-chemistry-electrochemistry', 'Passing 96500 C through molten NaCl deposits how many gram-equivalents of sodium?', '0.5', '1', '2', '23', 'B', 'By Faraday''s law, 96500 C deposits one gram-equivalent of the element.', 7),
  ('jee-chemistry-states-of-matter-q01', 'jee-chemistry-states-of-matter', 'Boyle''s law states that at constant temperature, pressure is:', 'Inversely proportional to volume', 'Proportional to volume', 'Independent of volume', 'Proportional to temperature', 'A', 'At constant T, PV is constant, so P varies inversely with V.', 0),
  ('jee-chemistry-states-of-matter-q02', 'jee-chemistry-states-of-matter', 'The ideal gas constant R in SI units is approximately:', '0.0821 J/(mol K)', '96500 J/(mol K)', '22.4 J/(mol K)', '8.314 J/(mol K)', 'D', 'R = 8.314 J/(mol K) in SI units.', 1),
  ('jee-chemistry-states-of-matter-q03', 'jee-chemistry-states-of-matter', 'Charles''s law states that at constant pressure, volume is proportional to:', 'Pressure', '1/Temperature', 'Absolute temperature', 'Number of collisions', 'C', 'At constant pressure, V is directly proportional to absolute temperature.', 2),
  ('jee-chemistry-states-of-matter-q04', 'jee-chemistry-states-of-matter', 'Dalton''s law of partial pressures states that the total pressure equals the:', 'Product of partial pressures', 'Largest partial pressure', 'Average of partial pressures', 'Sum of partial pressures', 'D', 'Total pressure is the sum of the partial pressures of all gases present.', 3),
  ('jee-chemistry-states-of-matter-q05', 'jee-chemistry-states-of-matter', 'The compressibility factor Z for an ideal gas is:', '1', '0', 'Greater than 1 always', 'Less than 0', 'A', 'For an ideal gas Z = PV/nRT = 1.', 4),
  ('jee-chemistry-states-of-matter-q06', 'jee-chemistry-states-of-matter', 'In the van der Waals equation, the constant b corrects for the:', 'Intermolecular attraction', 'Finite volume of molecules', 'Temperature drift', 'Number of moles', 'B', 'The constant b accounts for the finite volume occupied by gas molecules.', 5),
  ('jee-chemistry-states-of-matter-q07', 'jee-chemistry-states-of-matter', 'Real gases behave most ideally at:', 'High pressure, low temperature', 'Low pressure, low temperature', 'High pressure, high temperature', 'Low pressure, high temperature', 'D', 'At low pressure and high temperature intermolecular forces become negligible.', 6),
  ('jee-chemistry-states-of-matter-q08', 'jee-chemistry-states-of-matter', 'The rms speed of gas molecules increases with:', 'Increasing temperature', 'Increasing molar mass', 'Decreasing temperature', 'Increasing pressure only', 'A', 'v_rms = sqrt(3RT/M) rises with temperature and falls with molar mass.', 7),
  ('jee-mathematics-complex-numbers-q01', 'jee-mathematics-complex-numbers', 'The modulus of the complex number 3 + 4i is:', '25', '7', '5', '1', 'C', '|z| = sqrt(3² + 4²) = sqrt(25) = 5.', 0),
  ('jee-mathematics-complex-numbers-q02', 'jee-mathematics-complex-numbers', 'The value of i raised to the power 4 is:', 'i', '-1', '1', '-i', 'C', 'i² = -1, so i^4 = (i²)² = 1.', 1),
  ('jee-mathematics-complex-numbers-q03', 'jee-mathematics-complex-numbers', 'The sum of the three cube roots of unity is:', '0', '1', '-1', '3', 'A', '1 + omega + omega² = 0 for the cube roots of unity.', 2),
  ('jee-mathematics-complex-numbers-q04', 'jee-mathematics-complex-numbers', 'The conjugate of the complex number 2 - 5i is:', '-2 + 5i', '-2 - 5i', '2 + 5i', '5 - 2i', 'C', 'The conjugate flips the sign of the imaginary part, giving 2 + 5i.', 3),
  ('jee-mathematics-complex-numbers-q05', 'jee-mathematics-complex-numbers', 'By De Moivre''s theorem, (cos(theta) + i sin(theta)) raised to n equals:', 'cos(n theta) + i sin(n theta)', 'cos(n theta) - i sin(n theta)', 'n cos(theta) + i n sin(theta)', 'cos(theta/n) + i sin(theta/n)', 'A', 'De Moivre''s theorem gives cos(n theta) + i sin(n theta).', 4),
  ('jee-mathematics-complex-numbers-q06', 'jee-mathematics-complex-numbers', 'The product of a complex number z and its conjugate equals:', 'z', 'Modulus of z', 'Square of the modulus of z', 'Zero', 'C', 'z times its conjugate equals |z|².', 5),
  ('jee-mathematics-complex-numbers-q07', 'jee-mathematics-complex-numbers', 'Multiplying a complex number by i rotates its representation in the plane by:', '90 degrees', '45 degrees', '180 degrees', '270 degrees', 'A', 'Multiplication by i is rotation by 90 degrees about the origin.', 6),
  ('jee-mathematics-complex-numbers-q08', 'jee-mathematics-complex-numbers', 'The equation |z - 2| = 3 represents in the complex plane a:', 'Straight line', 'Single point', 'Parabola', 'Circle of radius 3', 'D', '|z - z0| = r is a circle of radius r centred at z0, here radius 3 at 2.', 7),
  ('jee-mathematics-sequences-series-q01', 'jee-mathematics-sequences-series', 'The 10th term of the AP 2, 5, 8, ... is:', '29', '27', '30', '32', 'A', 'a_n = a + (n-1)d = 2 + 9(3) = 29.', 0),
  ('jee-mathematics-sequences-series-q02', 'jee-mathematics-sequences-series', 'The sum of the first n natural numbers is:', 'n(n+1)', 'n(n+1)/2', 'n²', 'n(2n+1)/6', 'B', 'Sum of first n naturals is n(n+1)/2.', 1),
  ('jee-mathematics-sequences-series-q03', 'jee-mathematics-sequences-series', 'The sum of an infinite GP with first term 1 and ratio 1/2 is:', '2', '1', '1.5', 'Infinite', 'A', 'S = a/(1 - r) = 1/(1 - 0.5) = 2.', 2),
  ('jee-mathematics-sequences-series-q04', 'jee-mathematics-sequences-series', 'The geometric mean of 4 and 9 is:', '6', '6.5', '13', '36', 'A', 'GM = sqrt(4 x 9) = sqrt(36) = 6.', 3),
  ('jee-mathematics-sequences-series-q05', 'jee-mathematics-sequences-series', 'For positive numbers, the relation among the three means is:', 'AM = GM = HM', 'AM is at least GM is at least HM', 'HM is at least GM is at least AM', 'GM is the largest', 'B', 'AM is greater than or equal to GM, which is greater than or equal to HM.', 4),
  ('jee-mathematics-sequences-series-q06', 'jee-mathematics-sequences-series', 'The 5th term of the GP 3, 6, 12, ... is:', '24', '96', '48', '36', 'C', 'a_n = a r^(n-1) = 3 x 2^4 = 48.', 5),
  ('jee-mathematics-sequences-series-q07', 'jee-mathematics-sequences-series', 'The sum of squares of the first n natural numbers is:', 'n(n+1)/2', '[n(n+1)/2]²', 'n(n+1)(2n+1)/6', 'n²', 'C', 'Sum of squares is n(n+1)(2n+1)/6.', 6),
  ('jee-mathematics-sequences-series-q08', 'jee-mathematics-sequences-series', 'A sequence whose reciprocals form an AP is called a:', 'Geometric progression', 'Fibonacci sequence', 'Arithmetic progression', 'Harmonic progression', 'D', 'If reciprocals are in AP, the original sequence is a harmonic progression.', 7),
  ('jee-mathematics-permutations-combinations-q01', 'jee-mathematics-permutations-combinations', 'The value of 5! (5 factorial) is:', '25', '120', '60', '720', 'B', '5! = 5 x 4 x 3 x 2 x 1 = 120.', 0),
  ('jee-mathematics-permutations-combinations-q02', 'jee-mathematics-permutations-combinations', 'The number of ways to choose 2 items from 5 distinct items is:', '5', '25', '20', '10', 'D', '5C2 = 10.', 1),
  ('jee-mathematics-permutations-combinations-q03', 'jee-mathematics-permutations-combinations', 'The number of arrangements (permutations) of 3 items chosen from 5 is:', '60', '15', '120', '10', 'A', '5P3 = 5!/(2!) = 60.', 2),
  ('jee-mathematics-permutations-combinations-q04', 'jee-mathematics-permutations-combinations', 'The number of circular permutations of 5 distinct objects is:', '24', '120', '5', '60', 'A', 'Circular permutations of n objects equal (n-1)! = 4! = 24.', 3),
  ('jee-mathematics-permutations-combinations-q05', 'jee-mathematics-permutations-combinations', 'The sum of all binomial coefficients nC0 + nC1 + ... + nCn equals:', 'n', 'n squared', 'n!', '2 raised to n', 'D', 'Setting a = b = 1 in (a+b)^n gives the sum 2 raised to n.', 4),
  ('jee-mathematics-permutations-combinations-q06', 'jee-mathematics-permutations-combinations', 'The number of ways to arrange the letters of the word LEVEL is:', '30', '60', '120', '20', 'A', 'LEVEL has 5 letters with L and E repeated twice: 5!/(2! 2!) = 30.', 5),
  ('jee-mathematics-permutations-combinations-q07', 'jee-mathematics-permutations-combinations', 'The identity nCr equals:', 'nC(n+r)', 'nCr-1', 'nC(n-r)', 'n!/r!', 'C', 'By symmetry, nCr = nC(n-r).', 6),
  ('jee-mathematics-permutations-combinations-q08', 'jee-mathematics-permutations-combinations', 'The number of ways to select at least one item from 4 distinct items is:', '4', '8', '15', '16', 'C', 'Total subsets minus the empty set: 2^4 - 1 = 15.', 7),
  ('jee-mathematics-binomial-theorem-q01', 'jee-mathematics-binomial-theorem', 'The number of terms in the expansion of (a + b) raised to 7 is:', '7', '8', '9', '14', 'B', 'The expansion of (a + b)^n has n + 1 terms, here 8.', 0),
  ('jee-mathematics-binomial-theorem-q02', 'jee-mathematics-binomial-theorem', 'The general term of (a + b) raised to n is:', 'nCr a^r b^(n-r)', 'nCr a^(n-r) b^r', 'nPr a^(n-r) b^r', 'a^(n-r) b^r', 'B', 'The (r+1)th term is nCr times a^(n-r) times b^r.', 1),
  ('jee-mathematics-binomial-theorem-q03', 'jee-mathematics-binomial-theorem', 'The coefficient of x² in the expansion of (1 + x) raised to 4 is:', '6', '4', '8', '12', 'A', 'The coefficient is 4C2 = 6.', 2),
  ('jee-mathematics-binomial-theorem-q04', 'jee-mathematics-binomial-theorem', 'The middle term in the expansion of (a + b) raised to 6 is the term number:', '3rd', '4th', '5th', '6th', 'B', 'For n = 6 (even), the single middle term is the (n/2 + 1) = 4th term.', 3),
  ('jee-mathematics-binomial-theorem-q05', 'jee-mathematics-binomial-theorem', 'The sum of the binomial coefficients in (1 + x) raised to 5 is:', '16', '10', '32', '25', 'C', 'Putting x = 1 gives 2^5 = 32.', 4),
  ('jee-mathematics-binomial-theorem-q06', 'jee-mathematics-binomial-theorem', 'For small x, the approximation (1 + x) raised to n is approximately:', '1 + x raised to n', '1 - nx', 'nx', '1 + nx', 'D', 'For small x, (1 + x)^n is about 1 + nx.', 5),
  ('jee-mathematics-binomial-theorem-q07', 'jee-mathematics-binomial-theorem', 'The number of middle terms in the expansion of (a + b) raised to 9 is:', '1', '0', '3', '2', 'D', 'When n is odd there are two middle terms.', 6),
  ('jee-mathematics-binomial-theorem-q08', 'jee-mathematics-binomial-theorem', 'Pascal''s rule states nCr + nC(r-1) equals:', 'nC(r+1)', '(n+1)Cr', '(n-1)Cr', '2 nCr', 'B', 'Pascal''s rule: nCr + nC(r-1) = (n+1)Cr.', 7),
  ('jee-mathematics-matrices-determinants-q01', 'jee-mathematics-matrices-determinants', 'The determinant of the 2x2 matrix with rows (2, 3) and (1, 4) is:', '8', '5', '11', '-5', 'B', 'Determinant = (2)(4) - (3)(1) = 8 - 3 = 5.', 0),
  ('jee-mathematics-matrices-determinants-q02', 'jee-mathematics-matrices-determinants', 'A square matrix is invertible only if its determinant is:', 'Non-zero', 'Zero', 'Positive', 'An integer', 'A', 'An inverse exists only when the determinant is non-zero.', 1),
  ('jee-mathematics-matrices-determinants-q03', 'jee-mathematics-matrices-determinants', 'Matrix multiplication is in general:', 'Commutative', 'Equal to addition', 'Always undefined', 'Not commutative', 'D', 'In general AB is not equal to BA, so matrix multiplication is not commutative.', 2),
  ('jee-mathematics-matrices-determinants-q04', 'jee-mathematics-matrices-determinants', 'If two rows of a determinant are identical, its value is:', '1', 'Doubled', 'Negative', 'Zero', 'D', 'A determinant with two equal rows is zero.', 3),
  ('jee-mathematics-matrices-determinants-q05', 'jee-mathematics-matrices-determinants', 'For a 3x3 matrix A, the determinant of kA equals:', 'k det(A)', 'k² det(A)', 'det(A)', 'k³ det(A)', 'D', 'For an n x n matrix, det(kA) = k^n det(A); here k³ det(A).', 4),
  ('jee-mathematics-matrices-determinants-q06', 'jee-mathematics-matrices-determinants', 'A matrix that equals its own transpose is called:', 'Skew-symmetric', 'Symmetric', 'Singular', 'Orthogonal', 'B', 'A matrix with transpose equal to itself is symmetric.', 5),
  ('jee-mathematics-matrices-determinants-q07', 'jee-mathematics-matrices-determinants', 'Cramer''s rule can be used to solve a linear system only when the coefficient determinant is:', 'Zero', 'Non-zero', 'Negative', 'Even', 'B', 'Cramer''s rule requires a non-zero coefficient determinant for a unique solution.', 6),
  ('jee-mathematics-matrices-determinants-q08', 'jee-mathematics-matrices-determinants', 'The diagonal elements of a skew-symmetric matrix are all:', 'Zero', 'One', 'Equal', 'Negative', 'A', 'A skew-symmetric matrix has all diagonal entries zero.', 7),
  ('jee-mathematics-straight-lines-circles-q01', 'jee-mathematics-straight-lines-circles', 'The slope of the line passing through (1, 2) and (3, 6) is:', '1', '3', '2', '4', 'C', 'Slope = (6 - 2)/(3 - 1) = 4/2 = 2.', 0),
  ('jee-mathematics-straight-lines-circles-q02', 'jee-mathematics-straight-lines-circles', 'Two lines are perpendicular when the product of their slopes is:', '0', '1', 'Infinite', '-1', 'D', 'Perpendicular lines satisfy m1 times m2 = -1.', 1),
  ('jee-mathematics-straight-lines-circles-q03', 'jee-mathematics-straight-lines-circles', 'The radius of the circle x² + y² = 49 is:', '14', '49', '7', '24.5', 'C', 'Comparing with x² + y² = r² gives r = sqrt(49) = 7.', 2),
  ('jee-mathematics-straight-lines-circles-q04', 'jee-mathematics-straight-lines-circles', 'The centre of the circle x² + y² + 2gx + 2fy + c = 0 is:', '(-g, -f)', '(g, f)', '(2g, 2f)', '(-2g, -2f)', 'A', 'The centre of the general circle is (-g, -f).', 3),
  ('jee-mathematics-straight-lines-circles-q05', 'jee-mathematics-straight-lines-circles', 'Two parallel lines have slopes that are:', 'Negative reciprocals', 'Equal', 'Zero', 'Opposite in sign', 'B', 'Parallel lines have equal slopes.', 4),
  ('jee-mathematics-straight-lines-circles-q06', 'jee-mathematics-straight-lines-circles', 'The distance of the point (0, 0) from the line 3x + 4y - 10 = 0 is:', '1', '2', '10', '5', 'B', 'Distance = |0 + 0 - 10|/sqrt(9 + 16) = 10/5 = 2.', 5),
  ('jee-mathematics-straight-lines-circles-q07', 'jee-mathematics-straight-lines-circles', 'A line is tangent to a circle when its distance from the centre equals the:', 'Diameter', 'Circumference', 'Radius', 'Zero', 'C', 'Tangency requires the centre-to-line distance to equal the radius.', 6),
  ('jee-mathematics-straight-lines-circles-q08', 'jee-mathematics-straight-lines-circles', 'The equation of a line with slope 2 and y-intercept 3 is:', 'y = 3x + 2', 'y = 2x + 3', 'y = 2x - 3', 'x = 2y + 3', 'B', 'Using y = mx + c with m = 2 and c = 3 gives y = 2x + 3.', 7),
  ('jee-mathematics-limits-continuity-q01', 'jee-mathematics-limits-continuity', 'The limit as x approaches 0 of sin(x)/x is:', '0', '1', 'Infinite', 'Undefined', 'B', 'This is a standard limit equal to 1.', 0),
  ('jee-mathematics-limits-continuity-q02', 'jee-mathematics-limits-continuity', 'A function f is continuous at x = a if the limit of f as x approaches a equals:', '0', 'Infinity', 'f(a)', 'f prime of a', 'C', 'Continuity at a requires the limit to equal the function value f(a).', 1),
  ('jee-mathematics-limits-continuity-q03', 'jee-mathematics-limits-continuity', 'The function |x| at x = 0 is:', 'Differentiable', 'Undefined', 'Discontinuous', 'Continuous but not differentiable', 'D', '|x| is continuous everywhere but has a corner at 0, so it is not differentiable there.', 2),
  ('jee-mathematics-limits-continuity-q04', 'jee-mathematics-limits-continuity', 'The derivative of x³ with respect to x is:', 'x²', '3x²', '3x', 'x³/3', 'B', 'By the power rule, d/dx of x³ is 3x².', 3),
  ('jee-mathematics-limits-continuity-q05', 'jee-mathematics-limits-continuity', 'The limit as x approaches 0 of (e^x - 1)/x is:', '0', 'e', '1', 'Infinite', 'C', 'This standard limit equals 1.', 4),
  ('jee-mathematics-limits-continuity-q06', 'jee-mathematics-limits-continuity', 'Differentiability of a function at a point implies that it is:', 'Discontinuous there', 'Unbounded', 'Constant', 'Continuous there', 'D', 'Differentiability implies continuity, though the converse is false.', 5),
  ('jee-mathematics-limits-continuity-q07', 'jee-mathematics-limits-continuity', 'The derivative of the product uv is:', 'u prime v + u v prime', 'u prime v prime', 'u prime v - u v prime', 'u v', 'A', 'The product rule gives (uv) prime = u prime v + u v prime.', 6),
  ('jee-mathematics-limits-continuity-q08', 'jee-mathematics-limits-continuity', 'A limit of the indeterminate form 0/0 can often be evaluated using:', 'The power rule', 'Integration', 'L''Hopital''s rule', 'The product rule', 'C', 'L''Hopital''s rule resolves 0/0 and infinity/infinity forms by differentiating top and bottom.', 7),
  ('jee-mathematics-integration-q01', 'jee-mathematics-integration', 'The integral of x² with respect to x is:', '2x + C', 'x³ + C', 'x³/3 + C', '3x² + C', 'C', 'By the power rule, the integral of x² is x³/3 + C.', 0),
  ('jee-mathematics-integration-q02', 'jee-mathematics-integration', 'The integral of 1/x with respect to x is:', '-1/x² + C', 'ln|x| + C', 'x + C', '1 + C', 'B', 'The integral of 1/x is the natural logarithm ln|x| + C.', 1),
  ('jee-mathematics-integration-q03', 'jee-mathematics-integration', 'The integration by parts formula is the integral of u dv equals:', 'uv minus the integral of v du', 'uv plus the integral of v du', 'uv times the integral of du', 'the integral of u times the integral of dv', 'A', 'Integration by parts: integral of u dv = uv minus the integral of v du.', 2),
  ('jee-mathematics-integration-q04', 'jee-mathematics-integration', 'The definite integral of 2x from 0 to 3 is:', '6', '18', '9', '3', 'C', 'The antiderivative is x², so the value is 9 - 0 = 9.', 3),
  ('jee-mathematics-integration-q05', 'jee-mathematics-integration', 'The integral over a symmetric interval (-a to a) of an odd function is:', '2 times the integral from 0 to a', 'Infinite', 'a²', 'Zero', 'D', 'An odd function integrates to zero over a symmetric interval.', 4),
  ('jee-mathematics-integration-q06', 'jee-mathematics-integration', 'The integral of e^x with respect to x is:', 'x e^x + C', 'ln(x) + C', 'e^x / x + C', 'e^x + C', 'D', 'The integral of e^x is itself, e^x + C.', 5),
  ('jee-mathematics-integration-q07', 'jee-mathematics-integration', 'The Fundamental Theorem of Calculus links integration to:', 'Multiplication', 'Factoring', 'Differentiation', 'Series summation', 'C', 'It states the definite integral equals the change in an antiderivative, linking it to differentiation.', 6),
  ('jee-mathematics-integration-q08', 'jee-mathematics-integration', 'The recommended order for choosing u in integration by parts is given by:', 'ILATE', 'FOIL', 'PEMDAS', 'SOHCAHTOA', 'A', 'ILATE orders functions (inverse, log, algebraic, trig, exponential) for choosing u.', 7),
  ('jee-mathematics-vectors-3d-q01', 'jee-mathematics-vectors-3d', 'The dot product of two perpendicular vectors is:', 'Maximum', 'Negative', 'Their product of magnitudes', 'Zero', 'D', 'a dot b = |a||b|cos(90) = 0 for perpendicular vectors.', 0),
  ('jee-mathematics-vectors-3d-q02', 'jee-mathematics-vectors-3d', 'The cross product of two parallel vectors is:', 'Maximum', 'The zero vector', 'A scalar', 'Their sum', 'B', 'a cross b = |a||b|sin(0) = 0 for parallel vectors.', 1),
  ('jee-mathematics-vectors-3d-q03', 'jee-mathematics-vectors-3d', 'The magnitude of the vector (3, 0, 4) is:', '7', '5', '12', '25', 'B', 'Magnitude = sqrt(9 + 0 + 16) = sqrt(25) = 5.', 2),
  ('jee-mathematics-vectors-3d-q04', 'jee-mathematics-vectors-3d', 'The scalar triple product of three vectors gives the volume of a:', 'Sphere', 'Cylinder', 'Parallelepiped', 'Cone', 'C', 'The scalar triple product a dot (b cross c) equals the parallelepiped volume.', 3),
  ('jee-mathematics-vectors-3d-q05', 'jee-mathematics-vectors-3d', 'Three vectors are coplanar when their scalar triple product is:', 'Positive', 'Zero', 'Negative', 'One', 'B', 'Coplanarity makes the scalar triple product (the volume) zero.', 4),
  ('jee-mathematics-vectors-3d-q06', 'jee-mathematics-vectors-3d', 'The direction ratios of the normal to the plane 2x + 3y - z + 5 = 0 are:', '(1, 1, 1)', '(2, 3, 5)', '(5, 3, -1)', '(2, 3, -1)', 'D', 'The coefficients of x, y, z give the normal''s direction ratios (2, 3, -1).', 5),
  ('jee-mathematics-vectors-3d-q07', 'jee-mathematics-vectors-3d', 'The cross product of two vectors yields a vector that is:', 'Parallel to both', 'Perpendicular to both', 'In the same plane', 'Always zero', 'B', 'The cross product is perpendicular to both original vectors.', 6),
  ('jee-mathematics-vectors-3d-q08', 'jee-mathematics-vectors-3d', 'The angle between two planes equals the angle between their:', 'Areas', 'Normals', 'Intercepts', 'Centroids', 'B', 'The angle between two planes is the angle between their normal vectors.', 7),
  ('jee-mathematics-probability-q01', 'jee-mathematics-probability', 'The probability of getting a head in a single toss of a fair coin is:', '0', '0.25', '1', '0.5', 'D', 'A fair coin has two equally likely outcomes, so P(head) = 0.5.', 0),
  ('jee-mathematics-probability-q02', 'jee-mathematics-probability', 'The probability of rolling a number greater than 4 on a fair die is:', '1/6', '2/3', '1/2', '1/3', 'D', 'Favourable outcomes are 5 and 6, so probability = 2/6 = 1/3.', 1),
  ('jee-mathematics-probability-q03', 'jee-mathematics-probability', 'For two independent events, P(A and B) equals:', 'P(A) + P(B)', 'P(A)/P(B)', 'P(A) - P(B)', 'P(A) times P(B)', 'D', 'Independent events satisfy P(A and B) = P(A) times P(B).', 2),
  ('jee-mathematics-probability-q04', 'jee-mathematics-probability', 'The sum of the probabilities of an event and its complement is:', '0', '0.5', '1', '2', 'C', 'P(E) + P(E complement) = 1.', 3),
  ('jee-mathematics-probability-q05', 'jee-mathematics-probability', 'For mutually exclusive events A and B, P(A or B) equals:', 'P(A) times P(B)', 'P(A) + P(B) - P(A and B)', 'P(A) + P(B)', '1', 'C', 'Mutually exclusive events cannot both occur, so P(A or B) = P(A) + P(B).', 4),
  ('jee-mathematics-probability-q06', 'jee-mathematics-probability', 'The conditional probability P(A given B) is defined as:', 'P(B)/P(A)', 'P(A)/P(B)', 'P(A and B) times P(B)', 'P(A and B)/P(B)', 'D', 'P(A given B) = P(A and B)/P(B).', 5),
  ('jee-mathematics-probability-q07', 'jee-mathematics-probability', 'The mean of a binomial distribution with parameters n and p is:', 'n/p', 'npq', 'p/n', 'np', 'D', 'The mean of a binomial distribution is np.', 6),
  ('jee-mathematics-probability-q08', 'jee-mathematics-probability', 'Drawing two aces in succession from a deck without replacement involves events that are:', 'Independent', 'Dependent', 'Mutually exclusive', 'Impossible', 'B', 'Without replacement, the first draw changes the second''s probability, so events are dependent.', 7),
  ('neet-biology-cell-structure-function-q01', 'neet-biology-cell-structure-function', 'Which organelle is known as the ''powerhouse of the cell''?', 'Ribosome', 'Lysosome', 'Golgi apparatus', 'Mitochondrion', 'D', 'Mitochondria generate most cellular ATP through aerobic respiration.', 0),
  ('neet-biology-cell-structure-function-q02', 'neet-biology-cell-structure-function', 'Ribosomes found in the cytoplasm of eukaryotic cells are of the type:', '80S', '70S', '50S', '30S', 'A', 'Eukaryotic cytoplasmic ribosomes are 80S; the 70S type occurs in mitochondria and chloroplasts.', 1),
  ('neet-biology-cell-structure-function-q03', 'neet-biology-cell-structure-function', 'Which structure is present in plant cells but absent in animal cells?', 'Mitochondrion', 'Nucleus', 'Ribosome', 'Cellulose cell wall', 'D', 'A rigid cellulose cell wall surrounds plant cells but is absent in animal cells.', 2),
  ('neet-biology-cell-structure-function-q04', 'neet-biology-cell-structure-function', 'Lysosomes are often called the ''suicide bags'' because they contain:', 'Photosynthetic pigments', 'DNA', 'Hydrolytic enzymes', 'Ribosomes', 'C', 'Lysosomes are packed with hydrolytic enzymes that can digest the cell''s own components.', 3),
  ('neet-biology-cell-structure-function-q05', 'neet-biology-cell-structure-function', 'The fluid-mosaic model of the plasma membrane was proposed by:', 'Schleiden and Schwann', 'Robert Hooke', 'Singer and Nicolson', 'Watson and Crick', 'C', 'Singer and Nicolson (1972) described the membrane as a lipid bilayer with mobile proteins.', 4),
  ('neet-biology-cell-structure-function-q06', 'neet-biology-cell-structure-function', 'Which feature distinguishes a prokaryotic from a eukaryotic cell?', 'Presence of cytoplasm', 'Presence of a plasma membrane', 'Presence of ribosomes', 'Absence of a membrane-bound nucleus', 'D', 'Prokaryotes lack a true membrane-bound nucleus; their DNA lies in a nucleoid region.', 5),
  ('neet-biology-cell-structure-function-q07', 'neet-biology-cell-structure-function', 'The nucleolus is the site of synthesis of:', 'DNA', 'rRNA', 'Lipids', 'ATP', 'B', 'The nucleolus is the centre of ribosomal RNA synthesis and ribosome assembly.', 6),
  ('neet-biology-cell-structure-function-q08', 'neet-biology-cell-structure-function', '''Omnis cellula e cellula'', meaning new cells arise from existing cells, was stated by:', 'Robert Hooke', 'Rudolf Virchow', 'Theodor Schwann', 'Anton van Leeuwenhoek', 'B', 'Virchow extended the cell theory with the principle that every cell comes from a pre-existing cell.', 7),
  ('neet-biology-human-physiology-digestion-q01', 'neet-biology-human-physiology-digestion', 'Salivary amylase (ptyalin) acts on:', 'Proteins', 'Fats', 'Starch', 'Nucleic acids', 'C', 'Ptyalin begins starch digestion in the mouth, converting it to maltose.', 0),
  ('neet-biology-human-physiology-digestion-q02', 'neet-biology-human-physiology-digestion', 'Pepsin is secreted in an inactive form called:', 'Pepsinogen', 'Prorennin', 'Trypsinogen', 'Chymotrypsinogen', 'A', 'Inactive pepsinogen is activated to pepsin by the HCl of gastric juice.', 1),
  ('neet-biology-human-physiology-digestion-q03', 'neet-biology-human-physiology-digestion', 'Bile, secreted by the liver, helps digestion by:', 'Breaking proteins', 'Emulsifying fats', 'Hydrolysing starch', 'Absorbing water', 'B', 'Bile salts emulsify large fat globules into smaller droplets for lipase to act on.', 2),
  ('neet-biology-human-physiology-digestion-q04', 'neet-biology-human-physiology-digestion', 'Most absorption of digested food occurs in the:', 'Stomach', 'Oesophagus', 'Small intestine', 'Large intestine', 'C', 'Villi and microvilli of the small intestine provide a huge surface for absorption.', 3),
  ('neet-biology-human-physiology-digestion-q05', 'neet-biology-human-physiology-digestion', 'The adult human dental formula 2123/2123 corresponds to how many teeth?', '20', '28', '36', '32', 'D', 'Each half-jaw has 2 incisors, 1 canine, 2 premolars, 3 molars; total 32 teeth.', 4),
  ('neet-biology-human-physiology-digestion-q06', 'neet-biology-human-physiology-digestion', 'The largest gland in the human body is the:', 'Liver', 'Pancreas', 'Salivary gland', 'Thyroid', 'A', 'The liver is the largest gland; it produces bile and stores glycogen.', 5),
  ('neet-biology-human-physiology-digestion-q07', 'neet-biology-human-physiology-digestion', 'Intrinsic factor secreted by the stomach is essential for the absorption of:', 'Vitamin C', 'Calcium', 'Vitamin B₁₂', 'Iron', 'C', 'Intrinsic factor binds vitamin B₁₂, enabling its absorption in the ileum.', 6),
  ('neet-biology-human-physiology-digestion-q08', 'neet-biology-human-physiology-digestion', 'Which enzyme from the pancreas digests fats?', 'Amylase', 'Lipase', 'Trypsin', 'Pepsin', 'B', 'Pancreatic lipase breaks fats into fatty acids and glycerol.', 7),
  ('neet-chemistry-organic-chemistry-basics-q01', 'neet-chemistry-organic-chemistry-basics', 'The correct order of stability of carbocations is:', 'Methyl > 1° > 2° > 3°', '2° > 3° > 1° > methyl', '3° > 2° > 1° > methyl', '1° > 2° > 3° > methyl', 'C', 'Hyperconjugation and the +I effect make tertiary carbocations the most stable.', 0),
  ('neet-chemistry-organic-chemistry-basics-q02', 'neet-chemistry-organic-chemistry-basics', 'An electrophile is a species that is:', 'Electron-rich', 'A free radical', 'Always negatively charged', 'Electron-deficient', 'D', 'Electrophiles are electron-poor and accept an electron pair from a nucleophile.', 1),
  ('neet-chemistry-organic-chemistry-basics-q03', 'neet-chemistry-organic-chemistry-basics', 'Which group shows a +M (electron-donating resonance) effect?', '−NO₂', '−C≡N', '−COOH', '−NH₂', 'D', 'The lone pair on −NH₂ is donated into the ring, a +M effect.', 2),
  ('neet-chemistry-organic-chemistry-basics-q04', 'neet-chemistry-organic-chemistry-basics', 'The hybridisation of the positively charged carbon in a carbocation is:', 'sp', 'sp²', 'sp³', 'sp³d', 'B', 'A carbocation carbon is sp² hybridised with an empty p-orbital, giving planar geometry.', 3),
  ('neet-chemistry-organic-chemistry-basics-q05', 'neet-chemistry-organic-chemistry-basics', 'Which of the following is the most acidic?', 'Ethanol', 'Acetic acid', 'Phenol', 'Water', 'B', 'Carboxylic acids are more acidic than phenols, alcohols and water due to resonance-stabilised anions.', 4),
  ('neet-chemistry-organic-chemistry-basics-q06', 'neet-chemistry-organic-chemistry-basics', 'Hyperconjugation involves the delocalisation of electrons from:', 'A σ (C–H) bond', 'A π bond only', 'A lone pair', 'A d orbital', 'A', 'Hyperconjugation delocalises σ(C–H) bond electrons into an adjacent empty or π orbital.', 5),
  ('neet-chemistry-organic-chemistry-basics-q07', 'neet-chemistry-organic-chemistry-basics', 'A chiral carbon atom must be bonded to:', 'A double bond', 'Two identical groups', 'Four different groups', 'A hydrogen only', 'C', 'Optical activity requires a carbon attached to four different groups (a stereocentre).', 6),
  ('neet-chemistry-organic-chemistry-basics-q08', 'neet-chemistry-organic-chemistry-basics', 'Electron-withdrawing groups attached to an acid generally:', 'Decrease acidity', 'Make it basic', 'Have no effect', 'Increase acidity', 'D', 'They stabilise the conjugate base by dispersing negative charge, increasing acidity.', 7),
  ('neet-physics-ray-optics-q01', 'neet-physics-ray-optics', 'The focal length of a spherical mirror is related to its radius of curvature by:', 'f = R', 'f = 2R', 'f = R/4', 'f = R/2', 'D', 'For a spherical mirror the focal length is half the radius of curvature, f = R/2.', 0),
  ('neet-physics-ray-optics-q02', 'neet-physics-ray-optics', 'Total internal reflection occurs when light travels from a:', 'Denser to a rarer medium beyond the critical angle', 'Denser to a rarer medium at normal incidence', 'Medium to vacuum at any angle', 'Rarer to a denser medium', 'A', 'TIR needs a denser-to-rarer transition with the incidence angle exceeding the critical angle.', 1),
  ('neet-physics-ray-optics-q03', 'neet-physics-ray-optics', 'The power of a lens of focal length 50 cm is:', '0.5 D', '5 D', '2 D', '50 D', 'C', 'P = 1/f(m) = 1/0.5 = 2 dioptres.', 2),
  ('neet-physics-ray-optics-q04', 'neet-physics-ray-optics', 'A convex lens always forms which type of image of a distant object?', 'Virtual and erect', 'Real and erect', 'Virtual and inverted', 'Real and inverted', 'D', 'A converging lens forms a real, inverted image of a distant real object on the far side.', 3),
  ('neet-physics-ray-optics-q05', 'neet-physics-ray-optics', 'Snell''s law relates the angles of incidence and refraction through:', 'n₁ cos i = n₂ cos r', 'n₁ sin i = n₂ sin r', 'n₁ tan i = n₂ tan r', 'n₁ i = n₂ r', 'B', 'Snell''s law states n₁ sin i = n₂ sin r at a refracting boundary.', 4),
  ('neet-physics-ray-optics-q06', 'neet-physics-ray-optics', 'Two thin lenses of power +3 D and +2 D placed in contact have a combined power of:', '1.2 D', '1 D', '6 D', '5 D', 'D', 'Powers add for lenses in contact: P = 3 + 2 = 5 D.', 5),
  ('neet-physics-ray-optics-q07', 'neet-physics-ray-optics', 'A prism produces a spectrum of white light because the refractive index:', 'Is constant for all colours', 'Depends on wavelength', 'Depends on the prism mass', 'Is zero for violet light', 'B', 'Refractive index varies with wavelength, so violet bends most and red least (dispersion).', 6),
  ('neet-physics-ray-optics-q08', 'neet-physics-ray-optics', 'A convex mirror always forms an image that is:', 'Real and inverted', 'Virtual and magnified', 'Real and magnified', 'Virtual, erect and diminished', 'D', 'A convex (diverging) mirror always gives a virtual, erect, diminished image, useful as a rear-view mirror.', 7),
  ('neet-biology-cell-cycle-cell-division-q01', 'neet-biology-cell-cycle-cell-division', 'DNA replication during the cell cycle occurs in which phase?', 'S phase', 'G1 phase', 'G2 phase', 'M phase', 'A', 'DNA is replicated during the S (synthesis) phase, doubling the chromosomal DNA content.', 0),
  ('neet-biology-cell-cycle-cell-division-q02', 'neet-biology-cell-cycle-cell-division', 'Separation of sister chromatids to opposite poles takes place during:', 'Prophase', 'Anaphase', 'Metaphase', 'Telophase', 'B', 'In anaphase the centromeres split and sister chromatids move to opposite poles.', 1),
  ('neet-biology-cell-cycle-cell-division-q03', 'neet-biology-cell-cycle-cell-division', 'Crossing over, which recombines genetic material, occurs during which sub-stage of prophase I?', 'Leptotene', 'Pachytene', 'Zygotene', 'Diakinesis', 'B', 'Crossing over occurs at the chiasmata during pachytene of meiotic prophase I.', 2),
  ('neet-biology-cell-cycle-cell-division-q04', 'neet-biology-cell-cycle-cell-division', 'Meiosis in a human cell produces gametes with how many chromosomes?', '46', '22', '92', '23', 'D', 'Meiosis is reductional, halving the diploid 46 to the haploid 23 in gametes.', 3),
  ('neet-biology-cell-cycle-cell-division-q05', 'neet-biology-cell-cycle-cell-division', 'At which stage of mitosis do chromosomes align at the equatorial plate?', 'Anaphase', 'Metaphase', 'Telophase', 'Prophase', 'B', 'During metaphase the chromosomes line up at the equatorial (metaphase) plate.', 4),
  ('neet-biology-cell-cycle-cell-division-q06', 'neet-biology-cell-cycle-cell-division', 'The quiescent stage in which cells exit the cell cycle is called:', 'M phase', 'S phase', 'G2 phase', 'G0 phase', 'D', 'G0 is a quiescent stage where cells leave the cycle, as seen in mature neurons.', 5),
  ('neet-biology-cell-cycle-cell-division-q07', 'neet-biology-cell-cycle-cell-division', 'Reduction in chromosome number during meiosis occurs at:', 'Meiosis II', 'Cytokinesis', 'Meiosis I', 'Interphase', 'C', 'The chromosome number is halved at meiosis I; meiosis II resembles mitosis.', 6),
  ('neet-biology-cell-cycle-cell-division-q08', 'neet-biology-cell-cycle-cell-division', 'Mitosis is described as equational division because the daughter cells are:', 'Diploid and identical to the parent', 'Haploid and different', 'Haploid and identical', 'Tetraploid', 'A', 'Mitosis produces two diploid daughter cells genetically identical to the parent cell.', 7),
  ('neet-biology-biomolecules-q01', 'neet-biology-biomolecules', 'Proteins are polymers of amino acids joined by which type of bond?', 'Glycosidic bond', 'Hydrogen bond', 'Phosphodiester bond', 'Peptide bond', 'D', 'Amino acids are linked by peptide bonds to form polypeptides and proteins.', 0),
  ('neet-biology-biomolecules-q02', 'neet-biology-biomolecules', 'The most abundant protein in the entire biosphere is:', 'Haemoglobin', 'Collagen', 'Keratin', 'RuBisCO', 'D', 'RuBisCO, the CO2-fixing enzyme of photosynthesis, is the most abundant protein in the biosphere.', 1),
  ('neet-biology-biomolecules-q03', 'neet-biology-biomolecules', 'The alpha-helix and beta-pleated sheet describe which level of protein structure?', 'Secondary', 'Primary', 'Tertiary', 'Quaternary', 'A', 'Secondary structure refers to local folding such as the alpha-helix and beta-pleated sheet.', 2),
  ('neet-biology-biomolecules-q04', 'neet-biology-biomolecules', 'The storage polysaccharide in animals is:', 'Starch', 'Glycogen', 'Cellulose', 'Chitin', 'B', 'Glycogen is the storage polysaccharide in animals, while starch stores energy in plants.', 3),
  ('neet-biology-biomolecules-q05', 'neet-biology-biomolecules', 'Enzymes act as biological catalysts mainly by:', 'Lowering activation energy', 'Raising activation energy', 'Changing the equilibrium constant', 'Supplying heat', 'A', 'Enzymes accelerate reactions by lowering the activation energy without altering equilibrium.', 4),
  ('neet-biology-biomolecules-q06', 'neet-biology-biomolecules', 'Haemoglobin, with four polypeptide subunits, illustrates which level of protein organisation?', 'Primary', 'Secondary', 'Quaternary', 'Tertiary', 'C', 'Quaternary structure arises from the association of multiple subunits, as in haemoglobin.', 5),
  ('neet-biology-biomolecules-q07', 'neet-biology-biomolecules', 'An inhibitor that resembles the substrate and binds the active site is a:', 'Coenzyme', 'Non-competitive inhibitor', 'Allosteric activator', 'Competitive inhibitor', 'D', 'Competitive inhibitors structurally resemble the substrate and compete for the active site.', 6),
  ('neet-biology-biomolecules-q08', 'neet-biology-biomolecules', 'Cellulose is a structural homopolymer made of:', 'Alpha-D-glucose', 'Amino acids', 'Fructose', 'Beta-D-glucose', 'D', 'Cellulose is a structural homopolymer of beta-D-glucose units.', 7),
  ('neet-biology-photosynthesis-higher-plants-q01', 'neet-biology-photosynthesis-higher-plants', 'The light reaction of photosynthesis takes place in the:', 'Stroma', 'Thylakoid membrane', 'Cytoplasm', 'Mitochondrial matrix', 'B', 'The light reaction occurs on the thylakoid membranes, producing ATP, NADPH and O2.', 0),
  ('neet-biology-photosynthesis-higher-plants-q02', 'neet-biology-photosynthesis-higher-plants', 'Oxygen released during photosynthesis comes from:', 'Photolysis of water', 'Glucose', 'Carbon dioxide', 'RuBP', 'A', 'The splitting (photolysis) of water in the light reaction releases molecular oxygen.', 1),
  ('neet-biology-photosynthesis-higher-plants-q03', 'neet-biology-photosynthesis-higher-plants', 'The enzyme that fixes CO2 onto RuBP in the Calvin cycle is:', 'PEP carboxylase', 'ATP synthase', 'RuBisCO', 'Carbonic anhydrase', 'C', 'RuBisCO fixes CO2 onto RuBP, the first stable product being 3-PGA in the C3 pathway.', 2),
  ('neet-biology-photosynthesis-higher-plants-q04', 'neet-biology-photosynthesis-higher-plants', 'The first stable product of the C3 (Calvin) cycle is a compound with how many carbons?', '3-carbon (3-PGA)', '4-carbon (OAA)', '5-carbon (RuBP)', '6-carbon (glucose)', 'A', 'In C3 plants the first stable product is the 3-carbon 3-phosphoglyceric acid (3-PGA).', 3),
  ('neet-biology-photosynthesis-higher-plants-q05', 'neet-biology-photosynthesis-higher-plants', 'In C4 plants CO2 is first fixed in the mesophyll by which enzyme?', 'RuBisCO', 'PEP carboxylase', 'Hexokinase', 'Dehydrogenase', 'B', 'C4 plants fix CO2 as oxaloacetate via PEP carboxylase, minimising photorespiration.', 4),
  ('neet-biology-photosynthesis-higher-plants-q06', 'neet-biology-photosynthesis-higher-plants', 'The primary photosynthetic pigment in green plants is:', 'Carotenoid', 'Xanthophyll', 'Chlorophyll a', 'Anthocyanin', 'C', 'Chlorophyll a is the primary pigment; carotenoids serve as accessory pigments.', 5),
  ('neet-biology-photosynthesis-higher-plants-q07', 'neet-biology-photosynthesis-higher-plants', 'Which wavelengths of light are most effective for photosynthesis?', 'Green and yellow', 'Orange only', 'Red and blue', 'Ultraviolet', 'C', 'Red and blue wavelengths are absorbed best by chlorophyll and drive photosynthesis effectively.', 6),
  ('neet-biology-photosynthesis-higher-plants-q08', 'neet-biology-photosynthesis-higher-plants', 'The dark reaction (Calvin cycle) occurs in which part of the chloroplast?', 'Thylakoid lumen', 'Stroma', 'Thylakoid membrane', 'Outer membrane', 'B', 'The Calvin cycle, which synthesises sugar, takes place in the stroma of the chloroplast.', 7),
  ('neet-biology-plant-animal-tissues-q01', 'neet-biology-plant-animal-tissues', 'Conduction of water from roots to leaves is carried out by:', 'Phloem', 'Xylem', 'Collenchyma', 'Parenchyma', 'B', 'Xylem conducts water and minerals upward; phloem translocates food.', 0),
  ('neet-biology-plant-animal-tissues-q02', 'neet-biology-plant-animal-tissues', 'Which animal tissue has plasma as its fluid matrix?', 'Muscular tissue', 'Nervous tissue', 'Epithelial tissue', 'Blood', 'D', 'Blood is a fluid connective tissue with plasma serving as its liquid matrix.', 1),
  ('neet-biology-plant-animal-tissues-q03', 'neet-biology-plant-animal-tissues', 'Tendons, which connect muscle to bone, are an example of which tissue?', 'Connective', 'Epithelial', 'Muscular', 'Nervous', 'A', 'Tendons are dense connective tissue joining muscle to bone; ligaments join bone to bone.', 2),
  ('neet-biology-plant-animal-tissues-q04', 'neet-biology-plant-animal-tissues', 'Flexible mechanical support in young plant stems is provided mainly by:', 'Sclerenchyma', 'Phloem', 'Xylem', 'Collenchyma', 'D', 'Collenchyma provides flexible support; sclerenchyma gives rigid support.', 3),
  ('neet-biology-plant-animal-tissues-q05', 'neet-biology-plant-animal-tissues', 'Cardiac muscle is correctly described as:', 'Smooth and multinucleate', 'Smooth and voluntary', 'Striated and voluntary', 'Striated, branched and involuntary', 'D', 'Cardiac muscle is striated, branched, uninucleate and involuntary.', 4),
  ('neet-biology-plant-animal-tissues-q06', 'neet-biology-plant-animal-tissues', 'Active cell division in plants takes place in tissue called:', 'Parenchyma', 'Sclerenchyma', 'Phloem', 'Meristematic tissue', 'D', 'Meristematic tissue consists of dividing cells responsible for plant growth.', 5),
  ('neet-biology-plant-animal-tissues-q07', 'neet-biology-plant-animal-tissues', 'Which tissue lines and covers body surfaces in animals?', 'Connective', 'Muscular', 'Epithelial', 'Nervous', 'C', 'Epithelial tissue covers and lines body surfaces and cavities.', 6),
  ('neet-biology-plant-animal-tissues-q08', 'neet-biology-plant-animal-tissues', 'Translocation of food in plants occurs through sieve tubes of the:', 'Phloem', 'Xylem', 'Cambium', 'Cortex', 'A', 'Phloem, through its sieve tubes, translocates the food prepared in leaves.', 7),
  ('neet-biology-breathing-exchange-of-gases-q01', 'neet-biology-breathing-exchange-of-gases', 'The exchange of gases in the lungs occurs across the walls of the:', 'Bronchi', 'Trachea', 'Larynx', 'Alveoli', 'D', 'Gaseous exchange occurs by diffusion across the thin walls of the alveoli.', 0),
  ('neet-biology-breathing-exchange-of-gases-q02', 'neet-biology-breathing-exchange-of-gases', 'Carbon dioxide is transported in blood mainly as:', 'Bicarbonate ions', 'Carbaminohaemoglobin', 'Dissolved CO2', 'Carbonic acid gas', 'A', 'About 70 percent of CO2 is carried as bicarbonate ions in the plasma.', 1),
  ('neet-biology-breathing-exchange-of-gases-q03', 'neet-biology-breathing-exchange-of-gases', 'During inspiration the diaphragm:', 'Relaxes and domes up', 'Flattens and contracts', 'Stays unchanged', 'Moves sideways only', 'B', 'The diaphragm flattens and contracts during inspiration, increasing thoracic volume.', 2),
  ('neet-biology-breathing-exchange-of-gases-q04', 'neet-biology-breathing-exchange-of-gases', 'The respiratory rhythm centre that controls breathing is located in the:', 'Cerebellum', 'Hypothalamus', 'Medulla oblongata', 'Spinal cord', 'C', 'The breathing centre lies in the medulla oblongata of the brain.', 3),
  ('neet-biology-breathing-exchange-of-gases-q05', 'neet-biology-breathing-exchange-of-gases', 'Oxygen is transported in blood predominantly as:', 'Oxyhaemoglobin', 'Dissolved O2 in plasma', 'Bicarbonate', 'Carbamino compound', 'A', 'About 97 percent of oxygen is carried bound to haemoglobin as oxyhaemoglobin.', 4),
  ('neet-biology-breathing-exchange-of-gases-q06', 'neet-biology-breathing-exchange-of-gases', 'The approximate tidal volume of a normal adult human is:', '4500 mL', '1500 mL', '3500 mL', '500 mL', 'D', 'Tidal volume, the air exchanged in a normal breath, is about 500 mL.', 5),
  ('neet-biology-breathing-exchange-of-gases-q07', 'neet-biology-breathing-exchange-of-gases', 'The enzyme in RBCs that speeds conversion of CO2 to bicarbonate is:', 'Pepsin', 'Carbonic anhydrase', 'Catalase', 'Amylase', 'B', 'Carbonic anhydrase in red blood cells accelerates the CO2-to-bicarbonate reaction.', 6),
  ('neet-biology-breathing-exchange-of-gases-q08', 'neet-biology-breathing-exchange-of-gases', 'A rightward shift of the oxygen dissociation curve (Bohr effect) is favoured by:', 'Low CO2 and high pH', 'High pH alone', 'Low temperature only', 'High CO2, low pH and high temperature', 'D', 'High CO2, low pH and high temperature shift the curve right, releasing more O2 to tissues.', 7),
  ('neet-biology-body-fluids-circulation-q01', 'neet-biology-body-fluids-circulation', 'The natural pacemaker of the human heart is the:', 'AV node', 'Bundle of His', 'SA node', 'Purkinje fibres', 'C', 'The sino-atrial (SA) node generates impulses and acts as the heart''s pacemaker.', 0),
  ('neet-biology-body-fluids-circulation-q02', 'neet-biology-body-fluids-circulation', 'Mature mammalian red blood cells are unusual because they:', 'Have two nuclei', 'Lack a nucleus', 'Contain chlorophyll', 'Are amoeboid', 'B', 'Mature mammalian RBCs lack a nucleus and live for about 120 days.', 1),
  ('neet-biology-body-fluids-circulation-q03', 'neet-biology-body-fluids-circulation', 'The valve located between the left atrium and left ventricle is the:', 'Tricuspid valve', 'Pulmonary valve', 'Bicuspid (mitral) valve', 'Aortic valve', 'C', 'The bicuspid (mitral) valve lies between the left atrium and left ventricle.', 2),
  ('neet-biology-body-fluids-circulation-q04', 'neet-biology-body-fluids-circulation', 'Blood clotting is the primary function of:', 'Erythrocytes', 'Leukocytes', 'Platelets', 'Plasma proteins only', 'C', 'Platelets (thrombocytes) play the central role in blood coagulation.', 3),
  ('neet-biology-body-fluids-circulation-q05', 'neet-biology-body-fluids-circulation', 'In the ABO system, which blood group is the universal donor?', 'A', 'B', 'AB', 'O', 'D', 'Group O lacks A and B surface antigens, making it the universal donor.', 4),
  ('neet-biology-body-fluids-circulation-q06', 'neet-biology-body-fluids-circulation', 'Roughly what percentage of blood volume is plasma?', 'About 10 percent', 'About 25 percent', 'About 90 percent', 'About 55 percent', 'D', 'Plasma forms about 55 percent of blood volume and is its fluid matrix.', 5),
  ('neet-biology-body-fluids-circulation-q07', 'neet-biology-body-fluids-circulation', 'The human heart is described as myogenic because the heartbeat originates in:', 'Nerves of the brain', 'Cardiac muscle itself', 'The spinal cord', 'Adrenal glands', 'B', 'A myogenic heart generates its own beat from cardiac muscle (the SA node), not from nerves.', 6),
  ('neet-biology-body-fluids-circulation-q08', 'neet-biology-body-fluids-circulation', 'Double circulation in humans is advantageous because it:', 'Mixes oxygenated and deoxygenated blood', 'Keeps oxygenated and deoxygenated blood separate', 'Removes the need for a heart', 'Slows blood flow to tissues', 'B', 'Double circulation keeps oxygenated and deoxygenated blood separate for efficient delivery.', 7),
  ('neet-biology-excretory-products-elimination-q01', 'neet-biology-excretory-products-elimination', 'The functional unit of the kidney is the:', 'Neuron', 'Glomerulus', 'Alveolus', 'Nephron', 'D', 'The nephron is the structural and functional unit of the kidney.', 0),
  ('neet-biology-excretory-products-elimination-q02', 'neet-biology-excretory-products-elimination', 'Humans are ureotelic, meaning the chief nitrogenous waste excreted is:', 'Urea', 'Uric acid', 'Ammonia', 'Amino acids', 'A', 'Ureotelic animals like humans excrete urea, formed in the liver by the ornithine cycle.', 1),
  ('neet-biology-excretory-products-elimination-q03', 'neet-biology-excretory-products-elimination', 'Glomerular filtration in the nephron takes place at the:', 'Loop of Henle', 'Distal tubule', 'Collecting duct', 'Bowman''s capsule', 'D', 'Filtration occurs at Bowman''s capsule, which encloses the glomerulus.', 2),
  ('neet-biology-excretory-products-elimination-q04', 'neet-biology-excretory-products-elimination', 'ADH (vasopressin) acts on the kidney to:', 'Increase urine volume', 'Excrete more glucose', 'Promote water reabsorption', 'Block filtration', 'C', 'ADH promotes water reabsorption, concentrating the urine and conserving water.', 3),
  ('neet-biology-excretory-products-elimination-q05', 'neet-biology-excretory-products-elimination', 'Birds and reptiles, which excrete mainly uric acid, are termed:', 'Uricotelic', 'Ureotelic', 'Ammonotelic', 'Osmotic', 'A', 'Uricotelic animals such as birds and reptiles excrete nitrogen mainly as uric acid.', 4),
  ('neet-biology-excretory-products-elimination-q06', 'neet-biology-excretory-products-elimination', 'The glomerular filtration rate (GFR) in a healthy person is about:', '25 mL per minute', '500 mL per minute', '125 mL per minute', '1000 mL per minute', 'C', 'A healthy GFR is about 125 mL per minute (roughly 180 L filtered per day).', 5),
  ('neet-biology-excretory-products-elimination-q07', 'neet-biology-excretory-products-elimination', 'The medullary concentration gradient of the kidney is maintained by the:', 'Counter-current mechanism in the loop of Henle', 'Glomerulus', 'Bowman''s capsule', 'Renal pelvis', 'A', 'The counter-current mechanism in the loop of Henle maintains the medullary osmotic gradient.', 6),
  ('neet-biology-excretory-products-elimination-q08', 'neet-biology-excretory-products-elimination', 'The hormone renin, which raises blood pressure via RAAS, is released by:', 'JG cells of the kidney', 'Adrenal cortex', 'Liver', 'Pancreas', 'A', 'Juxtaglomerular (JG) cells release renin, triggering the RAAS to raise blood pressure.', 7),
  ('neet-biology-neural-control-coordination-q01', 'neet-biology-neural-control-coordination', 'The resting membrane potential of a neuron is approximately:', '+70 mV', '0 mV', '-30 mV', '-70 mV', 'D', 'The resting potential is about -70 mV, with more sodium ions outside the membrane.', 0),
  ('neet-biology-neural-control-coordination-q02', 'neet-biology-neural-control-coordination', 'Conduction of the nerve impulse in myelinated fibres is called:', 'Continuous conduction', 'Saltatory conduction', 'Synaptic conduction', 'Reflex conduction', 'B', 'In myelinated axons the impulse jumps between nodes of Ranvier, called saltatory conduction.', 1),
  ('neet-biology-neural-control-coordination-q03', 'neet-biology-neural-control-coordination', 'Which part of the brain controls balance and coordination of movement?', 'Cerebrum', 'Cerebellum', 'Medulla oblongata', 'Hypothalamus', 'B', 'The cerebellum controls balance, posture and coordination of voluntary movement.', 2),
  ('neet-biology-neural-control-coordination-q04', 'neet-biology-neural-control-coordination', 'During depolarisation in an action potential, which ions rush into the neuron?', 'Potassium ions', 'Chloride ions', 'Sodium ions', 'Calcium ions only', 'C', 'Depolarisation occurs as sodium ions rush into the neuron, reversing membrane polarity.', 3),
  ('neet-biology-neural-control-coordination-q05', 'neet-biology-neural-control-coordination', 'A commonly cited chemical neurotransmitter at synapses is:', 'Insulin', 'Renin', 'Haemoglobin', 'Acetylcholine', 'D', 'Acetylcholine is a neurotransmitter that carries signals across chemical synapses.', 4),
  ('neet-biology-neural-control-coordination-q06', 'neet-biology-neural-control-coordination', 'The resting potential of a neuron is maintained chiefly by the:', 'Nucleus', 'Myelin sheath', 'Sodium-potassium pump', 'Golgi body', 'C', 'The sodium-potassium pump actively maintains the ionic gradient and resting potential.', 5),
  ('neet-biology-neural-control-coordination-q07', 'neet-biology-neural-control-coordination', 'The central nervous system consists of the:', 'Sense organs', 'Nerves and ganglia', 'Brain and spinal cord', 'Autonomic nerves only', 'C', 'The central nervous system comprises the brain and the spinal cord.', 6),
  ('neet-biology-neural-control-coordination-q08', 'neet-biology-neural-control-coordination', 'A rapid involuntary response such as withdrawing the hand from heat is integrated at the:', 'Cerebrum', 'Cerebellum', 'Spinal cord (reflex arc)', 'Thalamus', 'C', 'A reflex arc allows rapid involuntary responses, integrated at the spinal cord.', 7),
  ('neet-biology-principles-inheritance-variation-q01', 'neet-biology-principles-inheritance-variation', 'The phenotypic ratio of a monohybrid cross in the F2 generation is:', '1:1', '3:1', '9:3:3:1', '1:2:1', 'B', 'A monohybrid cross gives a 3:1 phenotypic ratio in the F2 generation.', 0),
  ('neet-biology-principles-inheritance-variation-q02', 'neet-biology-principles-inheritance-variation', 'Mendel performed his classic genetic experiments using:', 'Drosophila', 'Maize', 'Garden pea', 'Snapdragon', 'C', 'Mendel used the garden pea, Pisum sativum, to establish the laws of inheritance.', 1),
  ('neet-biology-principles-inheritance-variation-q03', 'neet-biology-principles-inheritance-variation', 'Inheritance of the ABO blood group, where both alleles express, is an example of:', 'Incomplete dominance', 'Codominance', 'Epistasis', 'Linkage', 'B', 'ABO blood groups show codominance, where alleles I-A and I-B are both expressed.', 2),
  ('neet-biology-principles-inheritance-variation-q04', 'neet-biology-principles-inheritance-variation', 'Down syndrome is caused by:', 'Trisomy of chromosome 21', 'Monosomy of chromosome 21', 'Trisomy of chromosome 18', 'XXY genotype', 'A', 'Down syndrome results from trisomy of chromosome 21 (three copies of chromosome 21).', 3),
  ('neet-biology-principles-inheritance-variation-q05', 'neet-biology-principles-inheritance-variation', 'Mendel''s law of segregation states that:', 'Alleles assort independently', 'One allele always masks another', 'Alleles separate during gamete formation', 'Genes are linked', 'C', 'The law of segregation states that paired alleles separate during gamete formation.', 4),
  ('neet-biology-principles-inheritance-variation-q06', 'neet-biology-principles-inheritance-variation', 'Haemophilia and red-green colour blindness are inherited as:', 'Autosomal dominant traits', 'Y-linked traits', 'X-linked recessive traits', 'Mitochondrial traits', 'C', 'Both haemophilia and colour blindness are X-linked recessive disorders.', 5),
  ('neet-biology-principles-inheritance-variation-q07', 'neet-biology-principles-inheritance-variation', 'A dihybrid cross between two heterozygotes gives an F2 phenotypic ratio of:', '9:3:3:1', '1:2:1', '3:1', '1:1:1:1', 'A', 'A dihybrid cross yields a 9:3:3:1 phenotypic ratio in the F2 generation.', 6),
  ('neet-biology-principles-inheritance-variation-q08', 'neet-biology-principles-inheritance-variation', 'Crossing an individual of unknown genotype with a homozygous recessive parent is a:', 'Test cross', 'Back cross to dominant', 'Reciprocal cross', 'Dihybrid cross', 'A', 'A test cross with a homozygous recessive parent reveals the unknown genotype.', 7),
  ('neet-biology-molecular-basis-inheritance-q01', 'neet-biology-molecular-basis-inheritance', 'The double-helix model of DNA was proposed in 1953 by:', 'Watson and Crick', 'Meselson and Stahl', 'Hershey and Chase', 'Griffith and Avery', 'A', 'Watson and Crick proposed the antiparallel double-helix structure of DNA in 1953.', 0),
  ('neet-biology-molecular-basis-inheritance-q02', 'neet-biology-molecular-basis-inheritance', 'In DNA, adenine pairs with thymine through how many hydrogen bonds?', 'One', 'Two', 'Three', 'Four', 'B', 'A=T pairing involves two hydrogen bonds, whereas G=C uses three.', 1),
  ('neet-biology-molecular-basis-inheritance-q03', 'neet-biology-molecular-basis-inheritance', 'DNA replication is described as semiconservative, a fact proved experimentally by:', 'Meselson and Stahl', 'Watson and Crick', 'Mendel', 'Morgan', 'A', 'Meselson and Stahl demonstrated the semiconservative nature of DNA replication.', 2),
  ('neet-biology-molecular-basis-inheritance-q04', 'neet-biology-molecular-basis-inheritance', 'The start codon that signals the beginning of translation is:', 'UAA', 'AUG', 'UAG', 'UGA', 'B', 'AUG is the start codon coding for methionine; UAA, UAG and UGA are stop codons.', 3),
  ('neet-biology-molecular-basis-inheritance-q05', 'neet-biology-molecular-basis-inheritance', 'The classic model of inducible gene regulation in E. coli is the:', 'trp operon', 'ara operon', 'lac operon', 'gal operon', 'C', 'The lac operon of E. coli is the classic example of inducible gene regulation.', 4),
  ('neet-biology-molecular-basis-inheritance-q06', 'neet-biology-molecular-basis-inheritance', 'The enzyme that synthesises mRNA from a DNA template during transcription is:', 'RNA polymerase', 'DNA polymerase', 'DNA ligase', 'Helicase', 'A', 'RNA polymerase transcribes DNA into mRNA during transcription.', 5),
  ('neet-biology-molecular-basis-inheritance-q07', 'neet-biology-molecular-basis-inheritance', 'According to the central dogma, the correct flow of genetic information is:', 'Protein to RNA to DNA', 'RNA to DNA to Protein', 'DNA to Protein to RNA', 'DNA to RNA to Protein', 'D', 'The central dogma describes information flowing from DNA to RNA to protein.', 6),
  ('neet-biology-molecular-basis-inheritance-q08', 'neet-biology-molecular-basis-inheritance', 'The portion of tRNA that base-pairs with the mRNA codon is the:', 'Anticodon', 'Codon', 'Promoter', 'Operator', 'A', 'The tRNA anticodon reads and base-pairs with the complementary mRNA codon.', 7),
  ('neet-biology-evolution-q01', 'neet-biology-evolution', 'The theory of natural selection was proposed by:', 'Lamarck', 'De Vries', 'Darwin and Wallace', 'Mendel', 'C', 'Darwin and Wallace independently proposed evolution by natural selection.', 0),
  ('neet-biology-evolution-q02', 'neet-biology-evolution', 'Homologous organs, having a common origin but different functions, indicate:', 'Convergent evolution', 'Parallel evolution', 'Divergent evolution', 'Coevolution', 'C', 'Homologous organs share a common origin and indicate divergent evolution.', 1),
  ('neet-biology-evolution-q03', 'neet-biology-evolution', 'The wings of a bird and a butterfly are analogous organs that show:', 'Divergent evolution', 'Adaptive radiation only', 'Convergent evolution', 'Genetic drift', 'C', 'Analogous organs have different origins but similar function, indicating convergent evolution.', 2),
  ('neet-biology-evolution-q04', 'neet-biology-evolution', 'The inheritance of acquired characters was the central idea of:', 'Darwin', 'Wallace', 'Lamarck', 'Hardy', 'C', 'Lamarck proposed the now-discredited inheritance of acquired characters.', 3),
  ('neet-biology-evolution-q05', 'neet-biology-evolution', 'Industrial melanism in peppered moths is a classic example of:', 'Genetic drift', 'Natural selection', 'Mutation pressure', 'Gene flow', 'B', 'The rise of dark peppered moths during industrialisation illustrates natural selection.', 4),
  ('neet-biology-evolution-q06', 'neet-biology-evolution', 'The Miller-Urey experiment provided evidence for:', 'Spontaneous generation', 'Natural selection', 'Chemical evolution of life', 'Genetic drift', 'C', 'The Miller-Urey experiment supported the chemical (abiogenic) origin of organic molecules.', 5),
  ('neet-biology-evolution-q07', 'neet-biology-evolution', 'The Hardy-Weinberg principle states that allele frequencies remain constant when:', 'No evolutionary forces act', 'Mutation is frequent', 'Migration is high', 'Selection is strong', 'A', 'Allele frequencies stay constant in the absence of evolutionary forces (Hardy-Weinberg).', 6),
  ('neet-biology-evolution-q08', 'neet-biology-evolution', 'The correct sequence in human evolution is:', 'Homo sapiens to Homo erectus to Homo habilis', 'Australopithecus to Homo habilis to Homo erectus to Homo sapiens', 'Homo erectus to Australopithecus to Homo sapiens', 'Homo habilis to Australopithecus to Homo sapiens', 'B', 'Human evolution proceeded Australopithecus to Homo habilis to Homo erectus to Homo sapiens.', 7),
  ('neet-biology-human-reproduction-q01', 'neet-biology-human-reproduction', 'In humans fertilisation normally takes place in the:', 'Uterus', 'Ovary', 'Ampulla of the fallopian tube', 'Cervix', 'C', 'Fertilisation occurs in the ampulla of the fallopian tube, forming a diploid zygote.', 0),
  ('neet-biology-human-reproduction-q02', 'neet-biology-human-reproduction', 'Ovulation in a typical 28-day menstrual cycle is triggered by a surge of:', 'FSH', 'LH', 'Progesterone', 'Oxytocin', 'B', 'A mid-cycle LH surge around day 14 triggers ovulation.', 1),
  ('neet-biology-human-reproduction-q03', 'neet-biology-human-reproduction', 'Spermatogenesis takes place within the:', 'Epididymis', 'Seminiferous tubules of the testis', 'Prostate gland', 'Vas deferens', 'B', 'Sperm are produced in the seminiferous tubules of the testis.', 2),
  ('neet-biology-human-reproduction-q04', 'neet-biology-human-reproduction', 'The hormone detected by most pregnancy tests is:', 'Oestrogen', 'Progesterone', 'FSH', 'hCG', 'D', 'Human chorionic gonadotropin (hCG) is the basis of common pregnancy tests.', 3),
  ('neet-biology-human-reproduction-q05', 'neet-biology-human-reproduction', 'Progesterone that maintains the uterine lining is secreted mainly by the:', 'Corpus luteum', 'Anterior pituitary', 'Placenta in early days only', 'Hypothalamus', 'A', 'The corpus luteum secretes progesterone that maintains the uterine endometrium.', 4),
  ('neet-biology-human-reproduction-q06', 'neet-biology-human-reproduction', 'The hormone that stimulates uterine contractions during childbirth is:', 'Oxytocin', 'Insulin', 'Thyroxine', 'Aldosterone', 'A', 'Oxytocin stimulates strong uterine contractions during parturition (childbirth).', 5),
  ('neet-biology-human-reproduction-q07', 'neet-biology-human-reproduction', 'Normal human gestation lasts approximately:', '6 months', '9 months (about 280 days)', '12 months', '3 months', 'B', 'Human gestation lasts about 9 months (roughly 280 days).', 6),
  ('neet-biology-human-reproduction-q08', 'neet-biology-human-reproduction', 'After fertilisation, the structure that implants in the uterine wall is the:', 'Zygote', 'Corpus luteum', 'Ovum', 'Blastocyst', 'D', 'The blastocyst implants in the uterine wall, after which the placenta develops.', 7),
  ('neet-biology-biotechnology-principles-q01', 'neet-biology-biotechnology-principles', 'Enzymes that cut DNA at specific recognition sequences are called:', 'DNA ligases', 'Polymerases', 'Restriction endonucleases', 'Helicases', 'C', 'Restriction endonucleases are molecular scissors that cut DNA at specific sites.', 0),
  ('neet-biology-biotechnology-principles-q02', 'neet-biology-biotechnology-principles', 'The heat-stable enzyme used in PCR is:', 'DNA ligase', 'Reverse transcriptase', 'Restriction enzyme', 'Taq polymerase', 'D', 'PCR uses heat-stable Taq polymerase to extend primers during repeated cycles.', 1),
  ('neet-biology-biotechnology-principles-q03', 'neet-biology-biotechnology-principles', 'In gel electrophoresis, DNA fragments move towards the:', 'Negative electrode', 'Neither electrode', 'Positive electrode', 'Both equally', 'C', 'Negatively charged DNA migrates towards the positive electrode (anode) in electrophoresis.', 2),
  ('neet-biology-biotechnology-principles-q04', 'neet-biology-biotechnology-principles', 'The enzyme that joins two DNA fragments together is:', 'Amylase', 'Restriction enzyme', 'DNA ligase', 'Lipase', 'C', 'DNA ligase seals the nicks and joins DNA fragments into recombinant molecules.', 3),
  ('neet-biology-biotechnology-principles-q05', 'neet-biology-biotechnology-principles', 'A widely used restriction endonuclease in genetic engineering is:', 'Taq', 'RNase', 'DNA ligase', 'EcoRI', 'D', 'EcoRI is a commonly used restriction enzyme that cuts DNA at a specific palindromic site.', 4),
  ('neet-biology-biotechnology-principles-q06', 'neet-biology-biotechnology-principles', 'The vehicle most commonly used to carry foreign DNA into a host cell is a:', 'Ribosome', 'Lysosome', 'Plasmid vector', 'Centriole', 'C', 'A plasmid acts as a vector, carrying foreign DNA into a host such as E. coli.', 5),
  ('neet-biology-biotechnology-principles-q07', 'neet-biology-biotechnology-principles', 'The three repeating steps of one PCR cycle are:', 'Ligation, cutting, sealing', 'Denaturation, annealing, extension', 'Transcription, translation, folding', 'Replication, transcription, translation', 'B', 'Each PCR cycle consists of denaturation, primer annealing and extension.', 6),
  ('neet-biology-biotechnology-principles-q08', 'neet-biology-biotechnology-principles', 'Large-scale culture of cells for biotechnological products is carried out in:', 'Petri dishes only', 'Autoclaves', 'Test tubes', 'Bioreactors', 'D', 'Bioreactors allow large-scale culture of cells to obtain biotechnology products.', 7),
  ('neet-biology-ecosystem-biodiversity-q01', 'neet-biology-ecosystem-biodiversity', 'Green plants in an ecosystem occupy the trophic level of:', 'Primary consumers', 'Decomposers', 'Producers', 'Secondary consumers', 'C', 'Green plants are producers (autotrophs), the first trophic level of an ecosystem.', 0),
  ('neet-biology-ecosystem-biodiversity-q02', 'neet-biology-ecosystem-biodiversity', 'The 10 percent law of energy transfer between trophic levels was given by:', 'Odum', 'Tansley', 'Lindeman', 'Darwin', 'C', 'Lindeman''s 10 percent law states only about 10 percent of energy passes to the next trophic level.', 1),
  ('neet-biology-ecosystem-biodiversity-q03', 'neet-biology-ecosystem-biodiversity', 'The pyramid of energy in an ecosystem is always:', 'Upright', 'Inverted', 'Spindle-shaped', 'Horizontal', 'A', 'The pyramid of energy is always upright because energy decreases at each higher level.', 2),
  ('neet-biology-ecosystem-biodiversity-q04', 'neet-biology-ecosystem-biodiversity', 'Conservation of species within their natural habitat, as in national parks, is:', 'Ex situ conservation', 'Tissue culture', 'Cryopreservation', 'In situ conservation', 'D', 'In situ conservation protects species in their natural habitats like parks and reserves.', 3),
  ('neet-biology-ecosystem-biodiversity-q05', 'neet-biology-ecosystem-biodiversity', 'Energy flow through an ecosystem is described as:', 'Cyclic', 'Unidirectional', 'Bidirectional', 'Random', 'B', 'Energy flow in an ecosystem is unidirectional, moving from producers to consumers.', 4),
  ('neet-biology-ecosystem-biodiversity-q06', 'neet-biology-ecosystem-biodiversity', 'The greatest species richness on Earth is found in the:', 'Polar regions', 'Deserts', 'Tropics', 'Temperate grasslands', 'C', 'Species richness is highest in the tropics, which support the greatest biodiversity.', 5),
  ('neet-biology-ecosystem-biodiversity-q07', 'neet-biology-ecosystem-biodiversity', 'Threatened species are officially classified by the:', 'WWF', 'UNESCO', 'IUCN Red List', 'FAO', 'C', 'The IUCN Red List classifies the conservation status of threatened species.', 6),
  ('neet-biology-ecosystem-biodiversity-q08', 'neet-biology-ecosystem-biodiversity', 'A species with a disproportionately large effect on its ecosystem is called a:', 'Pioneer species', 'Keystone species', 'Endemic species', 'Invasive species', 'B', 'A keystone species has an effect on its community far larger than its abundance suggests.', 7),
  ('neet-biology-human-health-disease-q01', 'neet-biology-human-health-disease', 'Malaria in humans is caused by which pathogen?', 'Plasmodium', 'Salmonella', 'Entamoeba', 'HIV', 'A', 'Malaria is caused by the protozoan Plasmodium, transmitted by female Anopheles mosquitoes.', 0),
  ('neet-biology-human-health-disease-q02', 'neet-biology-human-health-disease', 'Malaria is transmitted to humans by the bite of the female:', 'Culex mosquito', 'Anopheles mosquito', 'Aedes mosquito', 'Housefly', 'B', 'The female Anopheles mosquito is the vector that transmits Plasmodium causing malaria.', 1),
  ('neet-biology-human-health-disease-q03', 'neet-biology-human-health-disease', 'HIV, the cause of AIDS, primarily attacks which cells of the immune system?', 'Red blood cells', 'Helper T-cells', 'Platelets', 'Neurons', 'B', 'HIV targets and destroys helper T-cells, weakening the immune response in AIDS.', 2),
  ('neet-biology-human-health-disease-q04', 'neet-biology-human-health-disease', 'Vaccination protects against disease by inducing:', 'Passive immunity', 'Allergy', 'Innate immunity only', 'Active immunity', 'D', 'Vaccines induce active immunity by exposing the body to weakened or inactivated antigens.', 3),
  ('neet-biology-human-health-disease-q05', 'neet-biology-human-health-disease', 'Immunity that is present from birth and is non-specific is termed:', 'Acquired immunity', 'Active immunity', 'Innate immunity', 'Passive immunity', 'C', 'Innate immunity is non-specific and present from birth, forming the first line of defence.', 4),
  ('neet-biology-human-health-disease-q06', 'neet-biology-human-health-disease', 'Typhoid fever is caused by the bacterium:', 'Plasmodium', 'Entamoeba', 'Salmonella', 'Wuchereria', 'C', 'Typhoid is caused by the bacterium Salmonella typhi.', 5),
  ('neet-biology-human-health-disease-q07', 'neet-biology-human-health-disease', 'A key feature distinguishing cancer cells from normal cells is the loss of:', 'Contact inhibition', 'Cell membrane', 'Ribosomes', 'Mitochondria', 'A', 'Cancer cells lose contact inhibition, allowing uncontrolled division and tumour formation.', 6),
  ('neet-biology-human-health-disease-q08', 'neet-biology-human-health-disease', 'The injection of ready-made antibodies provides:', 'Active immunity', 'Passive immunity', 'Innate immunity', 'Lifelong immunity', 'B', 'Supplying ready-made antibodies gives passive immunity, which is immediate but short-lived.', 7),
  ('neet-chemistry-atomic-structure-q01', 'neet-chemistry-atomic-structure', 'The neutron was discovered by:', 'J. J. Thomson', 'Rutherford', 'Niels Bohr', 'James Chadwick', 'D', 'James Chadwick discovered the neutron, a neutral subatomic particle.', 0),
  ('neet-chemistry-atomic-structure-q02', 'neet-chemistry-atomic-structure', 'The principle that no two electrons in an atom can have all four quantum numbers identical is:', 'Hund''s rule', 'Pauli exclusion principle', 'Aufbau principle', 'Heisenberg principle', 'B', 'The Pauli exclusion principle forbids two electrons from sharing all four quantum numbers.', 1),
  ('neet-chemistry-atomic-structure-q03', 'neet-chemistry-atomic-structure', 'The energy of the nth Bohr orbit of the hydrogen atom is given by:', 'E = -13.6 n^2 eV', 'E = 13.6 n eV', 'E = -13.6 / n^2 eV', 'E = -13.6 / n eV', 'C', 'The energy of the nth hydrogen Bohr orbit is E = -13.6/n^2 eV.', 2),
  ('neet-chemistry-atomic-structure-q04', 'neet-chemistry-atomic-structure', 'Hund''s rule of maximum multiplicity states that orbitals of a subshell are:', 'Filled in pairs first', 'Filled randomly', 'Left empty', 'Filled singly before pairing', 'D', 'Hund''s rule says degenerate orbitals are singly occupied before any pairing of electrons.', 3),
  ('neet-chemistry-atomic-structure-q05', 'neet-chemistry-atomic-structure', 'The de Broglie relation for the wavelength of a moving particle is:', 'lambda = mv/h', 'lambda = h/mv', 'lambda = hmv', 'lambda = h/m', 'B', 'The de Broglie wavelength is lambda = h/mv, giving matter its wave nature.', 4),
  ('neet-chemistry-atomic-structure-q06', 'neet-chemistry-atomic-structure', 'The nuclear model of the atom was proposed after the gold-foil experiment by:', 'Rutherford', 'Thomson', 'Bohr', 'Chadwick', 'A', 'Rutherford proposed the nuclear model based on the alpha-particle scattering experiment.', 5),
  ('neet-chemistry-atomic-structure-q07', 'neet-chemistry-atomic-structure', 'The Aufbau principle states that electrons first occupy orbitals of:', 'Highest energy', 'Equal energy only', 'Lowest energy', 'The outermost shell', 'C', 'By the Aufbau principle, electrons fill the lowest-energy available orbitals first.', 6),
  ('neet-chemistry-atomic-structure-q08', 'neet-chemistry-atomic-structure', 'Heisenberg''s uncertainty principle places a limit on simultaneously knowing a particle''s:', 'Position and momentum', 'Charge and mass', 'Spin and charge', 'Energy and charge', 'A', 'Heisenberg''s principle limits simultaneous precise knowledge of position and momentum.', 7),
  ('neet-chemistry-chemical-bonding-molecular-structure-q01', 'neet-chemistry-chemical-bonding-molecular-structure', 'The shape of a methane (CH4) molecule is:', 'Tetrahedral', 'Trigonal planar', 'Linear', 'Bent', 'A', 'CH4 is tetrahedral with bond angles of 109.5 degrees due to sp3 hybridisation.', 0),
  ('neet-chemistry-chemical-bonding-molecular-structure-q02', 'neet-chemistry-chemical-bonding-molecular-structure', 'An ionic bond is typically formed between:', 'Two non-metals', 'Two metals', 'A metal and a non-metal', 'Two noble gases', 'C', 'Ionic bonds form by electron transfer, typically between a metal and a non-metal.', 1),
  ('neet-chemistry-chemical-bonding-molecular-structure-q03', 'neet-chemistry-chemical-bonding-molecular-structure', 'The paramagnetic behaviour of the O2 molecule is best explained by:', 'VSEPR theory', 'Molecular orbital theory', 'Valence bond theory', 'Octet rule', 'B', 'Molecular orbital theory predicts two unpaired electrons in O2, explaining its paramagnetism.', 2),
  ('neet-chemistry-chemical-bonding-molecular-structure-q04', 'neet-chemistry-chemical-bonding-molecular-structure', 'The hybridisation of the boron atom in BF3 is:', 'sp', 'sp2', 'sp3', 'sp3d', 'B', 'BF3 is trigonal planar with sp2 hybridisation of the central boron atom.', 3),
  ('neet-chemistry-chemical-bonding-molecular-structure-q05', 'neet-chemistry-chemical-bonding-molecular-structure', 'A pi bond is formed by which kind of orbital overlap?', 'Head-on (axial) overlap', 'No overlap', 'Sideways (lateral) overlap', 'sp3 overlap only', 'C', 'Pi bonds form by sideways overlap of p-orbitals; sigma bonds form by head-on overlap.', 4),
  ('neet-chemistry-chemical-bonding-molecular-structure-q06', 'neet-chemistry-chemical-bonding-molecular-structure', 'The unusually high boiling point of water is mainly due to:', 'Hydrogen bonding', 'Ionic bonding', 'Metallic bonding', 'Van der Waals forces only', 'A', 'Extensive hydrogen bonding among water molecules gives water its high boiling point.', 5),
  ('neet-chemistry-chemical-bonding-molecular-structure-q07', 'neet-chemistry-chemical-bonding-molecular-structure', 'The geometry of molecules is predicted from electron-pair repulsion by:', 'Band theory', 'Crystal field theory', 'VSEPR theory', 'Kinetic theory', 'C', 'VSEPR theory predicts molecular geometry from repulsion between electron pairs.', 6),
  ('neet-chemistry-chemical-bonding-molecular-structure-q08', 'neet-chemistry-chemical-bonding-molecular-structure', 'The bond order of a diatomic molecule is calculated as:', '(bonding - antibonding electrons)/2', '(bonding + antibonding electrons)/2', 'bonding electrons only', 'antibonding electrons / 2', 'A', 'Bond order equals (number of bonding minus antibonding electrons) divided by two.', 7),
  ('neet-chemistry-periodic-classification-q01', 'neet-chemistry-periodic-classification', 'The modern periodic law arranges elements by increasing:', 'Atomic mass', 'Valency', 'Density', 'Atomic number', 'D', 'Moseley''s modern periodic law arranges elements by increasing atomic number.', 0),
  ('neet-chemistry-periodic-classification-q02', 'neet-chemistry-periodic-classification', 'The most electronegative element in the periodic table is:', 'Oxygen', 'Chlorine', 'Fluorine', 'Nitrogen', 'C', 'Fluorine is the most electronegative element.', 1),
  ('neet-chemistry-periodic-classification-q03', 'neet-chemistry-periodic-classification', 'As we move across a period from left to right, the atomic radius generally:', 'Decreases', 'Increases', 'Remains constant', 'First increases then decreases', 'A', 'Atomic radius decreases across a period as effective nuclear charge increases.', 2),
  ('neet-chemistry-periodic-classification-q04', 'neet-chemistry-periodic-classification', 'Down a group in the periodic table, ionisation enthalpy generally:', 'Decreases', 'Increases', 'Stays the same', 'Becomes zero', 'A', 'Ionisation enthalpy decreases down a group as atomic size and shielding increase.', 3),
  ('neet-chemistry-periodic-classification-q05', 'neet-chemistry-periodic-classification', 'Transition elements belong to which block of the periodic table?', 'd-block', 'p-block', 's-block', 'f-block', 'A', 'Transition elements are d-block elements; lanthanoids and actinoids are f-block.', 4),
  ('neet-chemistry-periodic-classification-q06', 'neet-chemistry-periodic-classification', 'Mendeleev arranged the elements in his periodic table primarily according to:', 'Atomic number', 'Density', 'Electronegativity', 'Atomic mass', 'D', 'Mendeleev arranged elements by increasing atomic mass and even predicted unknown elements.', 5),
  ('neet-chemistry-periodic-classification-q07', 'neet-chemistry-periodic-classification', 'The diagonal relationship correctly pairs which two elements?', 'Li and Mg', 'Na and K', 'He and Ne', 'Cl and Br', 'A', 'The diagonal relationship links Li-Mg, Be-Al and B-Si due to similar properties.', 6),
  ('neet-chemistry-periodic-classification-q08', 'neet-chemistry-periodic-classification', 'Across a period, metallic character of elements generally:', 'Increases', 'Doubles', 'Is unchanged', 'Decreases', 'D', 'Metallic character decreases across a period and increases down a group.', 7),
  ('neet-chemistry-thermodynamics-q01', 'neet-chemistry-thermodynamics', 'The mathematical statement of the first law of thermodynamics is:', 'delta U = q + w', 'delta U = q - w only', 'delta G = delta H - T delta S', 'delta S = q/T', 'A', 'The first law states delta U = q + w, expressing conservation of energy.', 0),
  ('neet-chemistry-thermodynamics-q02', 'neet-chemistry-thermodynamics', 'A process is spontaneous when the Gibbs free energy change is:', 'Greater than zero', 'Equal to zero', 'Infinite', 'Less than zero', 'D', 'A negative delta G (less than zero) indicates a spontaneous process.', 1),
  ('neet-chemistry-thermodynamics-q03', 'neet-chemistry-thermodynamics', 'The statement that the total enthalpy change is independent of the path taken is:', 'Le Chatelier''s principle', 'Raoult''s law', 'Hess''s law', 'Henry''s law', 'C', 'Hess''s law states the total enthalpy change of a reaction is independent of the path.', 2),
  ('neet-chemistry-thermodynamics-q04', 'neet-chemistry-thermodynamics', 'For an isothermal process involving an ideal gas, the change in internal energy is:', 'Maximum', 'Zero', 'Negative always', 'Equal to the work done', 'B', 'For an ideal gas at constant temperature, internal energy change delta U is zero.', 3),
  ('neet-chemistry-thermodynamics-q05', 'neet-chemistry-thermodynamics', 'An exothermic reaction is characterised by an enthalpy change (delta H) that is:', 'Positive', 'Undefined', 'Zero', 'Negative', 'D', 'Exothermic reactions release heat, so delta H is negative.', 4),
  ('neet-chemistry-thermodynamics-q06', 'neet-chemistry-thermodynamics', 'Enthalpy (H) is correctly defined as:', 'H = U + PV', 'H = U - PV', 'H = U + TS', 'H = U - TS', 'A', 'Enthalpy is defined as H = U + PV.', 5),
  ('neet-chemistry-thermodynamics-q07', 'neet-chemistry-thermodynamics', 'According to the third law of thermodynamics, the entropy of a perfect crystal at 0 K is:', 'Maximum', 'Infinite', 'Zero', 'Negative', 'C', 'The third law states the entropy of a perfect crystal is zero at absolute zero (0 K).', 6),
  ('neet-chemistry-thermodynamics-q08', 'neet-chemistry-thermodynamics', 'Which of the following is a state function?', 'Work', 'Heat', 'Path length', 'Enthalpy', 'D', 'Enthalpy is a state function depending only on initial and final states, not the path.', 7),
  ('neet-chemistry-equilibrium-q01', 'neet-chemistry-equilibrium', 'At chemical equilibrium, the rates of the forward and reverse reactions are:', 'Equal', 'Both zero', 'Forward greater', 'Reverse greater', 'A', 'At equilibrium the forward and reverse reaction rates are equal, so concentrations stay constant.', 0),
  ('neet-chemistry-equilibrium-q02', 'neet-chemistry-equilibrium', 'The pH of pure water at 25 degrees Celsius is:', '0', '14', '7', '1', 'C', 'Pure water is neutral with a pH of 7 at 25 degrees Celsius.', 1),
  ('neet-chemistry-equilibrium-q03', 'neet-chemistry-equilibrium', 'According to Le Chatelier''s principle, increasing the temperature shifts equilibrium in the:', 'Exothermic direction', 'Direction of fewer moles', 'Endothermic direction', 'No change', 'C', 'Raising temperature shifts the equilibrium in the endothermic direction to absorb the heat.', 2),
  ('neet-chemistry-equilibrium-q04', 'neet-chemistry-equilibrium', 'According to the Arrhenius concept, a base is a substance that in water gives:', 'H+ ions', 'Electrons', 'OH- ions', 'Protons', 'C', 'An Arrhenius base produces hydroxide (OH-) ions in aqueous solution.', 3),
  ('neet-chemistry-equilibrium-q05', 'neet-chemistry-equilibrium', 'A Bronsted-Lowry acid is defined as a substance that:', 'Accepts a proton', 'Donates a proton', 'Donates an electron pair', 'Accepts an electron pair', 'B', 'A Bronsted-Lowry acid is a proton (H+) donor.', 4),
  ('neet-chemistry-equilibrium-q06', 'neet-chemistry-equilibrium', 'The ionic product of water, Kw, at 25 degrees Celsius is:', '1.0 x 10^-7', '1.0 x 10^-14', '1.0 x 10^7', '1.0 x 10^14', 'B', 'Kw = [H+][OH-] = 1.0 x 10^-14 at 25 degrees Celsius.', 5),
  ('neet-chemistry-equilibrium-q07', 'neet-chemistry-equilibrium', 'Suppression of the ionisation of a weak electrolyte by adding a common ion is the:', 'Buffer action', 'Solubility effect', 'Le Chatelier shift', 'Common ion effect', 'D', 'The common ion effect suppresses the ionisation of a weak electrolyte.', 6),
  ('neet-chemistry-equilibrium-q08', 'neet-chemistry-equilibrium', 'A solution of CH3COOH and CH3COONa is an example of a:', 'Strong acid', 'Buffer solution', 'Neutral salt', 'Strong base', 'B', 'A mixture of a weak acid and its salt forms a buffer that resists pH change.', 7),
  ('neet-chemistry-hydrocarbons-q01', 'neet-chemistry-hydrocarbons', 'The general molecular formula of saturated hydrocarbons (alkanes) is:', 'CnH2n', 'CnH(2n-2)', 'CnH(2n+2)', 'CnHn', 'C', 'Alkanes are saturated hydrocarbons with the general formula CnH(2n+2).', 0),
  ('neet-chemistry-hydrocarbons-q02', 'neet-chemistry-hydrocarbons', 'Markovnikov''s rule predicts that in the addition of HX to an alkene, hydrogen adds to the carbon:', 'With fewer hydrogens', 'Bearing the halogen', 'In the middle', 'With more hydrogens', 'D', 'By Markovnikov''s rule, H adds to the carbon already bearing more hydrogen atoms.', 1),
  ('neet-chemistry-hydrocarbons-q03', 'neet-chemistry-hydrocarbons', 'Benzene is aromatic because it obeys Huckel''s rule, having a number of pi electrons equal to:', '2n', '4n', 'n + 1', '4n + 2', 'D', 'Aromatic compounds obey Huckel''s rule with (4n + 2) pi electrons; benzene has six.', 2),
  ('neet-chemistry-hydrocarbons-q04', 'neet-chemistry-hydrocarbons', 'Alkanes characteristically undergo which type of reaction?', 'Addition', 'Polymerisation only', 'Elimination', 'Substitution', 'D', 'Saturated alkanes undergo free-radical substitution, such as halogenation.', 3),
  ('neet-chemistry-hydrocarbons-q05', 'neet-chemistry-hydrocarbons', 'Ethyne (acetylene) can be prepared in the laboratory from water and:', 'Calcium oxide', 'Sodium chloride', 'Calcium carbide', 'Calcium carbonate', 'C', 'Calcium carbide reacts with water to give ethyne (acetylene).', 4),
  ('neet-chemistry-hydrocarbons-q06', 'neet-chemistry-hydrocarbons', 'The anti-Markovnikov (peroxide) effect is observed in the addition of which reagent to alkenes?', 'HCl', 'H2O', 'HI', 'HBr', 'D', 'The peroxide (Kharasch) effect reverses addition only with HBr, not HCl or HI.', 5),
  ('neet-chemistry-hydrocarbons-q07', 'neet-chemistry-hydrocarbons', 'Complete combustion of a hydrocarbon yields:', 'CO and H2', 'CO2 and H2O', 'C and H2O', 'CO2 and H2', 'B', 'Complete combustion of hydrocarbons produces carbon dioxide and water.', 6),
  ('neet-chemistry-hydrocarbons-q08', 'neet-chemistry-hydrocarbons', 'Which class of hydrocarbon contains a carbon-carbon triple bond?', 'Alkane', 'Alkyne', 'Alkene', 'Cycloalkane', 'B', 'Alkynes contain a carbon-carbon triple bond, as in ethyne.', 7),
  ('neet-chemistry-haloalkanes-haloarenes-q01', 'neet-chemistry-haloalkanes-haloarenes', 'An SN2 reaction at a chiral carbon proceeds with:', 'Retention of configuration', 'Inversion of configuration', 'Racemisation', 'No stereochemical change', 'B', 'SN2 reactions occur with inversion of configuration (Walden inversion) at the chiral carbon.', 0),
  ('neet-chemistry-haloalkanes-haloarenes-q02', 'neet-chemistry-haloalkanes-haloarenes', 'The reactivity order of haloalkanes towards SN2 is:', '3 degree > 2 degree > 1 degree', '1 degree > 2 degree > 3 degree', '2 degree > 1 degree > 3 degree', 'All react equally', 'B', 'SN2 reactivity is 1 degree > 2 degree > 3 degree because of decreasing steric hindrance.', 1),
  ('neet-chemistry-haloalkanes-haloarenes-q03', 'neet-chemistry-haloalkanes-haloarenes', 'A Grignard reagent (R-Mg-X) is prepared by reacting a haloalkane with:', 'Magnesium', 'Sodium', 'Zinc', 'Copper', 'A', 'A Grignard reagent forms from a haloalkane and magnesium in dry ether.', 2),
  ('neet-chemistry-haloalkanes-haloarenes-q04', 'neet-chemistry-haloalkanes-haloarenes', 'Two molecules of a haloalkane reacting with sodium to form a higher alkane is the:', 'Aldol reaction', 'Cannizzaro reaction', 'Wurtz reaction', 'Friedel-Crafts reaction', 'C', 'The Wurtz reaction couples two haloalkanes using sodium to give a higher alkane.', 3),
  ('neet-chemistry-haloalkanes-haloarenes-q05', 'neet-chemistry-haloalkanes-haloarenes', 'On standing in air and light, chloroform forms the poisonous gas:', 'Methane', 'Phosgene', 'Carbon dioxide', 'Mustard gas', 'B', 'Chloroform is slowly oxidised in air and light to poisonous phosgene (carbonyl chloride).', 4),
  ('neet-chemistry-haloalkanes-haloarenes-q06', 'neet-chemistry-haloalkanes-haloarenes', 'Among the C-X bonds, which haloalkane is most reactive in substitution due to the weakest bond?', 'Fluoride', 'Chloride', 'Bromide', 'Iodide', 'D', 'The C-I bond is the weakest, so iodides react fastest in nucleophilic substitution.', 5),
  ('neet-chemistry-haloalkanes-haloarenes-q07', 'neet-chemistry-haloalkanes-haloarenes', 'An SN1 reaction proceeds through which intermediate?', 'Carbanion', 'Carbene', 'Free radical', 'Carbocation', 'D', 'SN1 is a two-step reaction proceeding through a carbocation intermediate.', 6),
  ('neet-chemistry-haloalkanes-haloarenes-q08', 'neet-chemistry-haloalkanes-haloarenes', 'Haloarenes are less reactive than haloalkanes towards nucleophilic substitution because:', 'The C-X bond has partial double-bond character due to resonance', 'They lack any C-X bond', 'They are ionic', 'They are saturated', 'A', 'Resonance gives the C-X bond in haloarenes partial double-bond character, lowering reactivity.', 7),
  ('neet-chemistry-alcohols-phenols-ethers-q01', 'neet-chemistry-alcohols-phenols-ethers', 'Phenol is more acidic than ethanol because its conjugate base (phenoxide) is:', 'Less stable', 'Resonance-stabilised', 'A free radical', 'Non-polar', 'B', 'The phenoxide ion is resonance-stabilised, making phenol more acidic than alcohols.', 0),
  ('neet-chemistry-alcohols-phenols-ethers-q02', 'neet-chemistry-alcohols-phenols-ethers', 'The Williamson synthesis is used to prepare:', 'Ethers', 'Alcohols', 'Aldehydes', 'Carboxylic acids', 'A', 'The Williamson synthesis prepares ethers from an alkyl halide and a sodium alkoxide.', 1),
  ('neet-chemistry-alcohols-phenols-ethers-q03', 'neet-chemistry-alcohols-phenols-ethers', 'The test used to distinguish primary, secondary and tertiary alcohols by reaction speed is the:', 'Tollens'' test', 'Iodoform test', 'Fehling''s test', 'Lucas test', 'D', 'The Lucas test distinguishes 1, 2 and 3 degree alcohols by the rate of turbidity formation.', 2),
  ('neet-chemistry-alcohols-phenols-ethers-q04', 'neet-chemistry-alcohols-phenols-ethers', 'On controlled oxidation, a primary alcohol is first converted to a(n):', 'Ketone', 'Ether', 'Aldehyde', 'Ester', 'C', 'Primary alcohols oxidise first to aldehydes and then to carboxylic acids.', 3),
  ('neet-chemistry-alcohols-phenols-ethers-q05', 'neet-chemistry-alcohols-phenols-ethers', 'Phenol, used as an antiseptic, is also commonly known as:', 'Formic acid', 'Carbolic acid', 'Acetic acid', 'Oxalic acid', 'B', 'Phenol is also called carbolic acid and was historically used as an antiseptic.', 4),
  ('neet-chemistry-alcohols-phenols-ethers-q06', 'neet-chemistry-alcohols-phenols-ethers', 'Dehydration of an alcohol typically yields a(n):', 'Ester', 'Alkane', 'Alkyne', 'Alkene', 'D', 'Acid-catalysed dehydration of an alcohol removes water to give an alkene.', 5),
  ('neet-chemistry-alcohols-phenols-ethers-q07', 'neet-chemistry-alcohols-phenols-ethers', 'The functional group present in an alcohol is:', '-CHO', '-COOH', '-OH on an sp3 carbon', '-O- between two carbons', 'C', 'Alcohols contain a hydroxyl (-OH) group attached to an sp3 (saturated) carbon.', 6),
  ('neet-chemistry-alcohols-phenols-ethers-q08', 'neet-chemistry-alcohols-phenols-ethers', 'Which of the following has the highest acidity?', 'Ethanol', 'Phenol', 'Water', 'Methanol', 'B', 'Among these, phenol is the most acidic because its phenoxide ion is resonance-stabilised.', 7),
  ('neet-chemistry-aldehydes-ketones-carboxylic-acids-q01', 'neet-chemistry-aldehydes-ketones-carboxylic-acids', 'The functional group common to aldehydes, ketones and carboxylic acids is the:', 'Carbonyl group', 'Hydroxyl group', 'Amino group', 'Nitro group', 'A', 'All three contain the carbonyl group (C=O) as their key functional feature.', 0),
  ('neet-chemistry-aldehydes-ketones-carboxylic-acids-q02', 'neet-chemistry-aldehydes-ketones-carboxylic-acids', 'Tollens'' test (silver mirror) gives a positive result with:', 'Ketones', 'Alkanes', 'Ethers', 'Aldehydes', 'D', 'Tollens'' reagent is reduced by aldehydes, giving a silver mirror; ketones do not react.', 1),
  ('neet-chemistry-aldehydes-ketones-carboxylic-acids-q03', 'neet-chemistry-aldehydes-ketones-carboxylic-acids', 'The Cannizzaro reaction occurs only in aldehydes that have:', 'No alpha-hydrogen', 'An alpha-hydrogen', 'A double bond', 'A hydroxyl group', 'A', 'The Cannizzaro reaction occurs with aldehydes lacking an alpha-hydrogen, like formaldehyde.', 2),
  ('neet-chemistry-aldehydes-ketones-carboxylic-acids-q04', 'neet-chemistry-aldehydes-ketones-carboxylic-acids', 'The only carboxylic acid that gives a positive Tollens'' test is:', 'Acetic acid', 'Benzoic acid', 'Formic acid', 'Oxalic acid', 'C', 'Formic acid has an aldehyde-like group and reduces Tollens'' reagent.', 3),
  ('neet-chemistry-aldehydes-ketones-carboxylic-acids-q05', 'neet-chemistry-aldehydes-ketones-carboxylic-acids', 'The carbonyl carbon in aldehydes and ketones is hybridised as:', 'sp2', 'sp', 'sp3', 'sp3d', 'A', 'The carbonyl carbon is sp2 hybridised and electrophilic, favouring nucleophilic addition.', 4),
  ('neet-chemistry-aldehydes-ketones-carboxylic-acids-q06', 'neet-chemistry-aldehydes-ketones-carboxylic-acids', 'The aldol condensation requires the reacting aldehyde or ketone to have:', 'An alpha-hydrogen', 'No alpha-hydrogen', 'A halogen', 'An aromatic ring', 'A', 'Aldol condensation needs at least one alpha-hydrogen on the carbonyl compound.', 5),
  ('neet-chemistry-aldehydes-ketones-carboxylic-acids-q07', 'neet-chemistry-aldehydes-ketones-carboxylic-acids', 'Compared with alcohols and phenols, carboxylic acids are:', 'Less acidic', 'Neutral', 'Equally acidic', 'More acidic', 'D', 'Carboxylic acids are more acidic owing to the resonance-stabilised carboxylate ion.', 6),
  ('neet-chemistry-aldehydes-ketones-carboxylic-acids-q08', 'neet-chemistry-aldehydes-ketones-carboxylic-acids', 'The characteristic reaction of the carbonyl group in aldehydes and ketones is:', 'Electrophilic substitution', 'Nucleophilic addition', 'Free-radical addition', 'Elimination', 'B', 'The polar carbonyl group undergoes nucleophilic addition reactions.', 7),
  ('neet-chemistry-biomolecules-chemistry-q01', 'neet-chemistry-biomolecules-chemistry', 'Glucose is chemically classified as a(n):', 'Aldohexose', 'Ketohexose', 'Aldopentose', 'Ketopentose', 'A', 'Glucose is an aldohexose (a six-carbon sugar with an aldehyde group).', 0),
  ('neet-chemistry-biomolecules-chemistry-q02', 'neet-chemistry-biomolecules-chemistry', 'Sucrose is a non-reducing sugar because it lacks a:', 'Glycosidic bond', 'Carbon atom', 'Free anomeric -OH group', 'Hydroxyl group entirely', 'C', 'Sucrose is non-reducing because both anomeric -OH groups are involved in the glycosidic bond.', 1),
  ('neet-chemistry-biomolecules-chemistry-q03', 'neet-chemistry-biomolecules-chemistry', 'The sugar present in DNA is:', 'Ribose', 'Fructose', 'Glucose', 'Deoxyribose', 'D', 'DNA contains the sugar deoxyribose, while RNA contains ribose.', 2),
  ('neet-chemistry-biomolecules-chemistry-q04', 'neet-chemistry-biomolecules-chemistry', 'Which group of vitamins is fat-soluble?', 'B and C', 'C only', 'A, D, E and K', 'B-complex only', 'C', 'Vitamins A, D, E and K are fat-soluble; the B-complex and C are water-soluble.', 3),
  ('neet-chemistry-biomolecules-chemistry-q05', 'neet-chemistry-biomolecules-chemistry', 'Amino acids in a protein are joined together by:', 'Glycosidic bonds', 'Ether bonds', 'Ester bonds', 'Peptide bonds', 'D', 'Alpha-amino acids are linked by peptide bonds (-CO-NH-) to form proteins.', 4),
  ('neet-chemistry-biomolecules-chemistry-q06', 'neet-chemistry-biomolecules-chemistry', 'The bonds joining monosaccharide units in a polysaccharide are:', 'Peptide bonds', 'Disulphide bonds', 'Phosphodiester bonds', 'Glycosidic bonds', 'D', 'Glycosidic bonds link monosaccharide units in disaccharides and polysaccharides.', 5),
  ('neet-chemistry-biomolecules-chemistry-q07', 'neet-chemistry-biomolecules-chemistry', 'Insulin, which regulates blood glucose, is chemically a:', 'Carbohydrate', 'Lipid', 'Protein hormone', 'Nucleic acid', 'C', 'Insulin is a protein (peptide) hormone that lowers and regulates blood glucose.', 6),
  ('neet-chemistry-biomolecules-chemistry-q08', 'neet-chemistry-biomolecules-chemistry', 'Heating or extreme pH disrupts the secondary and tertiary structure of a protein in a process called:', 'Denaturation', 'Hydrolysis', 'Condensation', 'Esterification', 'A', 'Denaturation disrupts the secondary and tertiary structure of proteins by heat or pH change.', 7),
  ('neet-chemistry-coordination-compounds-q01', 'neet-chemistry-coordination-compounds', 'In K4[Fe(CN)6], the oxidation state of iron is:', '+3', '0', '+2', '+6', 'C', 'In K4[Fe(CN)6] iron is in the +2 oxidation state with coordination number 6.', 0),
  ('neet-chemistry-coordination-compounds-q02', 'neet-chemistry-coordination-compounds', 'EDTA, widely used in complexometric titration, is a ligand that is:', 'Hexadentate', 'Bidentate', 'Monodentate', 'Unidentate', 'A', 'EDTA is a hexadentate ligand, donating through six donor atoms.', 1),
  ('neet-chemistry-coordination-compounds-q03', 'neet-chemistry-coordination-compounds', 'In Werner''s theory, the coordination number corresponds to the metal''s:', 'Primary valency', 'Secondary valency', 'Atomic number', 'Mass number', 'B', 'Secondary valency in Werner''s theory equals the coordination number of ligand donor atoms.', 2),
  ('neet-chemistry-coordination-compounds-q04', 'neet-chemistry-coordination-compounds', 'Ethylenediamine (en) is an example of a ligand that is:', 'Bidentate', 'Monodentate', 'Tridentate', 'Hexadentate', 'A', 'Ethylenediamine (en) is a bidentate ligand with two nitrogen donor atoms.', 3),
  ('neet-chemistry-coordination-compounds-q05', 'neet-chemistry-coordination-compounds', 'The colour of transition-metal complexes is mainly due to:', 's-s transitions', 'd-d transitions', 'Nuclear transitions', 'p-p transitions', 'B', 'd-d electronic transitions absorb visible light, giving transition-metal complexes colour.', 4),
  ('neet-chemistry-coordination-compounds-q06', 'neet-chemistry-coordination-compounds', 'The splitting of d-orbitals into t2g and eg sets in a complex is explained by:', 'Valence bond theory', 'Molecular orbital theory of diatomics', 'VSEPR theory', 'Crystal field theory', 'D', 'Crystal field theory explains the splitting of d-orbitals into t2g and eg levels.', 5),
  ('neet-chemistry-coordination-compounds-q07', 'neet-chemistry-coordination-compounds', 'A ring structure formed by a polydentate ligand bound to a metal is called a:', 'Salt', 'Isomer', 'Complex ion only', 'Chelate', 'D', 'A chelate is a ring formed by a polydentate ligand, which adds extra stability.', 6),
  ('neet-chemistry-coordination-compounds-q08', 'neet-chemistry-coordination-compounds', 'In the spectrochemical series, which ligand is a strong-field ligand?', 'I-', 'CO', 'Cl-', 'F-', 'B', 'CO is a strong-field ligand in the spectrochemical series, while I- is weak-field.', 7),
  ('neet-physics-kinematics-q01', 'neet-physics-kinematics', 'Which equation of motion relates final velocity, initial velocity, acceleration and displacement?', 'v^2 = u^2 + 2as', 's = ut + (1/2)at^2', 'v = u + at', 's = vt', 'A', 'The relation v^2 = u^2 + 2as connects velocities, acceleration and displacement (no time term).', 0),
  ('neet-physics-kinematics-q02', 'neet-physics-kinematics', 'The maximum range of a projectile (for a given speed) is achieved at a launch angle of:', '30 degrees', '60 degrees', '45 degrees', '90 degrees', 'C', 'For a given speed, the horizontal range of a projectile is maximum at a 45 degree launch angle.', 1),
  ('neet-physics-kinematics-q03', 'neet-physics-kinematics', 'The slope of a velocity-time graph represents the:', 'Displacement', 'Speed', 'Acceleration', 'Distance', 'C', 'The slope of a velocity-time graph gives the acceleration of the body.', 2),
  ('neet-physics-kinematics-q04', 'neet-physics-kinematics', 'At the highest point of a projectile''s path, its vertical velocity is:', 'Maximum', 'Equal to horizontal velocity', 'Zero', 'Infinite', 'C', 'At the highest point the vertical component of a projectile''s velocity is zero.', 3),
  ('neet-physics-kinematics-q05', 'neet-physics-kinematics', 'Which of the following is a vector quantity?', 'Speed', 'Displacement', 'Distance', 'Time', 'B', 'Displacement is a vector (has magnitude and direction); distance and speed are scalars.', 4),
  ('neet-physics-kinematics-q06', 'neet-physics-kinematics', 'The area under a velocity-time graph gives the:', 'Displacement', 'Acceleration', 'Force', 'Power', 'A', 'The area under a velocity-time graph equals the displacement of the body.', 5),
  ('neet-physics-kinematics-q07', 'neet-physics-kinematics', 'The equations of motion (v = u + at etc.) are valid only when the acceleration is:', 'Uniform (constant)', 'Variable', 'Zero', 'Negative', 'A', 'The standard equations of motion hold only for uniform (constant) acceleration.', 6),
  ('neet-physics-kinematics-q08', 'neet-physics-kinematics', 'The path followed by a projectile under gravity (ignoring air resistance) is:', 'A straight line', 'A parabola', 'A circle', 'An ellipse', 'B', 'A projectile follows a parabolic path because horizontal velocity is constant while vertical velocity changes.', 7),
  ('neet-physics-laws-of-motion-q01', 'neet-physics-laws-of-motion', 'Newton''s first law of motion is also known as the law of:', 'Inertia', 'Acceleration', 'Action-reaction', 'Gravitation', 'A', 'Newton''s first law defines inertia, the tendency of a body to resist a change in its state.', 0),
  ('neet-physics-laws-of-motion-q02', 'neet-physics-laws-of-motion', 'The SI unit of force is the:', 'Newton', 'Watt', 'Joule', 'Pascal', 'A', 'The newton (N), equal to kg m/s^2, is the SI unit of force.', 1),
  ('neet-physics-laws-of-motion-q03', 'neet-physics-laws-of-motion', 'Newton''s second law states that force equals the rate of change of:', 'Displacement', 'Acceleration', 'Energy', 'Momentum', 'D', 'Newton''s second law gives F = dp/dt, the rate of change of momentum (F = ma).', 2),
  ('neet-physics-laws-of-motion-q04', 'neet-physics-laws-of-motion', 'The centripetal force needed for circular motion is directed:', 'Inward (toward the centre)', 'Outward (away from centre)', 'Tangentially', 'Vertically up', 'A', 'Centripetal force is directed toward the centre of the circular path, with magnitude mv^2/r.', 3),
  ('neet-physics-laws-of-motion-q05', 'neet-physics-laws-of-motion', 'Impulse delivered to a body is equal to its change in:', 'Velocity', 'Momentum', 'Kinetic energy', 'Acceleration', 'B', 'Impulse (force multiplied by time) equals the change in momentum of the body.', 4),
  ('neet-physics-laws-of-motion-q06', 'neet-physics-laws-of-motion', 'The recoil of a gun when fired is best explained by the conservation of:', 'Energy', 'Momentum', 'Mass', 'Charge', 'B', 'The gun''s recoil follows from conservation of linear momentum (and Newton''s third law).', 5),
  ('neet-physics-laws-of-motion-q07', 'neet-physics-laws-of-motion', 'Which type of friction must be overcome to start a stationary body moving?', 'Kinetic friction', 'Limiting (maximum static) friction', 'Rolling friction', 'Fluid friction', 'B', 'A body starts moving only after the applied force exceeds the limiting static friction.', 6),
  ('neet-physics-laws-of-motion-q08', 'neet-physics-laws-of-motion', 'Newton''s third law of motion states that for every action there is:', 'No reaction', 'A smaller reaction', 'An equal and opposite reaction', 'A larger reaction', 'C', 'Newton''s third law states every action has an equal and opposite reaction.', 7),
  ('neet-physics-work-energy-power-q01', 'neet-physics-work-energy-power', 'The net work done on a body equals its change in:', 'Potential energy', 'Kinetic energy', 'Momentum', 'Temperature', 'B', 'By the work-energy theorem, net work done equals the change in kinetic energy.', 0),
  ('neet-physics-work-energy-power-q02', 'neet-physics-work-energy-power', 'Work done by a force acting perpendicular to the displacement is:', 'Maximum', 'Zero', 'Negative', 'Equal to the force', 'B', 'Since W = Fs cos(theta) and cos 90 degrees = 0, perpendicular force does zero work.', 1),
  ('neet-physics-work-energy-power-q03', 'neet-physics-work-energy-power', 'The kinetic energy of a body of mass m moving with speed v is:', 'mgh', 'Fs', 'mv', '(1/2)mv^2', 'D', 'Kinetic energy is KE = (1/2)mv^2.', 2),
  ('neet-physics-work-energy-power-q04', 'neet-physics-work-energy-power', 'A collision is called elastic when there is conservation of:', 'Both momentum and kinetic energy', 'Only kinetic energy', 'Only momentum', 'Neither', 'A', 'An elastic collision conserves both momentum and kinetic energy.', 3),
  ('neet-physics-work-energy-power-q05', 'neet-physics-work-energy-power', 'The SI unit of power is the:', 'Joule', 'Watt', 'Newton', 'Pascal', 'B', 'Power, the rate of doing work, is measured in watts (W = J/s).', 4),
  ('neet-physics-work-energy-power-q06', 'neet-physics-work-energy-power', 'One horsepower is approximately equal to:', '100 watts', '746 watts', '1000 watts', '550 watts', 'B', 'One horsepower equals about 746 watts.', 5),
  ('neet-physics-work-energy-power-q07', 'neet-physics-work-energy-power', 'In a conservative field such as gravity, the total mechanical energy of a body is:', 'Always increasing', 'Always decreasing', 'Zero', 'Constant', 'D', 'If only conservative forces act, the total mechanical energy (KE + PE) stays constant.', 6),
  ('neet-physics-work-energy-power-q08', 'neet-physics-work-energy-power', 'The gravitational potential energy of a body of mass m at height h is:', '(1/2)mv^2', 'mv', 'mgh', 'Fvt', 'C', 'Gravitational potential energy near the surface is PE = mgh.', 7),
  ('neet-physics-gravitation-q01', 'neet-physics-gravitation', 'The escape velocity from the surface of the Earth is approximately:', '7.9 km/s', '3.0 x 10^5 km/s', '9.8 km/s', '11.2 km/s', 'D', 'The escape velocity from Earth''s surface is about 11.2 km/s.', 0),
  ('neet-physics-gravitation-q02', 'neet-physics-gravitation', 'Kepler''s law of periods states that the square of the orbital period is proportional to the:', 'Radius', 'Square of the radius', 'Cube of the semi-major axis', 'Mass of the planet', 'C', 'Kepler''s third law states T^2 is proportional to a^3, the cube of the semi-major axis.', 1),
  ('neet-physics-gravitation-q03', 'neet-physics-gravitation', 'The value of g at a planet''s surface is given by:', 'g = GM/R', 'g = GMR', 'g = G/R^2', 'g = GM/R^2', 'D', 'Acceleration due to gravity at the surface is g = GM/R^2.', 2),
  ('neet-physics-gravitation-q04', 'neet-physics-gravitation', 'A geostationary satellite has an orbital period of:', '24 hours', '12 hours', '1 hour', '365 days', 'A', 'A geostationary satellite orbits with a period of 24 hours, matching Earth''s rotation.', 3),
  ('neet-physics-gravitation-q05', 'neet-physics-gravitation', 'The acceleration due to gravity g is maximum at the:', 'Poles', 'Equator', 'Centre of the Earth', 'Top of a mountain', 'A', 'g is maximum at the poles and decreases with altitude and depth.', 4),
  ('neet-physics-gravitation-q06', 'neet-physics-gravitation', 'The weightlessness felt by an astronaut in orbit is due to the state of:', 'Zero gravity in space', 'High speed only', 'Free fall', 'Absence of mass', 'C', 'Orbital weightlessness arises because the satellite and astronaut are in continuous free fall.', 5),
  ('neet-physics-gravitation-q07', 'neet-physics-gravitation', 'According to Kepler''s law of areas, a planet sweeps out:', 'Unequal areas in equal times', 'Equal areas in unequal times', 'Equal areas in equal times', 'No area at all', 'C', 'Kepler''s second law states a planet sweeps equal areas in equal time intervals.', 6),
  ('neet-physics-gravitation-q08', 'neet-physics-gravitation', 'Newton''s law of gravitation states that the force between two masses is:', 'Inversely proportional to the square of the distance', 'Directly proportional to the distance', 'Independent of distance', 'Inversely proportional to the distance', 'A', 'Gravitational force varies as 1/r^2, the inverse square of the separation between masses.', 7),
  ('neet-physics-thermodynamics-q01', 'neet-physics-thermodynamics', 'In an adiabatic process, the quantity that stays zero is:', 'Heat exchanged with surroundings', 'Change in internal energy', 'Work done', 'Pressure', 'A', 'An adiabatic process exchanges no heat with the surroundings (delta Q = 0).', 0),
  ('neet-physics-thermodynamics-q02', 'neet-physics-thermodynamics', 'The first law of thermodynamics is expressed as:', 'delta Q = delta U - delta W', 'delta Q = delta W - delta U', 'delta Q = delta U + delta W', 'delta U = 0', 'C', 'The first law states delta Q = delta U + delta W, conserving energy.', 1),
  ('neet-physics-thermodynamics-q03', 'neet-physics-thermodynamics', 'The most efficient engine operating between two given temperatures is the:', 'Petrol engine', 'Carnot engine', 'Diesel engine', 'Steam engine', 'B', 'The Carnot engine is the most efficient possible engine between two temperatures.', 2),
  ('neet-physics-thermodynamics-q04', 'neet-physics-thermodynamics', 'In an isochoric process (constant volume), the work done by the gas is:', 'Zero', 'Maximum', 'Equal to delta U', 'Negative', 'A', 'At constant volume no work is done (W = P delta V = 0) since delta V = 0.', 3),
  ('neet-physics-thermodynamics-q05', 'neet-physics-thermodynamics', 'For an ideal gas, Mayer''s relation states that:', 'Cp - Cv = R', 'Cp + Cv = R', 'Cp = Cv', 'Cv - Cp = R', 'A', 'Mayer''s relation for an ideal gas is Cp - Cv = R.', 4),
  ('neet-physics-thermodynamics-q06', 'neet-physics-thermodynamics', 'According to the second law, heat flows spontaneously from a body at:', 'High to low temperature', 'Low to high temperature', 'Equal temperatures only', 'Any direction', 'A', 'Heat flows spontaneously from a hotter body to a colder body (second law).', 5),
  ('neet-physics-thermodynamics-q07', 'neet-physics-thermodynamics', 'The efficiency of a Carnot engine working between hot (Th) and cold (Tc) reservoirs is:', '1 - Tc/Th', 'Tc/Th', 'Th/Tc', '1 + Tc/Th', 'A', 'Carnot efficiency is 1 - Tc/Th, with temperatures in kelvin.', 6),
  ('neet-physics-thermodynamics-q08', 'neet-physics-thermodynamics', 'In an isothermal process for an ideal gas, the change in internal energy is:', 'Maximum', 'Negative', 'Zero', 'Equal to the heat supplied', 'C', 'At constant temperature, an ideal gas has delta U = 0.', 7),
  ('neet-physics-oscillations-waves-q01', 'neet-physics-oscillations-waves', 'In simple harmonic motion, the restoring force is proportional to and directed:', 'Same as the displacement', 'Opposite to the displacement', 'Perpendicular to displacement', 'Independent of displacement', 'B', 'In SHM the restoring force is proportional to and directed opposite to the displacement.', 0),
  ('neet-physics-oscillations-waves-q02', 'neet-physics-oscillations-waves', 'Sound waves are an example of which type of wave?', 'Transverse', 'Standing only', 'Electromagnetic', 'Longitudinal', 'D', 'Sound is a longitudinal wave in which particles vibrate parallel to wave propagation.', 1),
  ('neet-physics-oscillations-waves-q03', 'neet-physics-oscillations-waves', 'The time period of a simple pendulum of length L is given by:', 'T = 2 pi sqrt(m/k)', 'T = 2 pi L g', 'T = 2 pi sqrt(g/L)', 'T = 2 pi sqrt(L/g)', 'D', 'The period of a simple pendulum is T = 2 pi sqrt(L/g).', 2),
  ('neet-physics-oscillations-waves-q04', 'neet-physics-oscillations-waves', 'Sound cannot travel through:', 'Air', 'A vacuum', 'Steel', 'Water', 'B', 'Sound needs a material medium and cannot propagate through a vacuum.', 3),
  ('neet-physics-oscillations-waves-q05', 'neet-physics-oscillations-waves', 'Two sound waves of slightly different frequencies superpose to produce:', 'Beats', 'Resonance', 'Echo', 'Reverberation', 'A', 'Beats arise from two waves of slightly different frequencies; beat frequency = |f1 - f2|.', 4),
  ('neet-physics-oscillations-waves-q06', 'neet-physics-oscillations-waves', 'The relation between wave speed, frequency and wavelength is:', 'v = f/lambda', 'v = f x lambda', 'v = lambda/f', 'v = f + lambda', 'B', 'Wave speed equals frequency multiplied by wavelength (v = f times lambda).', 5),
  ('neet-physics-oscillations-waves-q07', 'neet-physics-oscillations-waves', 'The apparent change in observed frequency due to relative motion of source and observer is the:', 'Bohr effect', 'Photoelectric effect', 'Doppler effect', 'Compton effect', 'C', 'The Doppler effect changes the observed frequency when source and observer move relative to each other.', 6),
  ('neet-physics-oscillations-waves-q08', 'neet-physics-oscillations-waves', 'Resonance occurs when the forcing frequency equals the system''s:', 'Beat frequency', 'Natural frequency', 'Half-frequency', 'Zero frequency', 'B', 'Resonance occurs when the driving frequency matches the natural frequency, giving large amplitude.', 7),
  ('neet-physics-electrostatics-q01', 'neet-physics-electrostatics', 'According to Coulomb''s law, the force between two point charges is inversely proportional to:', 'The distance', 'The square of the distance', 'The cube of the distance', 'The product of charges', 'B', 'Coulomb''s law states the force varies as 1/r^2, the inverse square of the separation.', 0),
  ('neet-physics-electrostatics-q02', 'neet-physics-electrostatics', 'The SI unit of capacitance is the:', 'Farad', 'Coulomb', 'Volt', 'Tesla', 'A', 'Capacitance (C = Q/V) is measured in farads (F).', 1),
  ('neet-physics-electrostatics-q03', 'neet-physics-electrostatics', 'The electric field inside a conductor in electrostatic equilibrium is:', 'Maximum', 'Infinite', 'Equal to the surface field', 'Zero', 'D', 'In electrostatic equilibrium the electric field inside a conductor is zero.', 2),
  ('neet-physics-electrostatics-q04', 'neet-physics-electrostatics', 'Inserting a dielectric between the plates of a capacitor causes its capacitance to:', 'Decrease', 'Become zero', 'Stay the same', 'Increase', 'D', 'A dielectric increases the capacitance of a capacitor.', 3),
  ('neet-physics-electrostatics-q05', 'neet-physics-electrostatics', 'Gauss''s law relates the electric flux through a closed surface to the:', 'Surface area', 'Volume', 'External field only', 'Enclosed charge', 'D', 'Gauss''s law states the total flux equals the enclosed charge divided by epsilon0.', 4),
  ('neet-physics-electrostatics-q06', 'neet-physics-electrostatics', 'The energy stored in a capacitor of capacitance C charged to voltage V is:', 'CV', '(1/2)CV^2', 'C/V', 'CV^2', 'B', 'The energy stored in a charged capacitor is U = (1/2)CV^2.', 5),
  ('neet-physics-electrostatics-q07', 'neet-physics-electrostatics', 'Electric field lines:', 'Cross each other', 'Start on negative and end on positive charges', 'Start on positive and end on negative charges', 'Form closed loops around charges', 'C', 'Electric field lines begin on positive charges and end on negative charges and never cross.', 6),
  ('neet-physics-electrostatics-q08', 'neet-physics-electrostatics', 'The SI unit of electric field intensity is:', 'Newton per coulomb', 'Volt-metre', 'Coulomb per metre', 'Joule per coulomb', 'A', 'Electric field intensity is force per unit charge, measured in N/C (or V/m).', 7),
  ('neet-physics-current-electricity-q01', 'neet-physics-current-electricity', 'Ohm''s law is correctly expressed as:', 'I = VR', 'V = IR', 'R = VI', 'V = I/R', 'B', 'Ohm''s law states V = IR for an ohmic conductor at constant temperature.', 0),
  ('neet-physics-current-electricity-q02', 'neet-physics-current-electricity', 'The equivalent resistance of resistors connected in series is:', 'Less than the smallest resistance', 'The sum of the individual resistances', 'Reciprocal of the sum', 'Always equal to one resistor', 'B', 'In series the equivalent resistance equals the sum R1 + R2 + ...', 1),
  ('neet-physics-current-electricity-q03', 'neet-physics-current-electricity', 'Kirchhoff''s junction rule is a direct consequence of the conservation of:', 'Energy', 'Mass', 'Momentum', 'Charge', 'D', 'The junction rule (current in equals current out) follows from conservation of charge.', 2),
  ('neet-physics-current-electricity-q04', 'neet-physics-current-electricity', 'The resistance of a wire is related to its length L and area A by:', 'R = rho L / A', 'R = rho A / L', 'R = L / (rho A)', 'R = rho L A', 'A', 'Resistance R = rho L / A, increasing with length and decreasing with cross-section.', 3),
  ('neet-physics-current-electricity-q05', 'neet-physics-current-electricity', 'Electrical power dissipated in a resistor can be written as:', 'P = V/I', 'P = I^2 R', 'P = IR^2', 'P = V/R', 'B', 'Power dissipated is P = VI = I^2 R = V^2/R.', 4),
  ('neet-physics-current-electricity-q06', 'neet-physics-current-electricity', 'Kirchhoff''s loop rule is based on the conservation of:', 'Charge', 'Mass', 'Energy', 'Momentum', 'C', 'The loop rule (sum of EMFs equals sum of IR drops) follows from energy conservation.', 5),
  ('neet-physics-current-electricity-q07', 'neet-physics-current-electricity', 'A Wheatstone bridge is said to be balanced when:', 'P = Q', 'P/Q = R/S', 'R = S', 'P x Q = R x S', 'B', 'A Wheatstone bridge is balanced when the ratio P/Q equals R/S, giving zero galvanometer current.', 6),
  ('neet-physics-current-electricity-q08', 'neet-physics-current-electricity', 'In a parallel combination of resistors, the quantity that is the same across each resistor is the:', 'Current', 'Power', 'Resistance', 'Voltage', 'D', 'In a parallel circuit the same voltage is applied across each resistor.', 7),
  ('neet-physics-moving-charges-magnetism-q01', 'neet-physics-moving-charges-magnetism', 'The magnetic force on a charged particle moving in a magnetic field is:', 'Parallel to the velocity', 'Along the field', 'Perpendicular to both velocity and field', 'Zero always', 'C', 'The magnetic (Lorentz) force F = q(v x B) is perpendicular to both velocity and field.', 0),
  ('neet-physics-moving-charges-magnetism-q02', 'neet-physics-moving-charges-magnetism', 'The SI unit of magnetic field strength is the:', 'Weber', 'Tesla', 'Henry', 'Gauss', 'B', 'The SI unit of magnetic field (flux density) is the tesla (T).', 1),
  ('neet-physics-moving-charges-magnetism-q03', 'neet-physics-moving-charges-magnetism', 'Two parallel wires carrying current in the same direction will:', 'Rotate', 'Repel each other', 'Exert no force', 'Attract each other', 'D', 'Parallel currents in the same direction attract each other.', 2),
  ('neet-physics-moving-charges-magnetism-q04', 'neet-physics-moving-charges-magnetism', 'A charged particle entering a uniform magnetic field perpendicular to its velocity follows a:', 'Straight line', 'Parabola', 'Circular path', 'Hyperbola', 'C', 'A charge moving perpendicular to a uniform field moves in a circle of radius r = mv/(qB).', 3),
  ('neet-physics-moving-charges-magnetism-q05', 'neet-physics-moving-charges-magnetism', 'A device that accelerates charged particles using a magnetic field is the:', 'Cyclotron', 'Transformer', 'Galvanometer', 'Voltmeter', 'A', 'A cyclotron uses a magnetic field and alternating voltage to accelerate charged particles.', 4),
  ('neet-physics-moving-charges-magnetism-q06', 'neet-physics-moving-charges-magnetism', 'The magnetic field inside a long solenoid carrying current is given by:', 'B = mu0 n I', 'B = mu0 I / (2 pi r)', 'B = mu0 I / (2R)', 'B = mu0 I R', 'A', 'The field inside a long solenoid is B = mu0 n I, where n is turns per unit length.', 5),
  ('neet-physics-moving-charges-magnetism-q07', 'neet-physics-moving-charges-magnetism', 'A charged particle moving parallel to a magnetic field experiences a force that is:', 'Maximum', 'Zero', 'Perpendicular to B', 'Along B', 'B', 'When velocity is parallel to B, sin(theta) = 0, so the magnetic force is zero.', 6),
  ('neet-physics-moving-charges-magnetism-q08', 'neet-physics-moving-charges-magnetism', 'A moving-coil galvanometer detects small currents by measuring the:', 'Heat produced', 'Charge stored', 'Voltage drop', 'Torque on a current-carrying coil', 'D', 'A galvanometer works on the torque experienced by a current-carrying coil in a magnetic field.', 7),
  ('neet-physics-electromagnetic-induction-ac-q01', 'neet-physics-electromagnetic-induction-ac', 'Faraday''s law states that the induced EMF is equal to the rate of change of:', 'Magnetic flux', 'Current', 'Resistance', 'Charge', 'A', 'Faraday''s law: the induced EMF equals the negative rate of change of magnetic flux.', 0),
  ('neet-physics-electromagnetic-induction-ac-q02', 'neet-physics-electromagnetic-induction-ac', 'Lenz''s law, which says the induced current opposes the change causing it, is a consequence of conservation of:', 'Charge', 'Mass', 'Momentum', 'Energy', 'D', 'Lenz''s law is a statement of energy conservation; the induced current opposes the flux change.', 1),
  ('neet-physics-electromagnetic-induction-ac-q03', 'neet-physics-electromagnetic-induction-ac', 'A transformer can change the voltage of:', 'Direct current only', 'Both AC and DC', 'Alternating current only', 'Neither', 'C', 'A transformer works only on alternating current, using mutual induction.', 2),
  ('neet-physics-electromagnetic-induction-ac-q04', 'neet-physics-electromagnetic-induction-ac', 'The RMS value of an alternating current of peak value I0 is:', 'I0', '2 I0', 'I0 x sqrt(2)', 'I0 / sqrt(2)', 'D', 'The RMS current equals the peak value divided by the square root of two, I0/sqrt(2).', 3),
  ('neet-physics-electromagnetic-induction-ac-q05', 'neet-physics-electromagnetic-induction-ac', 'At resonance in a series LCR circuit, the impedance is:', 'Maximum', 'Infinite', 'Zero', 'Minimum (equal to R)', 'D', 'At resonance XL = XC, so impedance is minimum and equal to the resistance R.', 4),
  ('neet-physics-electromagnetic-induction-ac-q06', 'neet-physics-electromagnetic-induction-ac', 'Inductive reactance XL of a coil in an AC circuit is given by:', '1/(2 pi f L)', '1/(2 pi f C)', '2 pi f C', '2 pi f L', 'D', 'Inductive reactance is XL = 2 pi f L, increasing with frequency.', 5),
  ('neet-physics-electromagnetic-induction-ac-q07', 'neet-physics-electromagnetic-induction-ac', 'For an ideal transformer, the relation between turns and voltages is:', 'Vs/Vp = Ns/Np', 'Vs/Vp = Np/Ns', 'Vs x Vp = Ns x Np', 'Vs = Vp', 'A', 'In an ideal transformer Vs/Vp = Ns/Np, relating secondary and primary turns to voltages.', 6),
  ('neet-physics-electromagnetic-induction-ac-q08', 'neet-physics-electromagnetic-induction-ac', 'The phenomenon by which a coil opposes changes in its own current is called:', 'Mutual induction', 'Hysteresis', 'Eddy currents', 'Self-induction', 'D', 'Self-induction is a coil opposing changes in its own current via an induced back-EMF.', 7),
  ('neet-physics-dual-nature-modern-physics-q01', 'neet-physics-dual-nature-modern-physics', 'In the photoelectric effect, the emission of electrons depends on the light''s:', 'Frequency', 'Intensity only', 'Colour temperature', 'Phase', 'A', 'Photoelectron emission depends on frequency; below the threshold frequency no electrons emit.', 0),
  ('neet-physics-dual-nature-modern-physics-q02', 'neet-physics-dual-nature-modern-physics', 'The minimum energy required to eject an electron from a metal surface is the:', 'Work function', 'Kinetic energy', 'Binding energy', 'Ionisation energy of gas', 'A', 'The work function is the minimum energy needed to free an electron from the metal surface.', 1),
  ('neet-physics-dual-nature-modern-physics-q03', 'neet-physics-dual-nature-modern-physics', 'The de Broglie wavelength of a particle of momentum p is:', 'lambda = h/p', 'lambda = p/h', 'lambda = hp', 'lambda = h + p', 'A', 'The de Broglie wavelength is lambda = h/p, linking a particle''s momentum to its wavelength.', 2),
  ('neet-physics-dual-nature-modern-physics-q04', 'neet-physics-dual-nature-modern-physics', 'One electronvolt (eV) is equal to:', '1.6 x 10^-19 joule', '1.6 x 10^19 joule', '9.1 x 10^-31 joule', '6.6 x 10^-34 joule', 'A', 'One electronvolt equals 1.6 x 10^-19 joule.', 3),
  ('neet-physics-dual-nature-modern-physics-q05', 'neet-physics-dual-nature-modern-physics', 'The joining of light nuclei to release energy, as in the Sun, is called:', 'Nuclear fission', 'Radioactivity', 'Nuclear fusion', 'Ionisation', 'C', 'Nuclear fusion joins light nuclei into heavier ones, releasing large amounts of energy.', 4),
  ('neet-physics-dual-nature-modern-physics-q06', 'neet-physics-dual-nature-modern-physics', 'The energy of a photon of frequency f is given by:', 'E = h/f', 'E = hf', 'E = f/h', 'E = h + f', 'B', 'A photon''s energy is E = hf, where h is Planck''s constant.', 5),
  ('neet-physics-dual-nature-modern-physics-q07', 'neet-physics-dual-nature-modern-physics', 'The rest mass of a photon is:', 'Zero', 'Equal to that of an electron', 'Infinite', 'Equal to that of a proton', 'A', 'A photon has zero rest mass yet carries momentum p = h/lambda.', 6),
  ('neet-physics-dual-nature-modern-physics-q08', 'neet-physics-dual-nature-modern-physics', 'The Bohr model of the atom introduced the idea of:', 'Quantised energy levels', 'Continuous energy levels', 'A solid nucleus only', 'Electron-free atoms', 'A', 'Bohr proposed quantised energy levels (stationary orbits) to explain atomic spectra.', 7),
  ('neet-physics-semiconductor-electronics-q01', 'neet-physics-semiconductor-electronics', 'In an n-type semiconductor the majority charge carriers are:', 'Holes', 'Protons', 'Electrons', 'Neutrons', 'C', 'n-type semiconductors are doped with pentavalent atoms, making electrons the majority carriers.', 0),
  ('neet-physics-semiconductor-electronics-q02', 'neet-physics-semiconductor-electronics', 'A p-n junction diode conducts current when it is:', 'Reverse biased', 'Forward biased', 'Unbiased', 'At absolute zero', 'B', 'A diode conducts in forward bias and blocks current in reverse bias.', 1),
  ('neet-physics-semiconductor-electronics-q03', 'neet-physics-semiconductor-electronics', 'A p-type semiconductor is produced by doping silicon with a:', 'Pentavalent impurity', 'Trivalent impurity', 'Tetravalent impurity', 'Noble gas', 'B', 'Doping with a trivalent impurity (like boron) creates holes, giving a p-type semiconductor.', 2),
  ('neet-physics-semiconductor-electronics-q04', 'neet-physics-semiconductor-electronics', 'A diode is most commonly used in a circuit as a:', 'Amplifier', 'Transformer', 'Oscillator', 'Rectifier', 'D', 'A diode acts as a rectifier, converting alternating current (AC) to direct current (DC).', 3),
  ('neet-physics-semiconductor-electronics-q05', 'neet-physics-semiconductor-electronics', 'As temperature increases, the resistance of a pure semiconductor:', 'Increases', 'Becomes infinite', 'Stays constant', 'Decreases', 'D', 'In a semiconductor, more carriers are generated with rising temperature, so resistance decreases.', 4),
  ('neet-physics-semiconductor-electronics-q06', 'neet-physics-semiconductor-electronics', 'The diode used for voltage regulation operating in reverse breakdown is the:', 'LED', 'Rectifier diode', 'Photodiode', 'Zener diode', 'D', 'A Zener diode operates in reverse breakdown and is used for voltage regulation.', 5),
  ('neet-physics-semiconductor-electronics-q07', 'neet-physics-semiconductor-electronics', 'The forbidden energy gap of silicon is approximately:', '0.1 eV', '1.1 eV', '5.5 eV', '11 eV', 'B', 'The forbidden energy gap of silicon is about 1.1 eV.', 6),
  ('neet-physics-semiconductor-electronics-q08', 'neet-physics-semiconductor-electronics', 'A transistor can be used to:', 'Store charge only', 'Generate magnetic fields', 'Amplify signals or act as a switch', 'Rectify only', 'C', 'A transistor can amplify signals or act as an electronic switch.', 7),
  ('ssc-cgl-quant-percentages-profit-loss-q01', 'ssc-cgl-quant-percentages-profit-loss', 'A price is increased by 20% and then decreased by 20%. The net change is:', '0%', '+4%', '−2%', '−4%', 'D', 'Net% = 20 − 20 − (400/100) = −4%, a net decrease.', 0),
  ('ssc-cgl-quant-percentages-profit-loss-q02', 'ssc-cgl-quant-percentages-profit-loss', 'An article bought for ₹400 is sold for ₹500. The profit percentage is:', '30%', '20%', '25%', '40%', 'C', 'Profit% = (100/400) × 100 = 25%.', 1),
  ('ssc-cgl-quant-percentages-profit-loss-q03', 'ssc-cgl-quant-percentages-profit-loss', 'What is 35% of 240?', '80', '84', '74', '96', 'B', '35% of 240 = 0.35 × 240 = 84.', 2),
  ('ssc-cgl-quant-percentages-profit-loss-q04', 'ssc-cgl-quant-percentages-profit-loss', 'Two items are sold at the same price, one at 10% profit and one at 10% loss. The overall result is:', 'No profit, no loss', '1% profit', '1% loss', '2% loss', 'C', 'Selling at equal SP with ±x% gives a loss of (x/10)² = (10/10)² = 1%.', 3),
  ('ssc-cgl-quant-percentages-profit-loss-q05', 'ssc-cgl-quant-percentages-profit-loss', 'A shopkeeper marks an item at ₹800 and gives a 15% discount. The selling price is:', '₹640', '₹700', '₹680', '₹720', 'C', 'SP = 800 × (85/100) = ₹680.', 4),
  ('ssc-cgl-quant-percentages-profit-loss-q06', 'ssc-cgl-quant-percentages-profit-loss', 'If 60 is what percent of 150?', '50%', '25%', '45%', '40%', 'D', '(60/150) × 100 = 40%.', 5),
  ('ssc-cgl-quant-percentages-profit-loss-q07', 'ssc-cgl-quant-percentages-profit-loss', 'By selling a pen for ₹54, a man loses 10%. The cost price was:', '₹58', '₹62', '₹60', '₹64', 'C', 'CP = 54 / 0.90 = ₹60.', 6),
  ('ssc-cgl-quant-percentages-profit-loss-q08', 'ssc-cgl-quant-percentages-profit-loss', 'A number increased by 25% becomes 250. The original number is:', '180', '210', '200', '225', 'C', 'Original = 250 / 1.25 = 200.', 7),
  ('ssc-cgl-quant-time-speed-distance-q01', 'ssc-cgl-quant-time-speed-distance', 'A car covers 180 km in 3 hours. Its speed is:', '50 km/h', '70 km/h', '60 km/h', '90 km/h', 'C', 'Speed = 180/3 = 60 km/h.', 0),
  ('ssc-cgl-quant-time-speed-distance-q02', 'ssc-cgl-quant-time-speed-distance', 'Convert 72 km/h into m/s:', '18 m/s', '20 m/s', '15 m/s', '25 m/s', 'B', '72 × 5/18 = 20 m/s.', 1),
  ('ssc-cgl-quant-time-speed-distance-q03', 'ssc-cgl-quant-time-speed-distance', 'A man covers equal distances at 30 km/h and 60 km/h. His average speed is:', '40 km/h', '45 km/h', '48 km/h', '50 km/h', 'A', 'Average = 2uv/(u+v) = 2(30)(60)/90 = 40 km/h.', 2),
  ('ssc-cgl-quant-time-speed-distance-q04', 'ssc-cgl-quant-time-speed-distance', 'Two trains move towards each other at 40 km/h and 50 km/h. Their relative speed is:', '100 km/h', '45 km/h', '10 km/h', '90 km/h', 'D', 'For opposite directions, relative speed is the sum: 40 + 50 = 90 km/h.', 3),
  ('ssc-cgl-quant-time-speed-distance-q05', 'ssc-cgl-quant-time-speed-distance', 'A 150 m long train running at 20 m/s crosses a pole in:', '5 s', '7.5 s', '10 s', '12 s', 'B', 'Time = length/speed = 150/20 = 7.5 s.', 4),
  ('ssc-cgl-quant-time-speed-distance-q06', 'ssc-cgl-quant-time-speed-distance', 'A boat goes 12 km/h downstream and 8 km/h upstream. The speed of the stream is:', '2 km/h', '4 km/h', '6 km/h', '10 km/h', 'A', 'Stream speed = (down − up)/2 = (12 − 8)/2 = 2 km/h.', 5),
  ('ssc-cgl-quant-time-speed-distance-q07', 'ssc-cgl-quant-time-speed-distance', 'If a journey of 240 km takes 4 hours, how long will 360 km take at the same speed?', '5 hours', '6 hours', '7 hours', '8 hours', 'B', 'Speed = 60 km/h, so 360/60 = 6 hours.', 6),
  ('ssc-cgl-quant-time-speed-distance-q08', 'ssc-cgl-quant-time-speed-distance', 'A 120 m train at 15 m/s crosses a 180 m platform in:', '15 s', '20 s', '24 s', '18 s', 'B', 'Time = (120 + 180)/15 = 300/15 = 20 s.', 7),
  ('ssc-cgl-reasoning-coding-decoding-series-q01', 'ssc-cgl-reasoning-coding-decoding-series', 'If CAT is coded as DBU, then DOG is coded as:', 'FPH', 'EPF', 'EPH', 'CPH', 'C', 'Each letter shifts forward by one: D→E, O→P, G→H.', 0),
  ('ssc-cgl-reasoning-coding-decoding-series-q02', 'ssc-cgl-reasoning-coding-decoding-series', 'Find the next term: 2, 6, 12, 20, 30, ?', '40', '42', '44', '36', 'B', 'Differences are 4, 6, 8, 10, then 12; 30 + 12 = 42.', 1),
  ('ssc-cgl-reasoning-coding-decoding-series-q03', 'ssc-cgl-reasoning-coding-decoding-series', 'What is the position of the letter T in the English alphabet?', '20', '19', '18', '21', 'A', 'Using EJOTY, T is the 20th letter.', 2),
  ('ssc-cgl-reasoning-coding-decoding-series-q04', 'ssc-cgl-reasoning-coding-decoding-series', 'Complete the series: 1, 1, 2, 3, 5, 8, ?', '11', '15', '12', '13', 'D', 'Fibonacci: each term is the sum of the two before it; 5 + 8 = 13.', 3),
  ('ssc-cgl-reasoning-coding-decoding-series-q05', 'ssc-cgl-reasoning-coding-decoding-series', 'In a code, A is written as Z, B as Y, C as X. How is D written?', 'W', 'V', 'X', 'U', 'A', 'Opposite coding: each letter maps to 27 − n, so D (4) → 23 → W.', 4),
  ('ssc-cgl-reasoning-coding-decoding-series-q06', 'ssc-cgl-reasoning-coding-decoding-series', 'Find the missing term: 3, 9, 27, 81, ?', '243', '210', '162', '324', 'A', 'Each term is multiplied by 3; 81 × 3 = 243.', 5),
  ('ssc-cgl-reasoning-coding-decoding-series-q07', 'ssc-cgl-reasoning-coding-decoding-series', 'If 5 is coded as 36 and 6 as 49, then 7 is coded as:', '56', '63', '64', '81', 'C', 'The code is (n + 1)²; (7 + 1)² = 64.', 6),
  ('ssc-cgl-reasoning-coding-decoding-series-q08', 'ssc-cgl-reasoning-coding-decoding-series', 'Find the odd one in the number series: 4, 9, 16, 25, 35, 49', '16', '25', '49', '35', 'D', 'All are perfect squares except 35 (36 would fit the pattern).', 7),
  ('ssc-cgl-english-idioms-one-word-q01', 'ssc-cgl-english-idioms-one-word', 'The idiom ''to let the cat out of the bag'' means:', 'To buy a pet', 'To reveal a secret', 'To run away', 'To take a risk', 'B', 'It means to disclose a secret, usually by accident.', 0),
  ('ssc-cgl-english-idioms-one-word-q02', 'ssc-cgl-english-idioms-one-word', 'One word for ''a person who studies birds'' is:', 'Botanist', 'Ornithologist', 'Zoologist', 'Entomologist', 'B', 'Ornithology is the study of birds, so the practitioner is an ornithologist.', 1),
  ('ssc-cgl-english-idioms-one-word-q03', 'ssc-cgl-english-idioms-one-word', 'The idiom ''a blessing in disguise'' means:', 'A hidden danger', 'A good thing that seemed bad at first', 'A bad omen', 'An obvious gift', 'B', 'It refers to something that turns out beneficial despite seeming unfortunate initially.', 2),
  ('ssc-cgl-english-idioms-one-word-q04', 'ssc-cgl-english-idioms-one-word', 'One word for ''words inscribed on a tomb'' is:', 'Epithet', 'Epitaph', 'Epilogue', 'Epigram', 'B', 'An epitaph is the inscription on a gravestone or tomb.', 3),
  ('ssc-cgl-english-idioms-one-word-q05', 'ssc-cgl-english-idioms-one-word', '''Once in a blue moon'' means an event that happens:', 'Very often', 'Every month', 'At night only', 'Very rarely', 'D', 'The idiom denotes something happening extremely rarely.', 4),
  ('ssc-cgl-english-idioms-one-word-q06', 'ssc-cgl-english-idioms-one-word', 'One word for ''a person who hates mankind'' is:', 'Misanthrope', 'Egotist', 'Misogynist', 'Philanthropist', 'A', 'A misanthrope dislikes or distrusts humankind; a philanthropist loves it.', 5),
  ('ssc-cgl-english-idioms-one-word-q07', 'ssc-cgl-english-idioms-one-word', 'To ''burn the midnight oil'' means to:', 'Waste resources', 'Sleep early', 'Start a fire', 'Work late into the night', 'D', 'The idiom describes studying or working late into the night.', 6),
  ('ssc-cgl-english-idioms-one-word-q08', 'ssc-cgl-english-idioms-one-word', 'One word for ''a person who walks on a tightrope'' is:', 'Funambulist', 'Equestrian', 'Somnambulist', 'Acrobat', 'A', 'A funambulist is a tightrope walker; a somnambulist is a sleepwalker.', 7),
  ('ssc-cgl-general-awareness-indian-polity-facts-q01', 'ssc-cgl-general-awareness-indian-polity-facts', 'The Indian Constitution came into force on:', '26 January 1950', '15 August 1947', '26 November 1949', '2 October 1950', 'A', 'Though adopted on 26 November 1949, it came into force on 26 January 1950.', 0),
  ('ssc-cgl-general-awareness-indian-polity-facts-q02', 'ssc-cgl-general-awareness-indian-polity-facts', 'Who was the Chairman of the Drafting Committee of the Constitution?', 'Jawaharlal Nehru', 'Rajendra Prasad', 'B.R. Ambedkar', 'Sardar Patel', 'C', 'Dr. B.R. Ambedkar chaired the Drafting Committee of the Constituent Assembly.', 1),
  ('ssc-cgl-general-awareness-indian-polity-facts-q03', 'ssc-cgl-general-awareness-indian-polity-facts', 'The Fundamental Duties were added to the Constitution by which amendment?', '42nd Amendment', '44th Amendment', '52nd Amendment', '73rd Amendment', 'A', 'The 42nd Amendment (1976) added the Fundamental Duties under Article 51A.', 2),
  ('ssc-cgl-general-awareness-indian-polity-facts-q04', 'ssc-cgl-general-awareness-indian-polity-facts', 'Which Article of the Constitution deals with the office of the President?', 'Article 63', 'Article 52', 'Article 75', 'Article 76', 'B', 'Article 52 establishes the office of the President of India.', 3),
  ('ssc-cgl-general-awareness-indian-polity-facts-q05', 'ssc-cgl-general-awareness-indian-polity-facts', 'The Eighth Schedule of the Constitution deals with:', 'Anti-defection', 'Panchayats', 'Union and State lists', 'Official languages', 'D', 'The Eighth Schedule lists the recognised official languages, now 22 in number.', 4),
  ('ssc-cgl-general-awareness-indian-polity-facts-q06', 'ssc-cgl-general-awareness-indian-polity-facts', 'The concept of Directive Principles of State Policy was borrowed from:', 'The USA', 'The UK', 'Ireland', 'Canada', 'C', 'India adopted the Directive Principles from the Irish Constitution.', 5),
  ('ssc-cgl-general-awareness-indian-polity-facts-q07', 'ssc-cgl-general-awareness-indian-polity-facts', 'The Finance Commission is constituted under which Article and at what interval?', 'Article 280, every 5 years', 'Article 324, every 6 years', 'Article 148, annually', 'Article 280, every 10 years', 'A', 'Article 280 provides for a Finance Commission constituted every five years.', 6),
  ('ssc-cgl-general-awareness-indian-polity-facts-q08', 'ssc-cgl-general-awareness-indian-polity-facts', 'The 42nd Amendment (1976) added which words to the Preamble?', 'Sovereign and Republic', 'Democratic and Justice', 'Liberty and Equality', 'Socialist, Secular and Integrity', 'D', 'The 42nd Amendment inserted ''Socialist'', ''Secular'' and ''Integrity'' into the Preamble.', 7),
  ('ssc-cgl-quant-ratio-proportion-q01', 'ssc-cgl-quant-ratio-proportion', 'Divide ₹600 in the ratio 2 : 3. The smaller share is:', '₹300', '₹360', '₹200', '₹240', 'D', 'Smaller share = 600 × 2/(2+3) = 600 × 2/5 = ₹240.', 0),
  ('ssc-cgl-quant-ratio-proportion-q02', 'ssc-cgl-quant-ratio-proportion', 'The mean proportional of 9 and 16 is:', '10', '12', '14', '15', 'B', 'Mean proportional = sqrt(9 × 16) = sqrt(144) = 12.', 1),
  ('ssc-cgl-quant-ratio-proportion-q03', 'ssc-cgl-quant-ratio-proportion', 'If a : b = 2 : 3 and b : c = 4 : 5, then a : c is:', '8 : 15', '2 : 5', '3 : 5', '8 : 5', 'A', 'a : b : c = 8 : 12 : 15, so a : c = 8 : 15.', 2),
  ('ssc-cgl-quant-ratio-proportion-q04', 'ssc-cgl-quant-ratio-proportion', 'In a proportion a : b :: c : d, if a = 4, b = 6 and c = 10, then d is:', '12', '14', '16', '15', 'D', 'a×d = b×c gives 4d = 60, so d = 15.', 3),
  ('ssc-cgl-quant-ratio-proportion-q05', 'ssc-cgl-quant-ratio-proportion', 'Two numbers are in the ratio 5 : 7 and their sum is 96. The larger number is:', '40', '60', '56', '48', 'C', 'Larger = 96 × 7/12 = 56.', 4),
  ('ssc-cgl-quant-ratio-proportion-q06', 'ssc-cgl-quant-ratio-proportion', 'The ratio 18 : 24 in its simplest form is:', '2 : 3', '4 : 5', '3 : 4', '6 : 8', 'C', 'Dividing both by HCF 6 gives 3 : 4.', 5),
  ('ssc-cgl-quant-ratio-proportion-q07', 'ssc-cgl-quant-ratio-proportion', 'If 40% of A equals 60% of B, then A : B is:', '2 : 3', '3 : 2', '4 : 6', '5 : 3', 'B', '0.4A = 0.6B gives A/B = 0.6/0.4 = 3/2, so A : B = 3 : 2.', 6),
  ('ssc-cgl-quant-ratio-proportion-q08', 'ssc-cgl-quant-ratio-proportion', 'A sum is split among P, Q, R in the ratio 1 : 2 : 3. If R gets ₹90, the total sum is:', '₹150', '₹160', '₹120', '₹180', 'D', 'R has 3 parts = ₹90, so 1 part = ₹30 and total 6 parts = ₹180.', 7),
  ('ssc-cgl-quant-averages-q01', 'ssc-cgl-quant-averages', 'The average of 10, 20, 30, 40 and 50 is:', '25', '30', '35', '40', 'B', 'Sum = 150, count = 5, average = 150/5 = 30.', 0),
  ('ssc-cgl-quant-averages-q02', 'ssc-cgl-quant-averages', 'The average of the first 10 natural numbers is:', '5', '5.5', '6', '4.5', 'B', 'Average of first n naturals = (n+1)/2 = 11/2 = 5.5.', 1),
  ('ssc-cgl-quant-averages-q03', 'ssc-cgl-quant-averages', 'The average age of 5 boys is 14 years. The total of their ages is:', '70', '65', '60', '75', 'A', 'Total = average × number = 14 × 5 = 70.', 2),
  ('ssc-cgl-quant-averages-q04', 'ssc-cgl-quant-averages', 'The average of 6 numbers is 25. If one number 30 is removed, the average of the rest is:', '22', '23', '24', '26', 'C', 'Sum = 150, remove 30 gives 120 over 5 numbers = 24.', 3),
  ('ssc-cgl-quant-averages-q05', 'ssc-cgl-quant-averages', 'The average of first n odd natural numbers is:', 'n + 1', '2n', '(n+1)/2', 'n', 'D', 'The average of the first n odd numbers is exactly n.', 4),
  ('ssc-cgl-quant-averages-q06', 'ssc-cgl-quant-averages', 'A batsman''s average in 10 innings is 40. To raise it to 42 in the 11th innings, he must score:', '62', '60', '64', '66', 'A', 'New total needed = 42 × 11 = 462; old total = 400; required = 462 − 400 = 62.', 5),
  ('ssc-cgl-quant-averages-q07', 'ssc-cgl-quant-averages', 'The average of three consecutive even numbers is 16. The largest of them is:', '14', '16', '20', '18', 'D', 'Middle number = average = 16, so the numbers are 14, 16, 18; largest is 18.', 6),
  ('ssc-cgl-quant-averages-q08', 'ssc-cgl-quant-averages', 'Two groups of 4 and 6 students score average 70 and 80. The combined average is:', '74', '75', '76', '78', 'C', 'Weighted avg = (4×70 + 6×80)/10 = (280+480)/10 = 760/10 = 76.', 7),
  ('ssc-cgl-quant-simple-compound-interest-q01', 'ssc-cgl-quant-simple-compound-interest', 'The simple interest on ₹1000 at 5% per annum for 3 years is:', '₹150', '₹120', '₹180', '₹200', 'A', 'SI = (1000 × 5 × 3)/100 = ₹150.', 0),
  ('ssc-cgl-quant-simple-compound-interest-q02', 'ssc-cgl-quant-simple-compound-interest', 'The compound interest on ₹2000 at 10% per annum for 2 years is:', '₹420', '₹400', '₹440', '₹460', 'A', 'CI = 2000×(1.1)^2 − 2000 = 2420 − 2000 = ₹420.', 1),
  ('ssc-cgl-quant-simple-compound-interest-q03', 'ssc-cgl-quant-simple-compound-interest', 'The difference between CI and SI on ₹1000 at 10% for 2 years is:', '₹5', '₹8', '₹12', '₹10', 'D', 'Difference = P×(R/100)^2 = 1000×(0.1)^2 = ₹10.', 2),
  ('ssc-cgl-quant-simple-compound-interest-q04', 'ssc-cgl-quant-simple-compound-interest', 'At what rate will SI on a sum double the principal in 20 years?', '5%', '4%', '6%', '10%', 'A', 'Money doubles under SI when R×T = 100, so R = 100/20 = 5%.', 3),
  ('ssc-cgl-quant-simple-compound-interest-q05', 'ssc-cgl-quant-simple-compound-interest', 'The amount on ₹500 at simple interest of 8% for 2 years is:', '₹560', '₹580', '₹600', '₹620', 'B', 'SI = (500×8×2)/100 = ₹80; amount = 500 + 80 = ₹580.', 4),
  ('ssc-cgl-quant-simple-compound-interest-q06', 'ssc-cgl-quant-simple-compound-interest', 'A sum gives ₹60 simple interest in 2 years at 5% per annum. The principal is:', '₹500', '₹550', '₹650', '₹600', 'D', 'P = (SI×100)/(R×T) = (60×100)/(5×2) = ₹600.', 5),
  ('ssc-cgl-quant-simple-compound-interest-q07', 'ssc-cgl-quant-simple-compound-interest', 'The amount on ₹8000 at 5% compound interest for 1 year is:', '₹8200', '₹8300', '₹8400', '₹8500', 'C', 'Amount = 8000 × 1.05 = ₹8400 (for 1 year CI equals SI).', 6),
  ('ssc-cgl-quant-simple-compound-interest-q08', 'ssc-cgl-quant-simple-compound-interest', 'Simple interest on a sum for 8 months at 6% per annum equals ₹40. The principal is:', '₹800', '₹900', '₹1000', '₹1200', 'C', 'T = 8/12 yr; P = (40×100)/(6×8/12) = 4000/4 = ₹1000.', 7),
  ('ssc-cgl-quant-time-and-work-q01', 'ssc-cgl-quant-time-and-work', 'A does a job in 10 days and B in 15 days. Together they finish it in:', '5 days', '8 days', '7 days', '6 days', 'D', 'Together = ab/(a+b) = (10×15)/25 = 150/25 = 6 days.', 0),
  ('ssc-cgl-quant-time-and-work-q02', 'ssc-cgl-quant-time-and-work', 'If A can do a work in 12 days, his one day''s work is:', '1/10', '1/24', '1/6', '1/12', 'D', 'One day''s work = 1/(time to finish) = 1/12.', 1),
  ('ssc-cgl-quant-time-and-work-q03', 'ssc-cgl-quant-time-and-work', 'A and B together finish a job in 8 days; A alone takes 12 days. B alone takes:', '24 days', '20 days', '16 days', '18 days', 'A', 'B''s rate = 1/8 − 1/12 = 3/24 − 2/24 = 1/24, so B takes 24 days.', 2),
  ('ssc-cgl-quant-time-and-work-q04', 'ssc-cgl-quant-time-and-work', '12 men finish a work in 10 days. In how many days will 8 men finish the same work?', '12 days', '14 days', '15 days', '16 days', 'C', 'Men×days constant: 12×10 = 8×d, so d = 120/8 = 15 days.', 3),
  ('ssc-cgl-quant-time-and-work-q05', 'ssc-cgl-quant-time-and-work', 'A is twice as efficient as B. If B does a job in 18 days, A does it in:', '9 days', '6 days', '12 days', '36 days', 'A', 'Twice the efficiency means half the time: 18/2 = 9 days.', 4),
  ('ssc-cgl-quant-time-and-work-q06', 'ssc-cgl-quant-time-and-work', 'A pipe fills a tank in 6 hours and an outlet empties it in 12 hours. Together they fill it in:', '12 hours', '10 hours', '8 hours', '18 hours', 'A', 'Net rate = 1/6 − 1/12 = 1/12, so the tank fills in 12 hours.', 5),
  ('ssc-cgl-quant-time-and-work-q07', 'ssc-cgl-quant-time-and-work', 'A and B do a job in 20 and 30 days. Working together, the fraction done in 6 days is:', '1/3', '2/5', '1/2', '3/5', 'C', 'Combined rate = 1/20 + 1/30 = 5/60 = 1/12; in 6 days = 6/12 = 1/2.', 6),
  ('ssc-cgl-quant-time-and-work-q08', 'ssc-cgl-quant-time-and-work', 'If 4 workers build a wall in 9 days, how many workers build it in 6 days?', '5', '7', '6', '8', 'C', 'Workers×days constant: 4×9 = w×6, so w = 36/6 = 6 workers.', 7),
  ('ssc-cgl-quant-number-system-q01', 'ssc-cgl-quant-number-system', 'The HCF of 12 and 18 is:', '2', '3', '9', '6', 'D', 'Common factors of 12 and 18 give the greatest as 6.', 0),
  ('ssc-cgl-quant-number-system-q02', 'ssc-cgl-quant-number-system', 'The LCM of 4, 6 and 8 is:', '12', '24', '16', '48', 'B', 'Smallest number divisible by 4, 6 and 8 is 24.', 1),
  ('ssc-cgl-quant-number-system-q03', 'ssc-cgl-quant-number-system', 'If the HCF of two numbers is 6 and their LCM is 36, and one number is 12, the other is:', '24', '20', '18', '30', 'C', 'Product = HCF×LCM = 216; other = 216/12 = 18.', 2),
  ('ssc-cgl-quant-number-system-q04', 'ssc-cgl-quant-number-system', 'Which of these numbers is divisible by 9?', '1234', '2345', '4321', '5346', 'D', 'Digit sum of 5346 = 5+3+4+6 = 18, divisible by 9.', 3),
  ('ssc-cgl-quant-number-system-q05', 'ssc-cgl-quant-number-system', 'The least number which when divided by 5, 6 and 7 leaves remainder 2 in each case is:', '210', '208', '212', '216', 'C', 'LCM(5,6,7) = 210; required = 210 + 2 = 212.', 4),
  ('ssc-cgl-quant-number-system-q06', 'ssc-cgl-quant-number-system', 'Which of the following is a prime number?', '21', '27', '29', '33', 'C', '29 has exactly two factors, 1 and itself, so it is prime.', 5),
  ('ssc-cgl-quant-number-system-q07', 'ssc-cgl-quant-number-system', 'Is 3927 divisible by 11?', 'No, remainder 1', 'Yes, it is divisible', 'No, remainder 3', 'No, remainder 5', 'B', 'Alternating sum (7−2+9−3)=11 is divisible by 11, so 3927 is divisible.', 6),
  ('ssc-cgl-quant-number-system-q08', 'ssc-cgl-quant-number-system', 'The HCF of the fractions 2/3 and 4/9 is:', '2/9', '2/3', '4/3', '1/9', 'A', 'HCF of fractions = HCF(2,4)/LCM(3,9) = 2/9.', 7),
  ('ssc-cgl-quant-mensuration-q01', 'ssc-cgl-quant-mensuration', 'The area of a square with side 7 cm is:', '28 cm^2', '49 cm^2', '14 cm^2', '56 cm^2', 'B', 'Area = side^2 = 7^2 = 49 cm^2.', 0),
  ('ssc-cgl-quant-mensuration-q02', 'ssc-cgl-quant-mensuration', 'The perimeter of a rectangle 8 cm by 5 cm is:', '13 cm', '20 cm', '40 cm', '26 cm', 'D', 'Perimeter = 2(l+b) = 2(8+5) = 26 cm.', 1),
  ('ssc-cgl-quant-mensuration-q03', 'ssc-cgl-quant-mensuration', 'The area of a circle with radius 7 cm (pi = 22/7) is:', '144 cm^2', '174 cm^2', '164 cm^2', '154 cm^2', 'D', 'Area = pi×r^2 = (22/7)×49 = 154 cm^2.', 2),
  ('ssc-cgl-quant-mensuration-q04', 'ssc-cgl-quant-mensuration', 'The volume of a cube of edge 5 cm is:', '25 cm^3', '75 cm^3', '150 cm^3', '125 cm^3', 'D', 'Volume = a^3 = 5^3 = 125 cm^3.', 3),
  ('ssc-cgl-quant-mensuration-q05', 'ssc-cgl-quant-mensuration', 'The total surface area of a cube of edge 4 cm is:', '64 cm^2', '80 cm^2', '112 cm^2', '96 cm^2', 'D', 'TSA = 6×a^2 = 6×16 = 96 cm^2.', 4),
  ('ssc-cgl-quant-mensuration-q06', 'ssc-cgl-quant-mensuration', 'The area of a triangle with base 10 cm and height 6 cm is:', '60 cm^2', '16 cm^2', '30 cm^2', '40 cm^2', 'C', 'Area = (1/2)×base×height = (1/2)×10×6 = 30 cm^2.', 5),
  ('ssc-cgl-quant-mensuration-q07', 'ssc-cgl-quant-mensuration', 'The diagonal of a square of side 5 cm is:', '5 cm', '10 cm', '5sqrt(2) cm', '25 cm', 'C', 'Diagonal = side × sqrt(2) = 5sqrt(2) cm.', 6),
  ('ssc-cgl-quant-mensuration-q08', 'ssc-cgl-quant-mensuration', 'If each edge of a cube doubles, its volume becomes:', '8 times', '4 times', '6 times', '2 times', 'A', 'Volume scales by k^3; doubling gives 2^3 = 8 times.', 7),
  ('ssc-cgl-quant-algebra-basics-q01', 'ssc-cgl-quant-algebra-basics', 'Expand (a + b)^2:', 'a^2 + b^2', 'a^2 - 2ab + b^2', 'a^2 + 2ab + b^2', '2a + 2b', 'C', '(a + b)^2 = a^2 + 2ab + b^2.', 0),
  ('ssc-cgl-quant-algebra-basics-q02', 'ssc-cgl-quant-algebra-basics', 'Factorise a^2 - b^2:', '(a - b)^2', '(a + b)^2', '(a + b)(a - b)', 'a^2 + b^2', 'C', 'a^2 - b^2 = (a + b)(a - b).', 1),
  ('ssc-cgl-quant-algebra-basics-q03', 'ssc-cgl-quant-algebra-basics', 'If a + 1/a = 3, then a^2 + 1/a^2 equals:', '7', '5', '9', '11', 'A', 'a^2 + 1/a^2 = (a + 1/a)^2 − 2 = 9 − 2 = 7.', 2),
  ('ssc-cgl-quant-algebra-basics-q04', 'ssc-cgl-quant-algebra-basics', 'If a + b + c = 0, then a^3 + b^3 + c^3 equals:', '0', 'abc', 'a^3b^3c^3', '3abc', 'D', 'When a + b + c = 0, a^3 + b^3 + c^3 = 3abc.', 3),
  ('ssc-cgl-quant-algebra-basics-q05', 'ssc-cgl-quant-algebra-basics', 'For the equation 2x^2 - 5x + 3 = 0, the sum of the roots is:', '-5/2', '3/2', '5/2', '2/5', 'C', 'Sum of roots = -b/a = -(-5)/2 = 5/2.', 4),
  ('ssc-cgl-quant-algebra-basics-q06', 'ssc-cgl-quant-algebra-basics', 'The value of 102^2 - 98^2 is:', '400', '600', '1000', '800', 'D', 'a^2 - b^2 = (102+98)(102-98) = 200×4 = 800.', 5),
  ('ssc-cgl-quant-algebra-basics-q07', 'ssc-cgl-quant-algebra-basics', 'For 3x^2 + 6x + 2 = 0, the product of the roots is:', '2', '6', '-2', '2/3', 'D', 'Product of roots = c/a = 2/3.', 6),
  ('ssc-cgl-quant-algebra-basics-q08', 'ssc-cgl-quant-algebra-basics', 'If a - 1/a = 2, then a^2 + 1/a^2 equals:', '4', '5', '6', '8', 'C', 'a^2 + 1/a^2 = (a - 1/a)^2 + 2 = 4 + 2 = 6.', 7),
  ('ssc-cgl-quant-trigonometry-q01', 'ssc-cgl-quant-trigonometry', 'The value of sin 30 degrees is:', '0', 'sqrt(3)/2', '1', '1/2', 'D', 'sin 30 degrees = 1/2 from the standard table.', 0),
  ('ssc-cgl-quant-trigonometry-q02', 'ssc-cgl-quant-trigonometry', 'The value of sin^2(x) + cos^2(x) is:', '0', 'depends on x', '2', '1', 'D', 'The Pythagorean identity gives sin^2(x) + cos^2(x) = 1 for all x.', 1),
  ('ssc-cgl-quant-trigonometry-q03', 'ssc-cgl-quant-trigonometry', 'The value of tan 45 degrees is:', '0', '1/sqrt(3)', 'sqrt(3)', '1', 'D', 'tan 45 degrees = 1 from the standard angles.', 2),
  ('ssc-cgl-quant-trigonometry-q04', 'ssc-cgl-quant-trigonometry', 'sin(90 degrees - x) is equal to:', 'cos x', 'sin x', 'tan x', 'cosec x', 'A', 'By complementary angles, sin(90 − x) = cos x.', 3),
  ('ssc-cgl-quant-trigonometry-q05', 'ssc-cgl-quant-trigonometry', 'The value of cos 60 degrees is:', '1/2', 'sqrt(3)/2', '1', '0', 'A', 'cos 60 degrees = 1/2 from the standard table.', 4),
  ('ssc-cgl-quant-trigonometry-q06', 'ssc-cgl-quant-trigonometry', '1 + tan^2(x) equals:', 'cosec^2(x)', 'sec^2(x)', 'cot^2(x)', 'sin^2(x)', 'B', 'The identity states 1 + tan^2(x) = sec^2(x).', 5),
  ('ssc-cgl-quant-trigonometry-q07', 'ssc-cgl-quant-trigonometry', 'A tower casts a shadow equal to its height. The angle of elevation of the sun is:', '45 degrees', '30 degrees', '60 degrees', '90 degrees', 'A', 'tan(angle) = height/shadow = 1, so the angle is 45 degrees.', 6),
  ('ssc-cgl-quant-trigonometry-q08', 'ssc-cgl-quant-trigonometry', 'The value of sin 0 degrees + cos 0 degrees is:', '0', '2', '1', '1/2', 'C', 'sin 0 = 0 and cos 0 = 1, so the sum is 1.', 7),
  ('ssc-cgl-quant-geometry-q01', 'ssc-cgl-quant-geometry', 'The sum of the interior angles of a triangle is:', '180 degrees', '90 degrees', '270 degrees', '360 degrees', 'A', 'The angle sum of any triangle is 180 degrees.', 0),
  ('ssc-cgl-quant-geometry-q02', 'ssc-cgl-quant-geometry', 'In a right triangle with legs 6 and 8, the hypotenuse is:', '9', '10', '12', '14', 'B', 'Hypotenuse = sqrt(6^2 + 8^2) = sqrt(100) = 10.', 1),
  ('ssc-cgl-quant-geometry-q03', 'ssc-cgl-quant-geometry', 'The angle in a semicircle is:', '45 degrees', '90 degrees', '60 degrees', '120 degrees', 'B', 'The angle subtended in a semicircle is a right angle, 90 degrees.', 2),
  ('ssc-cgl-quant-geometry-q04', 'ssc-cgl-quant-geometry', 'The sum of interior angles of a hexagon is:', '540 degrees', '720 degrees', '900 degrees', '1080 degrees', 'B', 'Sum = (n−2)×180 = (6−2)×180 = 720 degrees.', 3),
  ('ssc-cgl-quant-geometry-q05', 'ssc-cgl-quant-geometry', 'Each exterior angle of a regular pentagon is:', '60 degrees', '90 degrees', '72 degrees', '108 degrees', 'C', 'Exterior angle = 360/n = 360/5 = 72 degrees.', 4),
  ('ssc-cgl-quant-geometry-q06', 'ssc-cgl-quant-geometry', 'The centroid of a triangle divides each median in the ratio:', '1 : 1', '2 : 1', '3 : 1', '3 : 2', 'B', 'The centroid divides each median 2 : 1 from the vertex.', 5),
  ('ssc-cgl-quant-geometry-q07', 'ssc-cgl-quant-geometry', 'An exterior angle of a triangle is 110 degrees and one opposite interior angle is 70 degrees. The other is:', '40 degrees', '30 degrees', '50 degrees', '60 degrees', 'A', 'Exterior angle = sum of opposite interiors, so other = 110 − 70 = 40 degrees.', 6),
  ('ssc-cgl-quant-geometry-q08', 'ssc-cgl-quant-geometry', 'A tangent to a circle meets the radius at the point of contact at an angle of:', '45 degrees', '90 degrees', '60 degrees', '180 degrees', 'B', 'A tangent is perpendicular to the radius at the point of contact, 90 degrees.', 7),
  ('ssc-cgl-quant-data-interpretation-q01', 'ssc-cgl-quant-data-interpretation', 'Sales rose from 200 to 250 units. The percentage increase is:', '20%', '25%', '30%', '50%', 'B', 'Increase = (250−200)/200 × 100 = 25%.', 0),
  ('ssc-cgl-quant-data-interpretation-q02', 'ssc-cgl-quant-data-interpretation', 'In a pie chart, a category is 25% of the total. Its slice angle is:', '60 degrees', '72 degrees', '90 degrees', '120 degrees', 'C', 'Angle = 25% × 360 = 90 degrees.', 1),
  ('ssc-cgl-quant-data-interpretation-q03', 'ssc-cgl-quant-data-interpretation', 'Sales over three years were 200, 250 and 300. The average annual sales is:', '240', '260', '250', '275', 'C', 'Average = (200+250+300)/3 = 750/3 = 250.', 2),
  ('ssc-cgl-quant-data-interpretation-q04', 'ssc-cgl-quant-data-interpretation', 'A pie slice measures 90 degrees and the grand total is 800. The slice value is:', '150', '200', '180', '250', 'B', 'Value = (90/360) × 800 = 200.', 3),
  ('ssc-cgl-quant-data-interpretation-q05', 'ssc-cgl-quant-data-interpretation', 'A value falls from 300 to 240. The percentage decrease is:', '20%', '15%', '25%', '30%', 'A', 'Decrease = (300−240)/300 × 100 = 20%.', 4),
  ('ssc-cgl-quant-data-interpretation-q06', 'ssc-cgl-quant-data-interpretation', 'If a category is 120 degrees in a pie chart, its share of the total is:', '33.33%', '30%', '25%', '40%', 'A', 'Share = (120/360) × 100 = 33.33%.', 5),
  ('ssc-cgl-quant-data-interpretation-q07', 'ssc-cgl-quant-data-interpretation', 'Four products sell 40, 60, 80 and 20 units. The product with the largest share has what percent?', '30%', '45%', '40%', '50%', 'C', 'Total = 200; largest is 80, so share = 80/200 × 100 = 40%.', 6),
  ('ssc-cgl-quant-data-interpretation-q08', 'ssc-cgl-quant-data-interpretation', 'A bar shows 150 in 2022 and 180 in 2023. The percentage growth is:', '15%', '20%', '18%', '25%', 'B', 'Growth = (180−150)/150 × 100 = 20%.', 7),
  ('ssc-cgl-reasoning-analogy-classification-q01', 'ssc-cgl-reasoning-analogy-classification', 'Hot is to Cold as Up is to:', 'High', 'Down', 'Top', 'Sky', 'B', 'The relationship is antonyms; the opposite of Up is Down.', 0),
  ('ssc-cgl-reasoning-analogy-classification-q02', 'ssc-cgl-reasoning-analogy-classification', '4 : 16 :: 5 : ?', '20', '10', '30', '25', 'D', 'The pattern is n : n^2, so 5 : 25.', 1),
  ('ssc-cgl-reasoning-analogy-classification-q03', 'ssc-cgl-reasoning-analogy-classification', 'Find the odd one out:', 'Rose', 'Lotus', 'Jasmine', 'Mango', 'D', 'Rose, Lotus and Jasmine are flowers; Mango is a fruit.', 2),
  ('ssc-cgl-reasoning-analogy-classification-q04', 'ssc-cgl-reasoning-analogy-classification', 'Carpenter is to Saw as Tailor is to:', 'Scissors', 'Shirt', 'Cloth', 'Shop', 'A', 'Worker-tool relationship; a tailor uses scissors as a carpenter uses a saw.', 3),
  ('ssc-cgl-reasoning-analogy-classification-q05', 'ssc-cgl-reasoning-analogy-classification', 'Find the odd number out:', '20', '16', '25', '9', 'A', '9, 16 and 25 are perfect squares; 20 is not.', 4),
  ('ssc-cgl-reasoning-analogy-classification-q06', 'ssc-cgl-reasoning-analogy-classification', 'Wheel is to Car as Petal is to:', 'Flower', 'Garden', 'Stem', 'Leaf', 'A', 'Part-whole relationship; a petal is part of a flower as a wheel is part of a car.', 5),
  ('ssc-cgl-reasoning-analogy-classification-q07', 'ssc-cgl-reasoning-analogy-classification', 'Find the odd one out:', '11', '13', '15', '17', 'C', '11, 13 and 17 are prime; 15 is composite (3×5).', 6),
  ('ssc-cgl-reasoning-analogy-classification-q08', 'ssc-cgl-reasoning-analogy-classification', 'Big is to Large as Quick is to:', 'Slow', 'Easy', 'Late', 'Fast', 'D', 'Synonym relationship; Quick and Fast mean the same.', 7),
  ('ssc-cgl-reasoning-blood-relations-q01', 'ssc-cgl-reasoning-blood-relations', 'Your father''s brother is your:', 'Maternal uncle', 'Paternal uncle', 'Cousin', 'Nephew', 'B', 'The father''s brother is the paternal uncle.', 0),
  ('ssc-cgl-reasoning-blood-relations-q02', 'ssc-cgl-reasoning-blood-relations', 'Your mother''s brother is your:', 'Maternal uncle', 'Paternal uncle', 'Brother-in-law', 'Father', 'A', 'The mother''s brother is the maternal uncle.', 1),
  ('ssc-cgl-reasoning-blood-relations-q03', 'ssc-cgl-reasoning-blood-relations', 'Pointing to a man, a woman said, "He is the son of my mother''s only son." The man is the woman''s:', 'Brother', 'Son', 'Nephew', 'Cousin', 'B', 'Mother''s only son is the woman''s brother only if she has none; here it is herself, so the man is her son.', 2),
  ('ssc-cgl-reasoning-blood-relations-q04', 'ssc-cgl-reasoning-blood-relations', 'Your son''s wife is your:', 'Sister-in-law', 'Niece', 'Daughter-in-law', 'Granddaughter', 'C', 'The wife of your son is your daughter-in-law.', 3),
  ('ssc-cgl-reasoning-blood-relations-q05', 'ssc-cgl-reasoning-blood-relations', 'A is B''s father and C is B''s sister. How is A related to C?', 'Uncle', 'Brother', 'Father', 'Grandfather', 'C', 'B and C are siblings, and A is the father of B, so A is C''s father.', 4),
  ('ssc-cgl-reasoning-blood-relations-q06', 'ssc-cgl-reasoning-blood-relations', 'Your daughter''s son is your:', 'Grandson', 'Nephew', 'Son', 'Cousin', 'A', 'The son of your daughter is your grandson.', 5),
  ('ssc-cgl-reasoning-blood-relations-q07', 'ssc-cgl-reasoning-blood-relations', 'P is the mother of Q. Q is the brother of R. R is the daughter of S. How is P related to S?', 'Sister', 'Wife', 'Daughter', 'Mother', 'B', 'P is mother of Q and R; S is father of R, so P is S''s wife.', 6),
  ('ssc-cgl-reasoning-blood-relations-q08', 'ssc-cgl-reasoning-blood-relations', 'Your father''s sister''s husband is your:', 'Maternal uncle', 'Brother-in-law', 'Paternal uncle (by marriage)', 'Cousin', 'C', 'Father''s sister is your aunt; her husband is your uncle by marriage on the paternal side.', 7),
  ('ssc-cgl-reasoning-direction-sense-q01', 'ssc-cgl-reasoning-direction-sense', 'A man walks 3 km east then 4 km north. His shortest distance from the start is:', '5 km', '7 km', '6 km', '1 km', 'A', 'Shortest = sqrt(3^2 + 4^2) = sqrt(25) = 5 km.', 0),
  ('ssc-cgl-reasoning-direction-sense-q02', 'ssc-cgl-reasoning-direction-sense', 'Facing north, you take a right turn. You now face:', 'East', 'South', 'West', 'North', 'A', 'A right turn from north (clockwise) faces east.', 1),
  ('ssc-cgl-reasoning-direction-sense-q03', 'ssc-cgl-reasoning-direction-sense', 'At sunrise a man''s shadow falls towards his:', 'West', 'North', 'East', 'South', 'A', 'The sun rises in the east, so shadows fall towards the west.', 2),
  ('ssc-cgl-reasoning-direction-sense-q04', 'ssc-cgl-reasoning-direction-sense', 'A walks 6 km south then 8 km west. His shortest distance from start is:', '10 km', '12 km', '14 km', '2 km', 'A', 'Shortest = sqrt(6^2 + 8^2) = sqrt(100) = 10 km.', 3),
  ('ssc-cgl-reasoning-direction-sense-q05', 'ssc-cgl-reasoning-direction-sense', 'Facing south, you make an about-turn. You now face:', 'East', 'West', 'South', 'North', 'D', 'An about-turn is a 180-degree reversal; from south you face north.', 4),
  ('ssc-cgl-reasoning-direction-sense-q06', 'ssc-cgl-reasoning-direction-sense', 'Facing east, you turn left. You now face:', 'West', 'South', 'North', 'East', 'C', 'A left turn from east (anticlockwise) faces north.', 5),
  ('ssc-cgl-reasoning-direction-sense-q07', 'ssc-cgl-reasoning-direction-sense', 'A man walks 5 km north, 5 km east, 5 km south. He is now from start:', '5 km east', '5 km west', '5 km north', '10 km east', 'A', 'North and south cancel; net displacement is 5 km east.', 6),
  ('ssc-cgl-reasoning-direction-sense-q08', 'ssc-cgl-reasoning-direction-sense', 'A path has legs of 5 km and 12 km at a right angle. The shortest distance is:', '15 km', '17 km', '13 km', '7 km', 'C', 'Shortest = sqrt(5^2 + 12^2) = sqrt(169) = 13 km.', 7),
  ('ssc-cgl-reasoning-syllogism-q01', 'ssc-cgl-reasoning-syllogism', 'All A are B. All B are C. Which conclusion follows?', 'All C are A', 'No A is C', 'Some C are not A', 'All A are C', 'D', 'All A are B and all B are C together give All A are C.', 0),
  ('ssc-cgl-reasoning-syllogism-q02', 'ssc-cgl-reasoning-syllogism', '"Some A are B" always implies which conversion?', 'All B are A', 'Some B are A', 'No B is A', 'All A are B', 'B', 'A particular positive converts: Some A are B implies Some B are A.', 1),
  ('ssc-cgl-reasoning-syllogism-q03', 'ssc-cgl-reasoning-syllogism', 'Two particular statements together give:', 'A universal conclusion', 'No definite conclusion', 'A negative conclusion', 'All are related', 'B', 'Two particular premises yield no definite conclusion.', 2),
  ('ssc-cgl-reasoning-syllogism-q04', 'ssc-cgl-reasoning-syllogism', 'All pens are books. No book is red. Which follows?', 'Some pens are red', 'No pen is red', 'All books are pens', 'All red are books', 'B', 'If no book is red and all pens are books, then no pen is red.', 3),
  ('ssc-cgl-reasoning-syllogism-q05', 'ssc-cgl-reasoning-syllogism', 'Does "All A are B" mean "All B are A"?', 'No, not necessarily', 'Yes, always', 'Only if A equals B', 'Only for particular statements', 'A', 'All A are B does not reverse; All B are A need not hold.', 4),
  ('ssc-cgl-reasoning-syllogism-q06', 'ssc-cgl-reasoning-syllogism', 'Some A are B. All B are C. Which follows?', 'No A is C', 'All A are C', 'Some A are C', 'All C are A', 'C', 'Some A are B and all B are C give Some A are C.', 5),
  ('ssc-cgl-reasoning-syllogism-q07', 'ssc-cgl-reasoning-syllogism', 'Two negative statements together give:', 'A valid conclusion', 'Some are conclusion', 'A universal positive', 'No definite conclusion', 'D', 'Two negative premises yield no definite conclusion.', 6),
  ('ssc-cgl-reasoning-syllogism-q08', 'ssc-cgl-reasoning-syllogism', 'In syllogism, you should judge conclusions based on:', 'The given statements only', 'Real-world facts', 'Common sense', 'Personal opinion', 'A', 'Conclusions must follow strictly from the given statements, not outside knowledge.', 7),
  ('ssc-cgl-reasoning-seating-puzzles-q01', 'ssc-cgl-reasoning-seating-puzzles', 'In a row of 5 facing north, who is exactly in the middle position?', '1st', '2nd', '5th', '3rd', 'D', 'In a row of 5, the middle position is the 3rd seat.', 0),
  ('ssc-cgl-reasoning-seating-puzzles-q02', 'ssc-cgl-reasoning-seating-puzzles', 'Five friends sit in a row. A is left of B, B is left of C. The leftmost so far is:', 'B', 'A', 'C', 'Cannot say', 'B', 'A is left of B who is left of C, so A is the leftmost of these three.', 1),
  ('ssc-cgl-reasoning-seating-puzzles-q03', 'ssc-cgl-reasoning-seating-puzzles', 'In a circle facing the centre, a person''s right hand points toward which side?', 'Outside', 'Anticlockwise neighbour', 'The centre', 'Clockwise neighbour', 'D', 'Facing centre, your right is toward the clockwise neighbour.', 2),
  ('ssc-cgl-reasoning-seating-puzzles-q04', 'ssc-cgl-reasoning-seating-puzzles', 'In a row of 7 people, the person 3rd from left is also which from the right?', '3rd', '5th', '4th', '6th', 'B', 'Position from right = total − left position + 1 = 7 − 3 + 1 = 5th.', 3),
  ('ssc-cgl-reasoning-seating-puzzles-q05', 'ssc-cgl-reasoning-seating-puzzles', 'Eight people sit evenly around a circle. The person opposite seat 1 is at seat:', '4', '8', '6', '5', 'D', 'Opposite seat in a circle of 8 is 1 + 4 = seat 5.', 4),
  ('ssc-cgl-reasoning-seating-puzzles-q06', 'ssc-cgl-reasoning-seating-puzzles', 'In a circle facing outward, a person''s right hand points toward which side?', 'Clockwise neighbour', 'The centre', 'Anticlockwise neighbour', 'Nobody', 'C', 'Facing outward, your right is toward the anticlockwise neighbour.', 5),
  ('ssc-cgl-reasoning-seating-puzzles-q07', 'ssc-cgl-reasoning-seating-puzzles', 'In a row of 10, a person is 4th from the left. How many people are to the right of them?', '5', '7', '6', '4', 'C', 'People to the right = 10 − 4 = 6.', 6),
  ('ssc-cgl-reasoning-seating-puzzles-q08', 'ssc-cgl-reasoning-seating-puzzles', 'When solving a seating puzzle, you should begin with:', 'A vague clue', 'The most concrete fixed clue', 'The last clue', 'A random guess', 'B', 'Start from the most concrete fixed clue to anchor the arrangement.', 7),
  ('ssc-cgl-reasoning-clock-calendar-q01', 'ssc-cgl-reasoning-clock-calendar', 'The angle between the hands of a clock at 3:00 is:', '60 degrees', '120 degrees', '90 degrees', '180 degrees', 'C', 'Angle = |30×3 − 5.5×0| = 90 degrees.', 0),
  ('ssc-cgl-reasoning-clock-calendar-q02', 'ssc-cgl-reasoning-clock-calendar', 'How many odd days are there in an ordinary year?', '0', '3', '2', '1', 'D', '365 days give 365 mod 7 = 1 odd day.', 1),
  ('ssc-cgl-reasoning-clock-calendar-q03', 'ssc-cgl-reasoning-clock-calendar', 'The minute hand moves how many degrees per minute?', '0.5 degrees', '6 degrees', '1 degree', '12 degrees', 'B', 'The minute hand covers 360 degrees in 60 minutes = 6 degrees per minute.', 2),
  ('ssc-cgl-reasoning-clock-calendar-q04', 'ssc-cgl-reasoning-clock-calendar', 'Which of these is a leap year?', '1900', '1800', '2100', '2000', 'D', 'Century years are leap only if divisible by 400; 2000 qualifies.', 3),
  ('ssc-cgl-reasoning-clock-calendar-q05', 'ssc-cgl-reasoning-clock-calendar', 'The angle between the clock hands at 6:00 is:', '90 degrees', '120 degrees', '150 degrees', '180 degrees', 'D', 'Angle = |30×6 − 5.5×0| = 180 degrees.', 4),
  ('ssc-cgl-reasoning-clock-calendar-q06', 'ssc-cgl-reasoning-clock-calendar', 'How many odd days are there in a leap year?', '2', '1', '3', '0', 'A', '366 days give 366 mod 7 = 2 odd days.', 5),
  ('ssc-cgl-reasoning-clock-calendar-q07', 'ssc-cgl-reasoning-clock-calendar', 'In 12 hours, the hands of a clock coincide how many times?', '10', '24', '12', '11', 'D', 'The hands coincide 11 times in every 12 hours.', 6),
  ('ssc-cgl-reasoning-clock-calendar-q08', 'ssc-cgl-reasoning-clock-calendar', 'The hour hand moves how many degrees per minute?', '1 degree', '0.5 degrees', '6 degrees', '2 degrees', 'B', 'The hour hand covers 30 degrees in 60 minutes = 0.5 degrees per minute.', 7),
  ('ssc-cgl-reasoning-mirror-paper-folding-q01', 'ssc-cgl-reasoning-mirror-paper-folding', 'A vertical mirror image reverses which directions?', 'Top and bottom', 'Left and right', 'Both diagonals', 'Nothing changes', 'B', 'A vertical mirror reverses left and right while keeping top and bottom.', 0),
  ('ssc-cgl-reasoning-mirror-paper-folding-q02', 'ssc-cgl-reasoning-mirror-paper-folding', 'A water image reverses which directions?', 'Left and right', 'Both', 'Nothing changes', 'Top and bottom', 'D', 'A water image flips the figure top to bottom about a horizontal line.', 1),
  ('ssc-cgl-reasoning-mirror-paper-folding-q03', 'ssc-cgl-reasoning-mirror-paper-folding', 'Which letter looks the same in a vertical mirror?', 'B', 'A', 'F', 'G', 'B', 'A has a vertical axis of symmetry, so it is unchanged in a vertical mirror.', 2),
  ('ssc-cgl-reasoning-mirror-paper-folding-q04', 'ssc-cgl-reasoning-mirror-paper-folding', 'A paper folded once, punched with one hole, when opened shows how many holes?', '1', '3', '2', '4', 'C', 'One fold creates a symmetric pair, giving 2 holes.', 3),
  ('ssc-cgl-reasoning-mirror-paper-folding-q05', 'ssc-cgl-reasoning-mirror-paper-folding', 'Which letter does NOT have vertical mirror symmetry?', 'H', 'R', 'T', 'O', 'B', 'R lacks a vertical axis of symmetry; H, O and T have one.', 4),
  ('ssc-cgl-reasoning-mirror-paper-folding-q06', 'ssc-cgl-reasoning-mirror-paper-folding', 'A paper folded twice, punched once, when opened shows up to how many holes?', '2', '3', '4', '8', 'C', 'Two folds can double twice, giving up to 4 holes.', 5),
  ('ssc-cgl-reasoning-mirror-paper-folding-q07', 'ssc-cgl-reasoning-mirror-paper-folding', 'In a mirror, a clock shows 3:00. What time does the actual clock show?', '3:00', '9:00', '6:00', '12:00', 'B', 'Mirror time = 12:00 − shown time, so 12:00 − 3:00 = 9:00.', 6),
  ('ssc-cgl-reasoning-mirror-paper-folding-q08', 'ssc-cgl-reasoning-mirror-paper-folding', 'For mirror images you should:', 'Swap top and bottom', 'Rotate 90 degrees', 'Swap left and right', 'Do nothing', 'C', 'A mirror image swaps left and right while keeping top and bottom fixed.', 7),
  ('ssc-cgl-reasoning-statement-conclusion-q01', 'ssc-cgl-reasoning-statement-conclusion', 'Statement: "Smoking is injurious to health." Conclusion: "One should avoid smoking." Does it follow?', 'Follows', 'Does not follow', 'Cannot be determined', 'Partially follows', 'A', 'The recommendation to avoid smoking is implied by the statement, so it follows.', 0),
  ('ssc-cgl-reasoning-statement-conclusion-q02', 'ssc-cgl-reasoning-statement-conclusion', 'In statement-conclusion questions, conclusions needing outside facts:', 'Do not follow', 'Always follow', 'Follow if true in reality', 'Follow sometimes', 'A', 'Conclusions requiring outside facts do not follow from the statement alone.', 1),
  ('ssc-cgl-reasoning-statement-conclusion-q03', 'ssc-cgl-reasoning-statement-conclusion', 'A conclusion that merely restates the statement:', 'Does not follow', 'Needs more data', 'Is always wrong', 'Follows trivially', 'D', 'A restatement of the statement follows trivially.', 2),
  ('ssc-cgl-reasoning-statement-conclusion-q04', 'ssc-cgl-reasoning-statement-conclusion', 'An assumption is best described as something that is:', 'Drawn after the statement', 'A restatement', 'An outside fact', 'Taken for granted to make the statement meaningful', 'D', 'An assumption is taken for granted to make the statement meaningful.', 3),
  ('ssc-cgl-reasoning-statement-conclusion-q05', 'ssc-cgl-reasoning-statement-conclusion', 'When evaluating two conclusions, you should test them:', 'Independently', 'Together as one', 'Using real-world data', 'By guessing', 'A', 'Each conclusion is tested independently before selecting the combined option.', 4),
  ('ssc-cgl-reasoning-statement-conclusion-q06', 'ssc-cgl-reasoning-statement-conclusion', 'Statement: "The library is open from 9 am to 5 pm." Conclusion: "The library is closed at 8 pm." Does it follow?', 'Cannot be determined', 'Does not follow', 'Follows', 'Partially follows', 'C', 'Since hours end at 5 pm, the library is closed at 8 pm, so it follows.', 5),
  ('ssc-cgl-reasoning-statement-conclusion-q07', 'ssc-cgl-reasoning-statement-conclusion', 'An overly strong, absolute conclusion drawn from a moderate statement:', 'Does not follow', 'Follows', 'Always follows', 'Is an assumption', 'A', 'An absolute claim beyond a moderate statement does not follow.', 6),
  ('ssc-cgl-reasoning-statement-conclusion-q08', 'ssc-cgl-reasoning-statement-conclusion', 'In these questions, the statement should be treated as:', 'Possibly false', 'One of many facts', 'The only available truth', 'Irrelevant', 'C', 'The statement is treated as the only truth available for the conclusion.', 7),
  ('ssc-cgl-english-synonyms-antonyms-q01', 'ssc-cgl-english-synonyms-antonyms', 'Choose the synonym of ABUNDANT:', 'Scarce', 'Plentiful', 'Empty', 'Rare', 'B', 'Abundant means existing in large quantity, that is, plentiful.', 0),
  ('ssc-cgl-english-synonyms-antonyms-q02', 'ssc-cgl-english-synonyms-antonyms', 'Choose the antonym of TRANSPARENT:', 'Clear', 'Opaque', 'Glassy', 'Bright', 'B', 'The opposite of transparent (see-through) is opaque.', 1),
  ('ssc-cgl-english-synonyms-antonyms-q03', 'ssc-cgl-english-synonyms-antonyms', 'Choose the synonym of CANDID:', 'Frank', 'Secretive', 'Rude', 'Shy', 'A', 'Candid means open and honest, that is, frank.', 2),
  ('ssc-cgl-english-synonyms-antonyms-q04', 'ssc-cgl-english-synonyms-antonyms', 'Choose the antonym of FRUGAL:', 'Extravagant', 'Economical', 'Thrifty', 'Careful', 'A', 'Frugal means sparing with money; its opposite is extravagant.', 3),
  ('ssc-cgl-english-synonyms-antonyms-q05', 'ssc-cgl-english-synonyms-antonyms', 'Choose the synonym of BENEVOLENT:', 'Kind', 'Cruel', 'Greedy', 'Harsh', 'A', 'Benevolent means well-meaning and kind.', 4),
  ('ssc-cgl-english-synonyms-antonyms-q06', 'ssc-cgl-english-synonyms-antonyms', 'Choose the antonym of OPTIMIST:', 'Dreamer', 'Pessimist', 'Realist', 'Believer', 'B', 'An optimist expects the best; the opposite is a pessimist.', 5),
  ('ssc-cgl-english-synonyms-antonyms-q07', 'ssc-cgl-english-synonyms-antonyms', 'Choose the synonym of LETHARGIC:', 'Sluggish', 'Energetic', 'Active', 'Quick', 'A', 'Lethargic means lacking energy, that is, sluggish.', 6),
  ('ssc-cgl-english-synonyms-antonyms-q08', 'ssc-cgl-english-synonyms-antonyms', 'Choose the antonym of AMATEUR:', 'Beginner', 'Novice', 'Professional', 'Learner', 'C', 'An amateur is a non-expert; the opposite is a professional.', 7),
  ('ssc-cgl-english-spotting-errors-q01', 'ssc-cgl-english-spotting-errors', 'Identify the error: "One of the boys (A)/ are absent (B)/ today (C)/ No error (D)."', 'B', 'A', 'C', 'D', 'A', '"One of the boys" is singular, so it should be "is absent".', 0),
  ('ssc-cgl-english-spotting-errors-q02', 'ssc-cgl-english-spotting-errors', 'Identify the error: "Each student (A)/ have submitted (B)/ the form (C)/ No error (D)."', 'A', 'D', 'C', 'B', 'D', '"Each" is singular, so it takes "has submitted".', 1),
  ('ssc-cgl-english-spotting-errors-q03', 'ssc-cgl-english-spotting-errors', 'Identify the error: "The furniture (A)/ in this room (B)/ are very old (C)/ No error (D)."', 'A', 'C', 'B', 'D', 'B', '"Furniture" is uncountable and takes a singular verb "is very old".', 2),
  ('ssc-cgl-english-spotting-errors-q04', 'ssc-cgl-english-spotting-errors', 'Identify the error: "She is (A)/ more better (B)/ than her sister (C)/ No error (D)."', 'A', 'D', 'C', 'B', 'D', '"More better" is a double comparative; it should be just "better".', 3),
  ('ssc-cgl-english-spotting-errors-q05', 'ssc-cgl-english-spotting-errors', 'Identify the error: "He returned (A)/ back home (B)/ late at night (C)/ No error (D)."', 'A', 'B', 'C', 'D', 'B', '"Returned back" is redundant; "returned" alone is correct.', 4),
  ('ssc-cgl-english-spotting-errors-q06', 'ssc-cgl-english-spotting-errors', 'Identify the error: "He bought (A)/ a umbrella (B)/ from the market (C)/ No error (D)."', 'A', 'D', 'C', 'B', 'D', '"Umbrella" begins with a vowel sound, so it needs "an umbrella".', 5),
  ('ssc-cgl-english-spotting-errors-q07', 'ssc-cgl-english-spotting-errors', 'Identify the error: "The committee (A)/ comprises of (B)/ ten members (C)/ No error (D)."', 'B', 'A', 'C', 'D', 'A', '"Comprise" takes no preposition; "comprises of" should be "comprises".', 6),
  ('ssc-cgl-english-spotting-errors-q08', 'ssc-cgl-english-spotting-errors', 'Identify the error: "They have (A)/ completed the project (B)/ successfully (C)/ No error (D)."', 'A', 'B', 'C', 'D', 'D', 'The sentence is grammatically correct, so the answer is No error.', 7),
  ('ssc-cgl-english-sentence-improvement-spelling-q01', 'ssc-cgl-english-sentence-improvement-spelling', 'Improve: "She has went to the market."', 'has gone', 'have went', 'had went', 'No improvement', 'A', 'The past participle of go is gone, so "has gone" is correct.', 0),
  ('ssc-cgl-english-sentence-improvement-spelling-q02', 'ssc-cgl-english-sentence-improvement-spelling', 'Choose the correctly spelt word:', 'Accomodate', 'Acommodate', 'Accommodate', 'Acomodate', 'C', 'Accommodate has two c''s and two m''s.', 1),
  ('ssc-cgl-english-sentence-improvement-spelling-q03', 'ssc-cgl-english-sentence-improvement-spelling', 'Improve: "Let us discuss about the plan."', 'discuss on', 'discuss about', 'discuss over', 'discuss', 'D', '"Discuss" takes no preposition, so "discuss the plan" is correct.', 2),
  ('ssc-cgl-english-sentence-improvement-spelling-q04', 'ssc-cgl-english-sentence-improvement-spelling', 'Choose the correctly spelt word:', 'Definitely', 'Definately', 'Definitly', 'Defenitely', 'A', 'Definitely is spelt with no a and ends in -itely.', 3),
  ('ssc-cgl-english-sentence-improvement-spelling-q05', 'ssc-cgl-english-sentence-improvement-spelling', 'Improve: "He gave me a free gift."', 'a free gift', 'a gift', 'an free gift', 'free of gift', 'B', 'A gift is already free, so "free gift" is redundant; "a gift" is correct.', 4),
  ('ssc-cgl-english-sentence-improvement-spelling-q06', 'ssc-cgl-english-sentence-improvement-spelling', 'Choose the correctly spelt word:', 'Embarass', 'Embaras', 'Embarrass', 'Embarras', 'C', 'Embarrass has two r''s and two s''s.', 5),
  ('ssc-cgl-english-sentence-improvement-spelling-q07', 'ssc-cgl-english-sentence-improvement-spelling', 'Improve: "She likes reading and to write."', 'reading and writing', 'reading and to write', 'to read and writing', 'read and write', 'A', 'Parallelism requires matching forms: "reading and writing".', 6),
