  ('gate-engineering-mathematics-linear-algebra-q01', 'gate-engineering-mathematics-linear-algebra', 'A square matrix A is invertible if and only if:', 'det(A) = 0', 'trace(A) = 0', 'det(A) ≠ 0', 'A is symmetric', 'C', 'A matrix is non-singular (invertible) exactly when its determinant is non-zero.', 0),
  ('gate-engineering-mathematics-linear-algebra-q02', 'gate-engineering-mathematics-linear-algebra', 'The sum of the eigenvalues of a matrix equals its:', 'Trace', 'Determinant', 'Rank', 'Norm', 'A', 'The sum of eigenvalues equals the trace; their product equals the determinant.', 1),
