  ('gate-engineering-mathematics-linear-algebra-q04', 'gate-engineering-mathematics-linear-algebra', 'The eigenvalues of a triangular matrix are:', 'Always complex', 'Always zero', 'Its off-diagonal entries', 'Its diagonal entries', 'D', 'For a triangular matrix, the eigenvalues are simply the diagonal elements.', 3),
  ('gate-engineering-mathematics-linear-algebra-q05', 'gate-engineering-mathematics-linear-algebra', 'A real symmetric matrix always has:', 'Zero determinant', 'Complex eigenvalues', 'Real eigenvalues', 'Equal eigenvalues', 'C', 'Real symmetric matrices are guaranteed to have real eigenvalues.', 4),
  ('gate-engineering-mathematics-linear-algebra-q06', 'gate-engineering-mathematics-linear-algebra', 'For the system Ax = b to have a unique solution, the rank must satisfy:', 'rank(A) = rank(A|b) = n', 'rank(A) < n', 'rank(A) ≠ rank(A|b)', 'rank(A) = 0', 'A', 'A unique solution needs the coefficient and augmented ranks to equal the number of unknowns n.', 5),
