  ('gate-core-cs-dbms-sql-q01', 'gate-core-cs-dbms-sql', 'Which normal form removes transitive dependency on the primary key?', 'First normal form', 'Second normal form', 'Zero normal form', 'Third normal form', 'D', 'Third normal form eliminates transitive dependencies on the key.', 0),
  ('gate-core-cs-dbms-sql-q02', 'gate-core-cs-dbms-sql', 'In SQL, which clause filters rows after aggregation by GROUP BY?', 'WHERE', 'ORDER BY', 'HAVING', 'SELECT', 'C', 'HAVING filters grouped results, whereas WHERE filters rows before grouping.', 1),
  ('gate-core-cs-dbms-sql-q03', 'gate-core-cs-dbms-sql', 'A foreign key in a relation is used to:', 'Uniquely identify each row by itself', 'Store aggregate values', 'Reference a primary key in another relation', 'Index the table physically', 'C', 'A foreign key references another relation''s primary key to enforce integrity.', 2),
  ('gate-core-cs-dbms-sql-q04', 'gate-core-cs-dbms-sql', 'The ACID property ensuring a transaction fully completes or has no effect is:', 'Atomicity', 'Isolation', 'Durability', 'Consistency', 'A', 'Atomicity guarantees all-or-nothing execution of a transaction.', 3),
  ('gate-core-cs-dbms-sql-q05', 'gate-core-cs-dbms-sql', 'A relation is in BCNF when, for every functional dependency, the determinant is:', 'A candidate key', 'A foreign key', 'A non-prime attribute', 'An aggregate', 'A', 'In BCNF every determinant must be a candidate key.', 4),
  ('gate-core-cs-dbms-sql-q06', 'gate-core-cs-dbms-sql', 'Which SQL operation combines rows from two tables on a matching condition?', 'JOIN', 'GROUP BY', 'DISTINCT', 'UNION', 'A', 'A JOIN merges rows from tables that satisfy the join condition.', 5),
  ('gate-core-cs-dbms-sql-q07', 'gate-core-cs-dbms-sql', 'A functional dependency X to Y means:', 'X uniquely determines Y', 'Y uniquely determines X', 'X and Y are independent', 'X equals Y', 'A', 'X to Y means each value of X determines exactly one value of Y.', 6),
