  ('gate-core-cs-digital-logic-q01', 'gate-core-cs-digital-logic', 'Which gates are functionally complete (universal)?', 'AND and OR', 'XOR only', 'NAND and NOR', 'Buffer only', 'C', 'NAND and NOR are universal; any circuit can be built from either alone.', 0),
  ('gate-core-cs-digital-logic-q02', 'gate-core-cs-digital-logic', 'By De Morgan''s law, NOT (A AND B) equals:', 'NOT A AND NOT B', 'A OR B', 'NOT A OR NOT B', 'A AND B', 'C', 'De Morgan''s law gives NOT (A AND B) equals NOT A OR NOT B.', 1),
  ('gate-core-cs-digital-logic-q03', 'gate-core-cs-digital-logic', 'The two''s complement of a binary number is obtained by:', 'Adding 1 to the number', 'Reversing the bit order', 'Taking the one''s complement and adding 1', 'Subtracting 1 from the number', 'C', 'Two''s complement is the one''s complement plus one.', 2),
  ('gate-core-cs-digital-logic-q04', 'gate-core-cs-digital-logic', 'An XOR gate outputs 1 when its inputs are:', 'Both 1', 'Both 0', 'Equal', 'Different', 'D', 'XOR outputs 1 exactly when the two inputs differ.', 3),
  ('gate-core-cs-digital-logic-q05', 'gate-core-cs-digital-logic', 'Which circuit type depends on stored state and a clock?', 'Combinational', 'A multiplexer', 'A single AND gate', 'Sequential', 'D', 'Sequential circuits depend on current inputs and stored state via a clock.', 4),
